export enum PostStatus {
  DRAFT = 'DRAFT',
  PUBLISHED = 'PUBLISHED',
  ARCHIVED = 'ARCHIVED'
}

export interface Post {
  id: string;
  title: string;
  content: string;
  excerpt: string;
  status: PostStatus;
  author: string;
  createdAt: number;
  updatedAt: number;
  coverImage?: string;
  tags: string[];
}

export interface SiteSettings {
  title: string;
  description: string;
  footerText: string;
  language: string;
  postsPerPage: number;
  logoUrl?: string;
  socialTwitter?: string;
  socialGithub?: string;
}

export interface MediaItem {
  id: string;
  url: string;
  name: string;
  type: string;
  createdAt: number;
  size: number;
}

export interface User {
  id: string;
  name: string;
  avatar: string;
  role: 'admin' | 'editor';
}

export type View = 'dashboard' | 'posts' | 'media' | 'editor' | 'settings' | 'site';

// For the router
export interface RouterState {
  view: View;
  postId?: string | null; // For editing a specific post
}

import { Post, PostStatus, SiteSettings, MediaItem } from '../types';

const POSTS_KEY = 'zenpress_posts';
const SETTINGS_KEY = 'zenpress_settings';
const MEDIA_KEY = 'zenpress_media';

const DEFAULT_SETTINGS: SiteSettings = {
  title: 'ZenPress',
  description: 'A minimalist, monochrome CMS.',
  footerText: '© 2024 ZenPress Systems. All rights reserved.',
  language: 'en',
  postsPerPage: 10
};

const INITIAL_POSTS: Post[] = [
  {
    id: '1',
    title: 'System Architecture v1',
    excerpt: 'Initial thoughts on the minimalist design system.',
    content: `# System Architecture

We are prioritizing **function over form**. The interface is stripped back to the raw essentials.

## Core Directives
1. Monospace typography for high data density.
2. Grayscale palette to reduce cognitive load.
3. Instant content delivery.

The system is operational.`,
    status: PostStatus.PUBLISHED,
    author: 'Admin',
    createdAt: Date.now(),
    updatedAt: Date.now(),
    tags: ['system', 'design'],
    coverImage: 'https://picsum.photos/800/400?grayscale'
  }
];

export const StorageService = {
  getPosts: (): Post[] => {
    try {
      const stored = localStorage.getItem(POSTS_KEY);
      return stored ? JSON.parse(stored) : INITIAL_POSTS;
    } catch (e) {
      console.error("Failed to load posts", e);
      return [];
    }
  },

  savePost: (post: Post): void => {
    const posts = StorageService.getPosts();
    const existingIndex = posts.findIndex(p => p.id === post.id);

    if (existingIndex >= 0) {
      posts[existingIndex] = post;
    } else {
      posts.unshift(post);
    }

    localStorage.setItem(POSTS_KEY, JSON.stringify(posts));
  },

  deletePost: (id: string): void => {
    const posts = StorageService.getPosts().filter(p => p.id !== id);
    localStorage.setItem(POSTS_KEY, JSON.stringify(posts));
  },

  getPostById: (id: string): Post | undefined => {
    return StorageService.getPosts().find(p => p.id === id);
  },

  getSettings: (): SiteSettings => {
    try {
      const stored = localStorage.getItem(SETTINGS_KEY);
      return stored ? JSON.parse(stored) : DEFAULT_SETTINGS;
    } catch (e) {
      return DEFAULT_SETTINGS;
    }
  },

  saveSettings: (settings: SiteSettings): void => {
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  },

  // Media Methods
  getMedia: (): MediaItem[] => {
    try {
      const stored = localStorage.getItem(MEDIA_KEY);
      return stored ? JSON.parse(stored) : [];
    } catch (e) {
      return [];
    }
  },

  saveMedia: (mediaItem: MediaItem): void => {
    const media = StorageService.getMedia();
    media.unshift(mediaItem);

    // Safety check for localStorage limits - keep last 20 images
    if (media.length > 20) {
      media.pop();
    }

    try {
      localStorage.setItem(MEDIA_KEY, JSON.stringify(media));
    } catch (e) {
      alert("Storage quota exceeded. Delete some images.");
    }
  },

  deleteMedia: (id: string): void => {
    const media = StorageService.getMedia().filter(m => m.id !== id);
    localStorage.setItem(MEDIA_KEY, JSON.stringify(media));
  }
};

