import React, { useState, useRef } from 'react';
import { SiteSettings } from '../types';
import { Save, Upload, X } from 'lucide-react';

interface SettingsProps {
  settings: SiteSettings;
  onSave: (settings: SiteSettings) => void;
}

const Settings: React.FC<SettingsProps> = ({ settings, onSave }) => {
  const [formData, setFormData] = useState<SiteSettings>(settings);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isDirty, setIsDirty] = useState(false);

  const handleChange = (field: keyof SiteSettings, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    setIsDirty(true);
  };

  const handleSave = () => {
    onSave(formData);
    setIsDirty(false);
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        handleChange('logoUrl', reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="p-8 max-w-3xl mx-auto font-mono text-sm">
      <header className="mb-8 flex items-center justify-between">
        <div>
            <h2 className="text-xl font-bold text-black uppercase tracking-tight">System Configuration</h2>
            <p className="text-gray-500 mt-1 text-xs">Manage global parameters.</p>
        </div>
        {isDirty && (
            <button 
                onClick={handleSave}
                className="bg-black text-white px-4 py-2 flex items-center gap-2 text-xs font-bold uppercase tracking-wider hover:bg-gray-800"
            >
                <Save size={14} /> Save Changes
            </button>
        )}
      </header>

      <div className="space-y-8">
        {/* General Identity */}
        <section className="bg-white border border-gray-200 p-6 shadow-sm">
            <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-6 border-b border-gray-100 pb-2">Identity</h3>

            <div className="grid gap-6">
                <div>
                    <label className="block text-xs font-bold text-gray-900 uppercase tracking-wider mb-2">Site Title</label>
                    <input 
                        type="text" 
                        value={formData.title} 
                        onChange={(e) => handleChange('title', e.target.value)}
                        className="w-full bg-gray-50 border border-gray-200 p-2.5 focus:border-black focus:outline-none transition-colors"
                    />
                </div>

                <div>
                    <label className="block text-xs font-bold text-gray-900 uppercase tracking-wider mb-2">Description</label>
                    <textarea 
                        value={formData.description} 
                        onChange={(e) => handleChange('description', e.target.value)}
                        className="w-full bg-gray-50 border border-gray-200 p-2.5 focus:border-black focus:outline-none transition-colors h-24 resize-none"
                    />
                </div>

                 <div>
                    <label className="block text-xs font-bold text-gray-900 uppercase tracking-wider mb-2">Footer Text</label>
                    <input 
                        type="text" 
                        value={formData.footerText} 
                        onChange={(e) => handleChange('footerText', e.target.value)}
                        className="w-full bg-gray-50 border border-gray-200 p-2.5 focus:border-black focus:outline-none transition-colors"
                    />
                </div>
            </div>
        </section>

        {/* Branding / Logo */}
        <section className="bg-white border border-gray-200 p-6 shadow-sm">
            <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-6 border-b border-gray-100 pb-2">Branding</h3>

            <div className="flex items-start gap-6">
                <div className="flex-1">
                    <label className="block text-xs font-bold text-gray-900 uppercase tracking-wider mb-2">Site Logo</label>
                    <div className="flex gap-2">
                        <input 
                            type="text" 
                            placeholder="https://..."
                            value={formData.logoUrl || ''} 
                            onChange={(e) => handleChange('logoUrl', e.target.value)}
                            className="flex-1 bg-gray-50 border border-gray-200 p-2.5 focus:border-black focus:outline-none text-xs"
                        />
                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            className="px-4 py-2 bg-gray-100 hover:bg-gray-200 border border-gray-200 text-gray-600"
                        >
                            <Upload size={16} />
                        </button>
                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            className="hidden" 
                            accept="image/*"
                            onChange={handleLogoUpload}
                        />
                    </div>
                </div>

                <div className="w-24 h-24 bg-gray-50 border border-gray-200 flex items-center justify-center relative group">
                    {formData.logoUrl ? (
                        <>
