import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import PostList from './components/PostList';
import Editor from './components/Editor';
import Login from './components/Login';
import SitePreview from './components/SitePreview';
import Settings from './components/Settings';
import MediaLibrary from './components/MediaLibrary';
import { Post, View, SiteSettings, MediaItem } from './types';
import { StorageService } from './services/storageService';

function App() {
  // Auth State
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoadingAuth, setIsLoadingAuth] = useState(true);

  // App State
  const [view, setView] = useState<View>('dashboard');
  const [posts, setPosts] = useState<Post[]>([]);
  const [media, setMedia] = useState<MediaItem[]>([]);
  const [settings, setSettings] = useState<SiteSettings>(StorageService.getSettings());
  const [editingPostId, setEditingPostId] = useState<string | null>(null);

  // Load initial data & Auth check
  useEffect(() => {
    const checkAuth = () => {
        const storedAuth = localStorage.getItem('zenpress_auth');
        if (storedAuth === 'true') {
            setIsAuthenticated(true);
        }
        setIsLoadingAuth(false);
    };

    const loadedPosts = StorageService.getPosts();
    const loadedMedia = StorageService.getMedia();
    setPosts(loadedPosts);
    setMedia(loadedMedia);

    // Listener for dashboard quick action
    const handleNavEditor = () => {
        setEditingPostId(null);
        setView('editor');
    };

    window.addEventListener('nav-editor', handleNavEditor);
    checkAuth();

    return () => window.removeEventListener('nav-editor', handleNavEditor);
  }, []);

  const handleLogin = () => {
      localStorage.setItem('zenpress_auth', 'true');
      setIsAuthenticated(true);
  };

  const handleLogout = () => {
      localStorage.removeItem('zenpress_auth');
      setIsAuthenticated(false);
      setView('dashboard');
  };

  const handleNavigate = (newView: View) => {
    if (newView !== 'editor') {
        setEditingPostId(null);
    }
    setView(newView);
  };

  const handleEditPost = (id: string) => {
    setEditingPostId(id);
    setView('editor');
  };

  const handleDeletePost = (id: string) => {
    StorageService.deletePost(id);
    setPosts(StorageService.getPosts()); // Refresh
  };

  const handleSavePost = (post: Post) => {
    StorageService.savePost(post);
    setPosts(StorageService.getPosts());
    setView('posts');
    setEditingPostId(null);
  };

  const handleSaveSettings = (newSettings: SiteSettings) => {
    StorageService.saveSettings(newSettings);
    setSettings(newSettings);
    alert('Settings saved.');
  };

  const handleUploadMedia = (item: MediaItem) => {
    StorageService.saveMedia(item);
    setMedia(StorageService.getMedia());
  };

  const handleDeleteMedia = (id: string) => {
    StorageService.deleteMedia(id);
    setMedia(StorageService.getMedia());
  };

  const getActivePost = () => {
      return editingPostId ? posts.find(p => p.id === editingPostId) : undefined;
  };

  // View Router
  const renderView = () => {
    switch (view) {
      case 'dashboard':
        return <Dashboard posts={posts} onNavigateToPost={handleEditPost} />;
      case 'posts':
        return <PostList posts={posts} onEdit={handleEditPost} onDelete={handleDeletePost} />;
      case 'media':
        return <MediaLibrary media={media} onUpload={handleUploadMedia} onDelete={handleDeleteMedia} />;
      case 'editor':
        return (
            <div className="absolute inset-0 z-50 bg-white">
                <Editor 
                    post={getActivePost()} 
                    onSave={handleSavePost} 
                    onCancel={() => setView(posts.length > 0 ? 'posts' : 'dashboard')} 
                />
            </div>
        );
      case 'settings':
        return <Settings settings={settings} onSave={handleSaveSettings} />;
      case 'site':
        return (
            <div className="absolute inset-0 z-50 bg-white overflow-auto">
                <SitePreview 
                    posts={posts} 
                    settings={settings}
                    onBackToDashboard={() => setView('dashboard')}
                    onEditPost={(id) => {
                        handleEditPost(id);
                    }}
                />
            </div>
        );
      default:
        return <Dashboard posts={posts} onNavigateToPost={handleEditPost} />;
    }
  };

  if (isLoadingAuth) return null;

  if (!isAuthenticated) {
      return <Login onLogin={handleLogin} />;
  }

  // If in editor mode, we render full screen
  if (view === 'editor' || view === 'site') {
      return renderView();
  }

  return (
    <Layout currentView={view} onChangeView={handleNavigate} siteName={settings.title} onLogout={handleLogout}>
      {renderView()}
    </Layout>
  );
}

export default App;

import React, { useState, useRef } from 'react';
import { Post, PostStatus } from '../types';
import { 
  Save, ArrowLeft, Eye, EyeOff, Sparkles, Image as ImageIcon, 
  MoreVertical, X, Check, Bold, Italic, Heading1, Heading2, 
  Quote, List, Link as LinkIcon, Wand2, PlayCircle, Clock, Upload
} from 'lucide-react';
import { GeminiService } from '../services/geminiService';

interface EditorProps {
  post?: Post;
  onSave: (post: Post) => void;
  onCancel: () => void;
}

// Simple Markdown to HTML converter function
const simpleMarkdown = (text: string) => {
    let html = text
        .replace(/^# (.*$)/gim, '<h1 class="text-3xl font-bold mb-4 font-mono uppercase tracking-tight">$1</h1>')
        .replace(/^## (.*$)/gim, '<h2 class="text-2xl font-bold mt-6 mb-3 font-mono uppercase tracking-tight border-b border-gray-200 pb-2">$1</h2>')
        .replace(/^### (.*$)/gim, '<h3 class="text-xl font-bold mt-4 mb-2 font-mono">$1</h3>')
        .replace(/^\> (.*$)/gim, '<blockquote class="border-l-2 border-black pl-4 italic my-4 text-gray-500 font-serif">$1</blockquote>')
        .replace(/\*\*(.*)\*\*/gim, '<b>$1</b>')
        .replace(/\*(.*)\*/gim, '<i>$1</i>')
        .replace(/!\[(.*?)\]\((.*?)\)/gim, "<img alt='$1' src='$2' class='my-4 max-w-full border border-gray-200 p-1' />")
        .replace(/\[(.*?)\]\((.*?)\)/gim, "<a href='$2' class='text-black underline decoration-gray-400 hover:decoration-black'>$1</a>")
        .replace(/^\- (.*$)/gim, '<li class="ml-4 list-disc">$1</li>')
        .replace(/\n/gim, '<br />');
    return html;
};

const Editor: React.FC<EditorProps> = ({ post, onSave, onCancel }) => {
  const [title, setTitle] = useState(post?.title || '');
  const [content, setContent] = useState(post?.content || '');
  const [excerpt, setExcerpt] = useState(post?.excerpt || '');
  const [status, setStatus] = useState<PostStatus>(post?.status || PostStatus.DRAFT);
  const [tags, setTags] = useState<string[]>(post?.tags || []);
  const [coverImage, setCoverImage] = useState(post?.coverImage || '');

  const [showPreview, setShowPreview] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // AI State
  const [aiPrompt, setAiPrompt] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiResponse, setAiResponse] = useState<string | null>(null);
  const [tagInput, setTagInput] = useState('');

  const contentRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Stats
  const wordCount = content.trim().split(/\s+/).filter(w => w.length > 0).length;
  const readTime = Math.ceil(wordCount / 200);

  const handleSave = () => {
    const newPost: Post = {
      id: post?.id || crypto.randomUUID(),
      title,
      content,
      excerpt,
      status,
      author: post?.author || 'Admin', 
      createdAt: post?.createdAt || Date.now(),
      updatedAt: Date.now(),
      tags,
      coverImage
    };
    onSave(newPost);
  };

  const handleAiGenerate = async () => {
      if (!aiPrompt) return;
      setIsAiLoading(true);
      setAiResponse(null);
      const result = await GeminiService.generateSuggestion(aiPrompt, content);
      setAiResponse(result);
      setIsAiLoading(false);
  };

  const handleAiContinue = async () => {
    setIsAiLoading(true);
    const result = await GeminiService.continueWriting(content);
    if (result) {
        setContent(prev => {
            const separator = prev.endsWith(' ') || prev.endsWith('\n') ? '' : ' ';
            return prev + separator + result;
        });
    }
    setIsAiLoading(false);
  };

  const handleAiImprove = async () => {
    const textarea = contentRef.current;
    if (!textarea) return;

    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const selection = content.substring(start, end);

    if (!selection) {
        alert("Please select some text to improve.");
        return;
    }

    setIsAiLoading(true);
    const improved = await GeminiService.improveText(selection);

    if (improved) {
        const newContent = content.substring(0, start) + improved + content.substring(end);
        setContent(newContent);
    }
    setIsAiLoading(false);
  };

  const applyAiResponse = () => {
      if (aiResponse) {
          setContent(prev => prev + '\n\n' + aiResponse);
          setAiResponse(null);
          setAiPrompt('');
      }
  };

  const handleAiExcerpt = async () => {
      setIsAiLoading(true);
      const generated = await GeminiService.generateExcerpt(content);
      setExcerpt(generated);
      setIsAiLoading(false);
  };

  const handleAddTag = (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' && tagInput.trim()) {
          e.preventDefault();
          if (!tags.includes(tagInput.trim())) {
              setTags([...tags, tagInput.trim()]);
          }
          setTagInput('');
      }
  };

  const removeTag = (tagToRemove: string) => {
      setTags(tags.filter(t => t !== tagToRemove));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        if (file.size > 2000000) {
            alert('File too large (Max 2MB)');
            return;
        }
        const reader = new FileReader();
        reader.onloadend = () => {
            setCoverImage(reader.result as string);
        };
        reader.readAsDataURL(file);
    }
  };

  const triggerFileInput = () => {
    fileInputRef.current?.click();
  };

  const insertFormat = (format: string) => {
    const textarea = contentRef.current;
    if (!textarea) return;

    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const text = textarea.value;
    const selection = text.substring(start, end);

    // Default wrap behavior
    let prefix = '';
    let suffix = '';
    let newCursorOffset = 0;

    switch (format) {
      case 'bold':
        prefix = '**'; suffix = '**'; newCursorOffset = 2;
        break;
      case 'italic':
        prefix = '*'; suffix = '*'; newCursorOffset = 1;
        break;
      case 'h1':
        prefix = '# '; newCursorOffset = 2;
        break;
      case 'h2':
        prefix = '## '; newCursorOffset = 3;
        break;
      case 'quote':
        prefix = '> '; newCursorOffset = 2;
        break;
      case 'list':
        prefix = '- '; newCursorOffset = 2;
        break;
      case 'link':
        prefix = '['; suffix = '](url)'; newCursorOffset = 1;
        break;
    }

    const newContent = text.substring(0, start) + prefix + selection + suffix + text.substring(end);
    setContent(newContent);

    // Restore focus and cursor
    setTimeout(() => {
        textarea.focus();
        if (selection.length > 0) {
            textarea.setSelectionRange(start + prefix.length, end + prefix.length);
        } else {
            textarea.setSelectionRange(start + prefix.length, start + prefix.length);
        }
    }, 0);
  };

  return (
    <div className="flex h-full bg-white relative font-mono text-gray-900">
      {/* Main Editor Area */}
      <div className={`flex-1 flex flex-col transition-all duration-300 ${isSidebarOpen ? 'mr-80' : ''}`}>
        {/* Top Header */}
        <header className="h-16 border-b border-gray-200 flex items-center justify-between px-6 bg-white z-20">
            <div className="flex items-center gap-4">
                <button onClick={onCancel} className="p-2 hover:bg-gray-100 text-gray-500 transition-colors">
                    <ArrowLeft size={16} />
                </button>
                <div className="flex flex-col">
                    <span className="text-sm font-bold text-gray-900 leading-none truncate max-w-[200px]">
                        {title || 'UNTITLED_ENTRY'}
                    </span>
                    <span className="text-[10px] text-gray-400 mt-1 uppercase tracking-widest font-bold">
                        {status === PostStatus.DRAFT ? 'Draft' : 'Live'} &bull; {wordCount} words
                    </span>
                </div>
            </div>

            <div className="flex items-center gap-3">
                 <button 
                    onClick={() => setShowPreview(!showPreview)} 
                    className={`flex items-center gap-2 px-3 py-2 text-xs font-bold uppercase tracking-wider transition-colors border ${showPreview ? 'bg-black text-white border-black' : 'text-gray-500 border-gray-200 hover:border-black hover:text-black'}`}
                >
                    {showPreview ? <EyeOff size={14} /> : <Eye size={14} />}
                    <span className="hidden sm:inline">{showPreview ? 'Editor' : 'Preview'}</span>
                </button>

                <div className="h-6 w-px bg-gray-200 mx-1"></div>

                <button 
                    onClick={handleSave} 
                    className="bg-black hover:bg-gray-800 text-white px-5 py-2 text-xs font-bold uppercase tracking-wider flex items-center gap-2 transition-transform active:scale-95"
                >
                    <Save size={14} />
                    Save
                </button>

                <button 
                    onClick={() => setIsSidebarOpen(!isSidebarOpen)} 
                    className={`p-2 transition-colors border ${isSidebarOpen ? 'bg-gray-100 text-black border-gray-300' : 'text-gray-400 border-transparent hover:bg-gray-50 hover:text-black'}`}
                >
                    <MoreVertical size={18} />
                </button>
            </div>
        </header>

        {/* Toolbar - Only visible in Edit mode */}
        {!showPreview && (
            <div className="px-6 py-2 border-b border-gray-100 bg-white flex items-center gap-1 sticky top-0 z-10 overflow-x-auto">
                <button onClick={() => insertFormat('bold')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50" title="Bold"><Bold size={16} /></button>
                <button onClick={() => insertFormat('italic')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50" title="Italic"><Italic size={16} /></button>
                <button onClick={() => insertFormat('link')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50" title="Link"><LinkIcon size={16} /></button>
                <div className="w-px h-4 bg-gray-200 mx-3"></div>
                <button onClick={() => insertFormat('h1')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50" title="Heading 1"><Heading1 size={16} /></button>
                <button onClick={() => insertFormat('h2')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50" title="Heading 2"><Heading2 size={16} /></button>
                <button onClick={() => insertFormat('quote')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50" title="Quote"><Quote size={16} /></button>
                <button onClick={() => insertFormat('list')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50" title="List"><List size={16} /></button>
                <div className="w-px h-4 bg-gray-200 mx-3"></div>
                <button 
                    onClick={handleAiContinue} 
                    disabled={isAiLoading}
                    className="flex items-center gap-1.5 px-3 py-1 text-[10px] font-bold uppercase tracking-wider text-black bg-gray-100 hover:bg-gray-200 transition-colors disabled:opacity-50"
                >
                    <PlayCircle size={12} />
                    {isAiLoading ? 'Thinking...' : 'Continue'}
                </button>
                <button 
                    onClick={handleAiImprove} 
                    disabled={isAiLoading}
                    className="flex items-center gap-1.5 px-3 py-1 text-[10px] font-bold uppercase tracking-wider text-black bg-gray-100 hover:bg-gray-200 transition-colors disabled:opacity-50 ml-1"
                    title="Select text to improve"
                >
                    <Wand2 size={12} />
                    Enhance
                </button>
            </div>
        )}

        {/* Editor Content */}
        <div className="flex-1 overflow-auto bg-white">
            {showPreview ? (
                <div className="max-w-3xl mx-auto px-8 py-16 prose prose-stone">
                    <h1 className="font-mono uppercase">{title || "Untitled Post"}</h1>
                    {coverImage && <img src={coverImage} alt="Cover" className="w-full grayscale border border-gray-200 mb-8 p-1" />}
                    <div dangerouslySetInnerHTML={{ __html: simpleMarkdown(content) }} />
                </div>
            ) : (
                <div className="max-w-3xl mx-auto px-6 py-10 h-full flex flex-col">
                    <input 
                        type="text" 
                        placeholder="ENTER_TITLE" 
                        className="text-3xl font-bold text-gray-900 placeholder-gray-200 border-none focus:ring-0 w-full bg-transparent p-0 mb-6 font-mono uppercase tracking-tight"
                        value={title}
                        onChange={(e) => setTitle(e.target.value)}
                    />
                    <textarea 
                        ref={contentRef}
                        placeholder="Start typing..." 
                        className="flex-1 resize-none w-full border-none focus:ring-0 text-base leading-relaxed text-gray-800 placeholder-gray-200 bg-transparent p-0 font-mono outline-none"
                        value={content}
                        onChange={(e) => setContent(e.target.value)}
                        spellCheck={false}
                    />
                    <div className="mt-4 pt-4 border-t border-gray-100 text-[10px] text-gray-400 flex items-center justify-between font-mono uppercase tracking-widest">
                         <span>Markdown Enabled</span>
                         <span className="flex items-center gap-1"><Clock size={12} /> {readTime} min read</span>
