        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-8">
            {/* Status Section */}
            <div>
                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Publication State</label>
                <div className="grid grid-cols-2 gap-2">
                    <button 
                        onClick={() => setStatus(PostStatus.DRAFT)}
