                    >
                        Draft
                    </button>
                    <button 
                        onClick={() => setStatus(PostStatus.PUBLISHED)}
                        className={`py-2 text-xs font-bold uppercase tracking-wider border ${status === PostStatus.PUBLISHED ? 'bg-black text-white border-black' : 'bg-white text-gray-400 border-gray-200 hover:border-gray-400'}`}
                    >
                        Publish
                    </button>
                </div>
            </div>

            {/* AI Assistant Section */}
            <div className="bg-gray-50 border border-gray-200 p-4">
                <div className="flex items-center gap-2 text-black font-bold text-[10px] uppercase tracking-widest mb-3">
