// Monochrome markdown renderer
const simpleMarkdown = (text: string) => {
    let html = text
        .replace(/^# (.*$)/gim, '<h1 class="text-3xl md:text-5xl font-bold mb-6 mt-4 text-gray-900 font-serif tracking-tight leading-none">$1</h1>')
        .replace(/^## (.*$)/gim, '<h2 class="text-2xl md:text-3xl font-bold mt-10 mb-4 text-gray-900 font-serif tracking-tight">$1</h2>')
        .replace(/^### (.*$)/gim, '<h3 class="text-xl md:text-2xl font-bold mt-8 mb-3 text-gray-900 font-serif tracking-tight">$1</h3>')
        .replace(/^\> (.*$)/gim, '<blockquote class="border-l-4 border-gray-900 pl-6 py-2 italic my-8 text-gray-800 text-xl font-serif">$1</blockquote>')
        .replace(/\*\*(.*)\*\*/gim, '<b class="font-bold text-gray-900">$1</b>')
        .replace(/\*(.*)\*/gim, '<i class="italic text-gray-800">$1</i>')
        .replace(/!\[(.*?)\]\((.*?)\)/gim, "<figure class='my-10'><img alt='$1' src='$2' class='w-full grayscale hover:grayscale-0 transition-all duration-700' /><figcaption class='text-center text-xs text-gray-500 mt-3 font-mono uppercase tracking-widest'>$1</figcaption></figure>")
        .replace(/\[(.*?)\]\((.*?)\)/gim, "<a href='$2' class='text-black underline decoration-2 decoration-gray-300 hover:decoration-black transition-all underline-offset-4'>$1</a>")
        .replace(/\n/gim, '<br />');
    return html;
};

