// Simple Markdown to HTML converter function
const simpleMarkdown = (text: string) => {
    let html = text
        .replace(/^# (.*$)/gim, '<h1 class="text-3xl font-bold mb-4 font-mono uppercase tracking-tight">$1</h1>')
        .replace(/^## (.*$)/gim, '<h2 class="text-2xl font-bold mt-6 mb-3 font-mono uppercase tracking-tight border-b border-gray-200 pb-2">$1</h2>')
        .replace(/^### (.*$)/gim, '<h3 class="text-xl font-bold mt-4 mb-2 font-mono">$1</h3>')
        .replace(/^\> (.*$)/gim, '<blockquote class="border-l-2 border-black pl-4 italic my-4 text-gray-500 font-serif">$1</blockquote>')
        .replace(/\*\*(.*)\*\*/gim, '<b>$1</b>')
        .replace(/\*(.*)\*/gim, '<i>$1</i>')
        .replace(/`([^`]+)`/gim, '<code class="bg-gray-100 px-1 py-0.5 rounded text-sm font-mono text-red-600">$1</code>')
        // Markdown image syntax fallback (still useful for quick typing)
        .replace(/!\[(.*?)\]\((.*?)\)/gim, "<img alt='$1' src='$2' class='my-6 max-w-full border border-gray-200 p-1 block' />")
        .replace(/\[(.*?)\]\((.*?)\)/gim, "<a href='$2' class='text-black underline decoration-gray-400 hover:decoration-black'>$1</a>")
        .replace(/^\- (.*$)/gim, '<li class="ml-4 list-disc">$1</li>')
        .replace(/^-{3,}$/gim, '<hr class="my-6 border-gray-200" />')
        .replace(/\n/gim, '<br />');
    return html;
};

const Editor: React.FC<EditorProps> = ({ post, media, onSave, onCancel, onUploadMedia }) => {
  const [title, setTitle] = useState(post?.title || '');
  const [content, setContent] = useState(post?.content || '');
  const [excerpt, setExcerpt] = useState(post?.excerpt || '');
  const [status, setStatus] = useState<PostStatus>(post?.status || PostStatus.DRAFT);
  const [tags, setTags] = useState<string[]>(post?.tags || []);
  const [coverImage, setCoverImage] = useState(post?.coverImage || '');

  // View Modes: 'edit' (Focus), 'split' (Side-by-Side), 'preview' (Full Preview)
  const [editorMode, setEditorMode] = useState<'edit' | 'split' | 'preview'>('edit');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isZenMode, setIsZenMode] = useState(false);

  // Media Picker State
  const [showMediaPicker, setShowMediaPicker] = useState(false);
  const [pickerTarget, setPickerTarget] = useState<'content' | 'cover'>('content');
  const [imageSize, setImageSize] = useState<'100%' | '50%' | '25%'>('100%');

  // AI State
  const [aiPrompt, setAiPrompt] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiResponse, setAiResponse] = useState<string | null>(null);
  const [tagInput, setTagInput] = useState('');

  const contentRef = useRef<HTMLTextAreaElement>(null);

  // Stats
  const wordCount = content.trim().split(/\s+/).filter(w => w.length > 0).length;
  const readTime = Math.ceil(wordCount / 200);

  const savePost = (targetStatus: PostStatus) => {
    const newPost: Post = {
      id: post?.id || crypto.randomUUID(),
      title,
      content,
      excerpt,
      status: targetStatus,
      author: post?.author || 'Admin', 
      createdAt: post?.createdAt || Date.now(),
      updatedAt: Date.now(),
      tags,
      coverImage
    };
    onSave(newPost);
  };

  const handlePublish = () => savePost(PostStatus.PUBLISHED);
  const handleSaveDraft = () => savePost(PostStatus.DRAFT);

  const handleAiGenerate = async () => {
      if (!aiPrompt) return;
      setIsAiLoading(true);
      setAiResponse(null);
      const result = await GeminiService.generateSuggestion(aiPrompt, content);
      setAiResponse(result);
      setIsAiLoading(false);
  };

  const handleAiContinue = async () => {
    setIsAiLoading(true);
    const result = await GeminiService.continueWriting(content);
    if (result) {
        setContent(prev => {
            const separator = prev.endsWith(' ') || prev.endsWith('\n') ? '' : ' ';
            return prev + separator + result;
        });
    }
    setIsAiLoading(false);
  };

  const handleAiImprove = async () => {
    const textarea = contentRef.current;
    if (!textarea) return;

    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const selection = content.substring(start, end);

    if (!selection) {
        alert("Please select some text to improve.");
        return;
    }

    setIsAiLoading(true);
    const improved = await GeminiService.improveText(selection);

    if (improved) {
        const newContent = content.substring(0, start) + improved + content.substring(end);
        setContent(newContent);
    }
    setIsAiLoading(false);
  };

  const applyAiResponse = () => {
      if (aiResponse) {
          setContent(prev => prev + '\n\n' + aiResponse);
          setAiResponse(null);
          setAiPrompt('');
      }
  };

  const handleAiExcerpt = async () => {
      setIsAiLoading(true);
      const generated = await GeminiService.generateExcerpt(content);
      setExcerpt(generated);
      setIsAiLoading(false);
  };

  const handleAddTag = (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' && tagInput.trim()) {
          e.preventDefault();
          if (!tags.includes(tagInput.trim())) {
              setTags([...tags, tagInput.trim()]);
          }
          setTagInput('');
      }
  };

  const removeTag = (tagToRemove: string) => {
      setTags(tags.filter(t => t !== tagToRemove));
  };

  const handleMediaUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        if (file.size > 2000000) {
            alert('File too large (Max 2MB)');
            return;
        }
        const reader = new FileReader();
        reader.onloadend = () => {
             const newItem: MediaItem = {
                id: crypto.randomUUID(),
                url: reader.result as string,
                name: file.name,
                type: file.type,
                createdAt: Date.now(),
                size: file.size
            };
            onUploadMedia(newItem);
        };
        reader.readAsDataURL(file);
    }
  };

  const openMediaPicker = (target: 'content' | 'cover') => {
      setPickerTarget(target);
      setShowMediaPicker(true);
  };

  const handleMediaSelect = (item: MediaItem) => {
      if (pickerTarget === 'cover') {
          setCoverImage(item.url);
      } else {
          // Insert HTML image tag with width, enabling "resize" via code edit
          const imgTag = `<img src="${item.url}" alt="${item.name}" width="${imageSize}" />`;
          insertFormat('html_image', imgTag);
      }
      setShowMediaPicker(false);
  };

  const insertFormat = (format: string, arg?: string) => {
    const textarea = contentRef.current;
    if (!textarea) return;

    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const text = textarea.value;
    const selection = text.substring(start, end);

    // Default wrap behavior
    let prefix = '';
    let suffix = '';

    switch (format) {
      case 'bold':
        prefix = '**'; suffix = '**'; 
        break;
      case 'italic':
        prefix = '*'; suffix = '*'; 
        break;
      case 'h1':
        prefix = '# '; 
        break;
      case 'h2':
        prefix = '## '; 
        break;
      case 'quote':
        prefix = '> '; 
        break;
      case 'list':
        prefix = '- '; 
        break;
      case 'link':
        prefix = '['; suffix = '](url)'; 
        break;
      case 'code':
        if (selection.includes('\n')) {
            prefix = '```\n'; suffix = '\n```'; 
        } else {
            prefix = '`'; suffix = '`'; 
        }
        break;
      case 'hr':
        prefix = '\n---\n'; 
        break;
      case 'image': // Standard Markdown Image
        const url = arg || 'url';
        prefix = `![Alt text](${url})`; 
        break;
       case 'html_image': // Custom sized image
        prefix = arg || '';
        break;
    }

    let newContent = '';
    if (format === 'image' || format === 'hr' || format === 'html_image') {
        newContent = text.substring(0, start) + prefix + text.substring(end);
    } else {
        newContent = text.substring(0, start) + prefix + selection + suffix + text.substring(end);
    }

    setContent(newContent);

    // Restore focus and cursor
    setTimeout(() => {
        textarea.focus();
        if (format !== 'image' && format !== 'hr' && format !== 'html_image') {
            if (selection.length > 0) {
                textarea.setSelectionRange(start + prefix.length, end + prefix.length);
            } else {
                textarea.setSelectionRange(start + prefix.length, start + prefix.length);
            }
        }
    }, 0);
  };

  const toggleEditorMode = () => {
      if (editorMode === 'edit') setEditorMode('split');
      else if (editorMode === 'split') setEditorMode('preview');
      else setEditorMode('edit');
  };

  return (
    <div className="flex h-full bg-white relative font-mono text-gray-900 overflow-hidden">
      {/* Media Picker Modal */}
      {showMediaPicker && (
          <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-8">
              <div className="bg-white w-full max-w-4xl h-[80vh] flex flex-col shadow-2xl animate-in fade-in zoom-in-95 duration-200">
                  <header className="p-6 border-b border-gray-100 flex items-center justify-between">
                      <div>
                          <h3 className="text-xl font-bold uppercase tracking-tight">Select Asset</h3>
                          <p className="text-xs text-gray-500 mt-1">
                              {pickerTarget === 'cover' ? 'Setting cover image' : 'Inserting into content'}
                          </p>
                      </div>
                      <div className="flex items-center gap-4">
                           {pickerTarget === 'content' && (
                                <div className="flex items-center gap-2 mr-4 bg-gray-50 p-1 border border-gray-200 rounded">
                                    <span className="text-[10px] font-bold uppercase px-2 text-gray-500">Width:</span>
                                    <button onClick={() => setImageSize('25%')} className={`text-[10px] px-2 py-1 font-bold ${imageSize === '25%' ? 'bg-black text-white' : 'text-gray-400'}`}>S</button>
                                    <button onClick={() => setImageSize('50%')} className={`text-[10px] px-2 py-1 font-bold ${imageSize === '50%' ? 'bg-black text-white' : 'text-gray-400'}`}>M</button>
                                    <button onClick={() => setImageSize('100%')} className={`text-[10px] px-2 py-1 font-bold ${imageSize === '100%' ? 'bg-black text-white' : 'text-gray-400'}`}>L</button>
                                </div>
                           )}

                          <div className="relative">
                                <input 
                                    type="file" 
                                    className="hidden" 
                                    id="modal-upload"
                                    accept="image/*"
                                    onChange={handleMediaUpload}
                                />
                                <label 
                                    htmlFor="modal-upload" 
                                    className="cursor-pointer bg-black text-white px-4 py-2 text-xs font-bold uppercase tracking-wider hover:bg-gray-800 flex items-center gap-2"
                                >
                                    <Upload size={14} /> Upload New
                                </label>
                          </div>
                          <button onClick={() => setShowMediaPicker(false)} className="p-2 hover:bg-gray-100"><X size={20} /></button>
                      </div>
                  </header>
                  <div className="flex-1 overflow-y-auto p-6 bg-gray-50">
                      {media.length === 0 ? (
                          <div className="h-full flex flex-col items-center justify-center text-gray-400">
                              <ImageIcon size={48} className="mb-4 opacity-20" />
                              <p className="text-sm font-bold uppercase">No Media Found</p>
                          </div>
                      ) : (
                          <div className="grid grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                              {media.map(item => (
                                  <button 
                                    key={item.id} 
                                    onClick={() => handleMediaSelect(item)}
                                    className="group relative aspect-square bg-white border border-gray-200 hover:border-black transition-colors focus:outline-none focus:ring-2 focus:ring-black focus:ring-offset-2"
                                  >
                                      <img src={item.url} alt={item.name} className="w-full h-full object-cover p-1" />
                                      <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors" />
                                      <div className="absolute bottom-0 left-0 right-0 bg-white/90 p-1 text-[10px] truncate border-t border-gray-100">
                                          {item.name}
                                      </div>
                                  </button>
                              ))}
                          </div>
                      )}
                  </div>
              </div>
          </div>
      )}

      {/* Main Editor Area */}
      <div className={`flex-1 flex flex-col transition-all duration-300 ${isSidebarOpen && !isZenMode ? 'mr-80' : ''}`}>
        {/* Top Header */}
        <header className={`h-16 border-b border-gray-200 flex items-center justify-between px-6 bg-white z-20 transition-all duration-300 ${isZenMode ? '-mt-16 opacity-0 pointer-events-none' : ''}`}>
            <div className="flex items-center gap-4">
                <button onClick={onCancel} className="p-2 hover:bg-gray-100 text-gray-500 transition-colors">
                    <ArrowLeft size={16} />
                </button>
                <div className="flex flex-col">
                    <span className="text-sm font-bold text-gray-900 leading-none truncate max-w-[200px]">
                        {title || 'UNTITLED_ENTRY'}
                    </span>
                    <span className="text-[10px] text-gray-400 mt-1 uppercase tracking-widest font-bold">
                        {status === PostStatus.DRAFT ? 'Draft' : 'Live'} &bull; {wordCount} words
                    </span>
                </div>
            </div>

            <div className="flex items-center gap-3">
                 <button 
                    onClick={toggleEditorMode} 
                    className="flex items-center gap-2 px-3 py-2 text-xs font-bold uppercase tracking-wider text-gray-500 border border-gray-200 hover:border-black hover:text-black transition-colors"
                    title="Toggle View Mode"
                >
                    {editorMode === 'edit' && <Eye size={14} />}
                    {editorMode === 'split' && <Columns size={14} />}
                    {editorMode === 'preview' && <EyeOff size={14} />}
                    <span className="hidden sm:inline">
                        {editorMode === 'edit' && 'Edit'}
                        {editorMode === 'split' && 'Split'}
                        {editorMode === 'preview' && 'Preview'}
                    </span>
                </button>

                <div className="h-6 w-px bg-gray-200 mx-1"></div>

                <button 
                    onClick={handleSaveDraft} 
                    className="text-gray-500 hover:text-black px-4 py-2 text-xs font-bold uppercase tracking-wider hover:bg-gray-50"
                >
                    Save Draft
                </button>

                <button 
                    onClick={handlePublish} 
                    className="bg-black hover:bg-gray-800 text-white px-5 py-2 text-xs font-bold uppercase tracking-wider flex items-center gap-2 transition-transform active:scale-95"
                >
                    <Save size={14} />
                    {status === PostStatus.PUBLISHED ? 'Update' : 'Publish'}
                </button>

                <button 
                    onClick={() => setIsSidebarOpen(!isSidebarOpen)} 
                    className={`p-2 transition-colors border ${isSidebarOpen ? 'bg-gray-100 text-black border-gray-300' : 'text-gray-400 border-transparent hover:bg-gray-50 hover:text-black'}`}
                >
                    <MoreVertical size={18} />
                </button>
            </div>
        </header>

        {/* Toolbar - Only visible when editing is possible (Edit or Split mode) */}
        {editorMode !== 'preview' && (
            <div className={`px-6 py-2 border-b border-gray-100 bg-white flex items-center gap-1 sticky top-0 z-10 overflow-x-auto transition-all duration-300 ${isZenMode ? 'opacity-0 -translate-y-full absolute w-full' : ''}`}>
                <button onClick={() => insertFormat('bold')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Bold"><Bold size={16} /></button>
                <button onClick={() => insertFormat('italic')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Italic"><Italic size={16} /></button>
                <button onClick={() => insertFormat('link')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Link"><LinkIcon size={16} /></button>
                <button onClick={() => insertFormat('code')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Code"><Code size={16} /></button>
                <button onClick={() => openMediaPicker('content')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Insert Image"><ImageIcon size={16} /></button>

                <div className="w-px h-4 bg-gray-200 mx-3"></div>

                <button onClick={() => insertFormat('h1')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Heading 1"><Heading1 size={16} /></button>
                <button onClick={() => insertFormat('h2')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Heading 2"><Heading2 size={16} /></button>
                <button onClick={() => insertFormat('quote')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Quote"><Quote size={16} /></button>
                <button onClick={() => insertFormat('list')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="List"><List size={16} /></button>
                <button onClick={() => insertFormat('hr')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Horizontal Rule"><Minus size={16} /></button>

                <div className="w-px h-4 bg-gray-200 mx-3"></div>

                <button 
                    onClick={handleAiContinue} 
                    disabled={isAiLoading}
                    className="flex items-center gap-1.5 px-3 py-1 text-[10px] font-bold uppercase tracking-wider text-black bg-gray-100 hover:bg-gray-200 transition-colors disabled:opacity-50 rounded"
                >
                    <PlayCircle size={12} />
                    {isAiLoading ? 'Thinking...' : 'Continue'}
                </button>
                <button 
                    onClick={handleAiImprove} 
                    disabled={isAiLoading}
                    className="flex items-center gap-1.5 px-3 py-1 text-[10px] font-bold uppercase tracking-wider text-black bg-gray-100 hover:bg-gray-200 transition-colors disabled:opacity-50 ml-1 rounded"
                    title="Select text to improve"
                >
                    <Wand2 size={12} />
                    Enhance
                </button>

                <div className="flex-1"></div>

                <button 
                    onClick={() => setIsZenMode(!isZenMode)}
                    className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" 
                    title="Zen Mode"
                >
                    {isZenMode ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
                </button>
            </div>
        )}

        {/* Editor Content Area */}
        <div className="flex-1 overflow-hidden bg-white relative flex">
            {/* Zen Mode Exit Button (Floating) */}
            {isZenMode && editorMode !== 'preview' && (
                <button 
                    onClick={() => setIsZenMode(false)}
                    className="absolute top-4 right-6 z-30 p-2 bg-gray-100 text-gray-500 hover:text-black hover:bg-gray-200 rounded-full opacity-50 hover:opacity-100 transition-opacity"
                    title="Exit Zen Mode"
                >
                    <Minimize2 size={16} />
                </button>
            )}

            {/* Editor Pane */}
            {(editorMode === 'edit' || editorMode === 'split') && (
                <div className={`flex-1 h-full flex flex-col overflow-auto transition-all duration-500 ${isZenMode ? 'py-16' : 'py-10'} ${editorMode === 'split' ? 'border-r border-gray-200' : ''}`}>
                    <div className="max-w-3xl mx-auto px-6 w-full h-full flex flex-col">
                        <input 
                            type="text" 
                            placeholder="ENTER_TITLE" 
                            className="text-4xl font-bold text-gray-900 placeholder-gray-200 border-none focus:ring-0 w-full bg-transparent p-0 mb-8 font-mono uppercase tracking-tight"
                            value={title}
                            onChange={(e) => setTitle(e.target.value)}
                        />
                        <textarea 
                            ref={contentRef}
                            placeholder="Start typing..." 
                            className="flex-1 resize-none w-full border-none focus:ring-0 text-lg leading-relaxed text-gray-800 placeholder-gray-200 bg-transparent p-0 font-mono outline-none"
                            value={content}
                            onChange={(e) => setContent(e.target.value)}
                            spellCheck={false}
                        />
                         {!isZenMode && (
                            <div className="mt-4 pt-4 border-t border-gray-100 text-[10px] text-gray-400 flex items-center justify-between font-mono uppercase tracking-widest">
                                <div className="flex items-center gap-4">
                                    <span>Markdown Enabled</span>
                                    {aiResponse && <span className="text-black font-bold animate-pulse">AI Suggestion Ready</span>}
                                </div>
                                <span className="flex items-center gap-1"><Clock size={12} /> {readTime} min read</span>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* Preview Pane */}
            {(editorMode === 'preview' || editorMode === 'split') && (
                <div className={`h-full overflow-auto bg-gray-50/50 ${editorMode === 'split' ? 'flex-1' : 'w-full'}`}>
                    <div className="max-w-3xl mx-auto px-8 py-16 prose prose-stone">
                        <h1 className="font-mono uppercase">{title || "Untitled Post"}</h1>
                        {coverImage && <img src={coverImage} alt="Cover" className="w-full grayscale border border-gray-200 mb-8 p-1" />}
                        <div dangerouslySetInnerHTML={{ __html: simpleMarkdown(content) }} />
                    </div>
                </div>
            )}
        </div>
      </div>

      {/* Settings/AI Sidebar */}
      <div className={`fixed right-0 top-0 bottom-0 w-80 bg-white border-l border-gray-200 shadow-2xl transform transition-transform duration-300 z-30 flex flex-col ${isSidebarOpen && !isZenMode ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="flex items-center justify-between p-5 border-b border-gray-200 bg-gray-50">
            <h3 className="font-bold text-xs text-gray-900 uppercase tracking-widest">Config</h3>
            <button onClick={() => setIsSidebarOpen(false)} className="text-gray-400 hover:text-black">
                <X size={18} />
            </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-8">
            {/* AI Assistant Section */}
            <div className="bg-gray-50 border border-gray-200 p-4">
                <div className="flex items-center gap-2 text-black font-bold text-[10px] uppercase tracking-widest mb-3">
                    <Sparkles size={12} />
                    <span>Gemini AI</span>
                </div>

                <div className="space-y-3">
                    <textarea 
                        className="w-full text-xs p-2 border border-gray-200 focus:border-black focus:ring-0 min-h-[80px] bg-white"
                        placeholder="Request generated content..."
                        value={aiPrompt}
                        onChange={(e) => setAiPrompt(e.target.value)}
                    />
                    <button 
                        onClick={handleAiGenerate}
                        disabled={isAiLoading || !aiPrompt}
                        className="w-full bg-white border border-gray-900 hover:bg-gray-900 hover:text-white text-black text-[10px] py-2 font-bold uppercase tracking-wider transition-colors disabled:opacity-50"
                    >
                        {isAiLoading ? 'Processing...' : 'Execute'}
                    </button>
                </div>

                {aiResponse && (
                    <div className="mt-4 bg-white p-3 border border-gray-200 text-xs text-gray-700 animate-in fade-in slide-in-from-top-2">
                        <p className="mb-3 max-h-40 overflow-y-auto leading-relaxed font-sans">{aiResponse}</p>
                        <button 
                            onClick={applyAiResponse}
                            className="text-[10px] flex items-center gap-1 text-black font-bold hover:underline uppercase tracking-wider"
                        >
                            <Check size={10} /> Insert
                        </button>
                    </div>
                )}
            </div>

            {/* General Settings */}
            <div>
                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Meta Description</label>
                <textarea 
                    className="w-full text-xs p-3 border border-gray-200 focus:border-black focus:ring-0 min-h-[100px] bg-gray-50"
                    placeholder="Brief summary..."
                    value={excerpt}
                    onChange={(e) => setExcerpt(e.target.value)}
                />
                <button 
                    onClick={handleAiExcerpt}
                    disabled={isAiLoading || !content}
                    className="mt-2 text-[10px] text-gray-600 font-bold uppercase tracking-wider flex items-center gap-1 hover:text-black disabled:opacity-50"
                >
                    <Sparkles size={10} /> Auto-Generate
                </button>
            </div>

            <div>
                 <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Cover Asset</label>
                 <div className="space-y-3">
                    <button 
                        onClick={() => openMediaPicker('cover')}
                        className="w-full py-6 border border-dashed border-gray-300 hover:border-black text-gray-400 hover:text-black transition-colors flex flex-col items-center justify-center gap-2 bg-gray-50"
                        title="Select Image"
                    >
                        <FileImage size={16} />
                        <span className="text-[10px] uppercase font-bold">Select from Library</span>
                    </button>

                    {coverImage && (
                        <div className="relative group">
                            <img src={coverImage} alt="Preview" className="w-full h-32 object-cover border border-gray-200 grayscale" />
                            <button onClick={() => setCoverImage('')} className="absolute top-2 right-2 bg-black text-white p-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                <X size={12} />
                            </button>
                        </div>
                    )}
                 </div>
            </div>

            <div>
                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Keywords / Tags</label>
                <div className="flex flex-wrap gap-2 mb-2">
                    {tags.map(tag => (
                        <span key={tag} className="bg-black text-white px-2 py-1 text-[10px] font-bold uppercase tracking-wider flex items-center gap-1">
                            {tag}
                            <button onClick={() => removeTag(tag)} className="hover:text-gray-300 ml-1"><X size={10} /></button>
                        </span>
                    ))}
                </div>
                <input 
                    type="text" 
                    placeholder="Type + Enter"
                    className="w-full text-xs p-2 border border-gray-200 focus:border-black focus:ring-0"
                    value={tagInput}
                    onChange={(e) => setTagInput(e.target.value)}
                    onKeyDown={handleAddTag}
                />
            </div>
        </div>
      </div>
    </div>
  );
};

export default Editor;

import React, { useState, useRef } from 'react';
import { Post, PostStatus, MediaItem } from '../types';
import { 
  ArrowLeft, Eye, EyeOff, Sparkles, Image as ImageIcon, 
  MoreVertical, X, Check, Bold, Italic, Heading1, Heading2, 
  Quote, List, Link as LinkIcon, Wand2, PlayCircle, Clock, Upload,
  Maximize2, Minimize2, Code, FileImage, Minus, Columns, Save
} from 'lucide-react';
import { GeminiService } from '../services/geminiService';

interface EditorProps {
  post?: Post;
  media: MediaItem[];
  onSave: (post: Post) => void;
  onCancel: () => void;
  onUploadMedia: (item: MediaItem) => void;
}

// Simple Markdown to HTML converter function
const simpleMarkdown = (text: string) => {
    let html = text
        .replace(/^# (.*$)/gim, '<h1 class="text-3xl font-bold mb-4 font-mono uppercase tracking-tight">$1</h1>')
        .replace(/^## (.*$)/gim, '<h2 class="text-2xl font-bold mt-6 mb-3 font-mono uppercase tracking-tight border-b border-gray-200 pb-2">$1</h2>')
        .replace(/^### (.*$)/gim, '<h3 class="text-xl font-bold mt-4 mb-2 font-mono">$1</h3>')
        .replace(/^\> (.*$)/gim, '<blockquote class="border-l-2 border-black pl-4 italic my-4 text-gray-500 font-serif">$1</blockquote>')
        .replace(/\*\*(.*)\*\*/gim, '<b>$1</b>')
        .replace(/\*(.*)\*/gim, '<i>$1</i>')
        .replace(/`([^`]+)`/gim, '<code class="bg-gray-100 px-1 py-0.5 rounded text-sm font-mono text-red-600">$1</code>')
        // Markdown image syntax fallback (still useful for quick typing)
        .replace(/!\[(.*?)\]\((.*?)\)/gim, "<img alt='$1' src='$2' class='my-6 max-w-full border border-gray-200 p-1 block' />")
        .replace(/\[(.*?)\]\((.*?)\)/gim, "<a href='$2' class='text-black underline decoration-gray-400 hover:decoration-black'>$1</a>")
        .replace(/^\- (.*$)/gim, '<li class="ml-4 list-disc">$1</li>')
        .replace(/^-{3,}$/gim, '<hr class="my-6 border-gray-200" />')
        .replace(/\n/gim, '<br />');
    return html;
};

const Editor: React.FC<EditorProps> = ({ post, media, onSave, onCancel, onUploadMedia }) => {
  const [title, setTitle] = useState(post?.title || '');
  const [content, setContent] = useState(post?.content || '');
  const [excerpt, setExcerpt] = useState(post?.excerpt || '');
  const [status, setStatus] = useState<PostStatus>(post?.status || PostStatus.DRAFT);
  const [tags, setTags] = useState<string[]>(post?.tags || []);
  const [coverImage, setCoverImage] = useState(post?.coverImage || '');

  // View Modes: 'edit' (Focus), 'split' (Side-by-Side), 'preview' (Full Preview)
  const [editorMode, setEditorMode] = useState<'edit' | 'split' | 'preview'>('edit');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isZenMode, setIsZenMode] = useState(false);

  // Media Picker State
  const [showMediaPicker, setShowMediaPicker] = useState(false);
  const [pickerTarget, setPickerTarget] = useState<'content' | 'cover'>('content');
  const [imageSize, setImageSize] = useState<'100%' | '50%' | '25%'>('100%');

  // AI State
  const [aiPrompt, setAiPrompt] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiResponse, setAiResponse] = useState<string | null>(null);
  const [tagInput, setTagInput] = useState('');

  const contentRef = useRef<HTMLTextAreaElement>(null);

  // Stats
  const wordCount = content.trim().split(/\s+/).filter(w => w.length > 0).length;
  const readTime = Math.ceil(wordCount / 200);

  const savePost = (targetStatus: PostStatus) => {
    const newPost: Post = {
      id: post?.id || crypto.randomUUID(),
      title,
      content,
      excerpt,
      status: targetStatus,
      author: post?.author || 'Admin', 
      createdAt: post?.createdAt || Date.now(),
      updatedAt: Date.now(),
      tags,
      coverImage
    };
    onSave(newPost);
  };

  const handlePublish = () => savePost(PostStatus.PUBLISHED);
  const handleSaveDraft = () => savePost(PostStatus.DRAFT);

  const handleAiGenerate = async () => {
      if (!aiPrompt) return;
      setIsAiLoading(true);
      setAiResponse(null);
      const result = await GeminiService.generateSuggestion(aiPrompt, content);
      setAiResponse(result);
      setIsAiLoading(false);
  };

  const handleAiContinue = async () => {
    setIsAiLoading(true);
    const result = await GeminiService.continueWriting(content);
    if (result) {
        setContent(prev => {
            const separator = prev.endsWith(' ') || prev.endsWith('\n') ? '' : ' ';
            return prev + separator + result;
        });
    }
    setIsAiLoading(false);
  };

  const handleAiImprove = async () => {
    const textarea = contentRef.current;
    if (!textarea) return;

    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const selection = content.substring(start, end);

    if (!selection) {
        alert("Please select some text to improve.");
        return;
    }

    setIsAiLoading(true);
    const improved = await GeminiService.improveText(selection);

    if (improved) {
        const newContent = content.substring(0, start) + improved + content.substring(end);
        setContent(newContent);
    }
    setIsAiLoading(false);
  };

  const applyAiResponse = () => {
      if (aiResponse) {
          setContent(prev => prev + '\n\n' + aiResponse);
          setAiResponse(null);
          setAiPrompt('');
      }
  };

  const handleAiExcerpt = async () => {
      setIsAiLoading(true);
      const generated = await GeminiService.generateExcerpt(content);
      setExcerpt(generated);
      setIsAiLoading(false);
  };

  const handleAddTag = (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' && tagInput.trim()) {
          e.preventDefault();
          if (!tags.includes(tagInput.trim())) {
              setTags([...tags, tagInput.trim()]);
          }
          setTagInput('');
      }
  };

  const removeTag = (tagToRemove: string) => {
      setTags(tags.filter(t => t !== tagToRemove));
  };

  const handleMediaUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        if (file.size > 2000000) {
            alert('File too large (Max 2MB)');
            return;
        }
        const reader = new FileReader();
        reader.onloadend = () => {
             const newItem: MediaItem = {
                id: crypto.randomUUID(),
                url: reader.result as string,
                name: file.name,
                type: file.type,
                createdAt: Date.now(),
                size: file.size
            };
            onUploadMedia(newItem);
        };
        reader.readAsDataURL(file);
    }
  };

  const openMediaPicker = (target: 'content' | 'cover') => {
      setPickerTarget(target);
      setShowMediaPicker(true);
  };

  const handleMediaSelect = (item: MediaItem) => {
      if (pickerTarget === 'cover') {
          setCoverImage(item.url);
      } else {
          // Insert HTML image tag with width, enabling "resize" via code edit
          const imgTag = `<img src="${item.url}" alt="${item.name}" width="${imageSize}" />`;
          insertFormat('html_image', imgTag);
      }
      setShowMediaPicker(false);
  };

  const insertFormat = (format: string, arg?: string) => {
    const textarea = contentRef.current;
    if (!textarea) return;

    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const text = textarea.value;
    const selection = text.substring(start, end);

    // Default wrap behavior
    let prefix = '';
    let suffix = '';

    switch (format) {
      case 'bold':
        prefix = '**'; suffix = '**'; 
        break;
      case 'italic':
        prefix = '*'; suffix = '*'; 
        break;
      case 'h1':
        prefix = '# '; 
        break;
      case 'h2':
        prefix = '## '; 
        break;
      case 'quote':
        prefix = '> '; 
        break;
      case 'list':
        prefix = '- '; 
        break;
      case 'link':
        prefix = '['; suffix = '](url)'; 
        break;
      case 'code':
        if (selection.includes('\n')) {
            prefix = '```\n'; suffix = '\n```'; 
        } else {
            prefix = '`'; suffix = '`'; 
        }
        break;
      case 'hr':
        prefix = '\n---\n'; 
        break;
      case 'image': // Standard Markdown Image
        const url = arg || 'url';
        prefix = `![Alt text](${url})`; 
        break;
       case 'html_image': // Custom sized image
        prefix = arg || '';
        break;
    }

    let newContent = '';
    if (format === 'image' || format === 'hr' || format === 'html_image') {
        newContent = text.substring(0, start) + prefix + text.substring(end);
    } else {
        newContent = text.substring(0, start) + prefix + selection + suffix + text.substring(end);
    }

    setContent(newContent);

    // Restore focus and cursor
    setTimeout(() => {
        textarea.focus();
        if (format !== 'image' && format !== 'hr' && format !== 'html_image') {
            if (selection.length > 0) {
                textarea.setSelectionRange(start + prefix.length, end + prefix.length);
            } else {
                textarea.setSelectionRange(start + prefix.length, start + prefix.length);
            }
        }
    }, 0);
  };

  const toggleEditorMode = () => {
      if (editorMode === 'edit') setEditorMode('split');
      else if (editorMode === 'split') setEditorMode('preview');
      else setEditorMode('edit');
  };

  return (
    <div className="flex h-full bg-white relative font-mono text-gray-900 overflow-hidden">
      {/* Media Picker Modal */}
      {showMediaPicker && (
          <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-8">
              <div className="bg-white w-full max-w-4xl h-[80vh] flex flex-col shadow-2xl animate-in fade-in zoom-in-95 duration-200">
                  <header className="p-6 border-b border-gray-100 flex items-center justify-between">
                      <div>
                          <h3 className="text-xl font-bold uppercase tracking-tight">Select Asset</h3>
                          <p className="text-xs text-gray-500 mt-1">
                              {pickerTarget === 'cover' ? 'Setting cover image' : 'Inserting into content'}
                          </p>
                      </div>
                      <div className="flex items-center gap-4">
                           {pickerTarget === 'content' && (
                                <div className="flex items-center gap-2 mr-4 bg-gray-50 p-1 border border-gray-200 rounded">
                                    <span className="text-[10px] font-bold uppercase px-2 text-gray-500">Width:</span>
                                    <button onClick={() => setImageSize('25%')} className={`text-[10px] px-2 py-1 font-bold ${imageSize === '25%' ? 'bg-black text-white' : 'text-gray-400'}`}>S</button>
                                    <button onClick={() => setImageSize('50%')} className={`text-[10px] px-2 py-1 font-bold ${imageSize === '50%' ? 'bg-black text-white' : 'text-gray-400'}`}>M</button>
                                    <button onClick={() => setImageSize('100%')} className={`text-[10px] px-2 py-1 font-bold ${imageSize === '100%' ? 'bg-black text-white' : 'text-gray-400'}`}>L</button>
                                </div>
                           )}

                          <div className="relative">
                                <input 
                                    type="file" 
                                    className="hidden" 
                                    id="modal-upload"
                                    accept="image/*"
                                    onChange={handleMediaUpload}
                                />
                                <label 
                                    htmlFor="modal-upload" 
                                    className="cursor-pointer bg-black text-white px-4 py-2 text-xs font-bold uppercase tracking-wider hover:bg-gray-800 flex items-center gap-2"
                                >
                                    <Upload size={14} /> Upload New
                                </label>
                          </div>
                          <button onClick={() => setShowMediaPicker(false)} className="p-2 hover:bg-gray-100"><X size={20} /></button>
                      </div>
                  </header>
                  <div className="flex-1 overflow-y-auto p-6 bg-gray-50">
                      {media.length === 0 ? (
                          <div className="h-full flex flex-col items-center justify-center text-gray-400">
                              <ImageIcon size={48} className="mb-4 opacity-20" />
                              <p className="text-sm font-bold uppercase">No Media Found</p>
                          </div>
                      ) : (
                          <div className="grid grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                              {media.map(item => (
                                  <button 
                                    key={item.id} 
                                    onClick={() => handleMediaSelect(item)}
                                    className="group relative aspect-square bg-white border border-gray-200 hover:border-black transition-colors focus:outline-none focus:ring-2 focus:ring-black focus:ring-offset-2"
                                  >
                                      <img src={item.url} alt={item.name} className="w-full h-full object-cover p-1" />
                                      <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors" />
                                      <div className="absolute bottom-0 left-0 right-0 bg-white/90 p-1 text-[10px] truncate border-t border-gray-100">
                                          {item.name}
                                      </div>
                                  </button>
                              ))}
                          </div>
                      )}
                  </div>
              </div>
          </div>
      )}

      {/* Main Editor Area */}
      <div className={`flex-1 flex flex-col transition-all duration-300 ${isSidebarOpen && !isZenMode ? 'mr-80' : ''}`}>
        {/* Top Header */}
        <header className={`h-16 border-b border-gray-200 flex items-center justify-between px-6 bg-white z-20 transition-all duration-300 ${isZenMode ? '-mt-16 opacity-0 pointer-events-none' : ''}`}>
            <div className="flex items-center gap-4">
                <button onClick={onCancel} className="p-2 hover:bg-gray-100 text-gray-500 transition-colors">
                    <ArrowLeft size={16} />
                </button>
                <div className="flex flex-col">
                    <span className="text-sm font-bold text-gray-900 leading-none truncate max-w-[200px]">
                        {title || 'UNTITLED_ENTRY'}
                    </span>
                    <span className="text-[10px] text-gray-400 mt-1 uppercase tracking-widest font-bold">
                        {status === PostStatus.DRAFT ? 'Draft' : 'Live'} &bull; {wordCount} words
                    </span>
                </div>
            </div>

            <div className="flex items-center gap-3">
                 <button 
                    onClick={toggleEditorMode} 
                    className="flex items-center gap-2 px-3 py-2 text-xs font-bold uppercase tracking-wider text-gray-500 border border-gray-200 hover:border-black hover:text-black transition-colors"
                    title="Toggle View Mode"
                >
                    {editorMode === 'edit' && <Eye size={14} />}
                    {editorMode === 'split' && <Columns size={14} />}
                    {editorMode === 'preview' && <EyeOff size={14} />}
                    <span className="hidden sm:inline">
                        {editorMode === 'edit' && 'Edit'}
                        {editorMode === 'split' && 'Split'}
                        {editorMode === 'preview' && 'Preview'}
                    </span>
                </button>

                <div className="h-6 w-px bg-gray-200 mx-1"></div>

                <button 
                    onClick={handleSaveDraft} 
                    className="text-gray-500 hover:text-black px-4 py-2 text-xs font-bold uppercase tracking-wider hover:bg-gray-50"
                >
                    Save Draft
                </button>

                <button 
                    onClick={handlePublish} 
                    className="bg-black hover:bg-gray-800 text-white px-5 py-2 text-xs font-bold uppercase tracking-wider flex items-center gap-2 transition-transform active:scale-95"
                >
                    <Save size={14} />
                    {status === PostStatus.PUBLISHED ? 'Update' : 'Publish'}
                </button>

                <button 
                    onClick={() => setIsSidebarOpen(!isSidebarOpen)} 
                    className={`p-2 transition-colors border ${isSidebarOpen ? 'bg-gray-100 text-black border-gray-300' : 'text-gray-400 border-transparent hover:bg-gray-50 hover:text-black'}`}
                >
                    <MoreVertical size={18} />
                </button>
            </div>
        </header>

        {/* Toolbar - Only visible when editing is possible (Edit or Split mode) */}
        {editorMode !== 'preview' && (
            <div className={`px-6 py-2 border-b border-gray-100 bg-white flex items-center gap-1 sticky top-0 z-10 overflow-x-auto transition-all duration-300 ${isZenMode ? 'opacity-0 -translate-y-full absolute w-full' : ''}`}>
                <button onClick={() => insertFormat('bold')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Bold"><Bold size={16} /></button>
                <button onClick={() => insertFormat('italic')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Italic"><Italic size={16} /></button>
                <button onClick={() => insertFormat('link')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Link"><LinkIcon size={16} /></button>
                <button onClick={() => insertFormat('code')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Code"><Code size={16} /></button>
                <button onClick={() => openMediaPicker('content')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Insert Image"><ImageIcon size={16} /></button>

                <div className="w-px h-4 bg-gray-200 mx-3"></div>

                <button onClick={() => insertFormat('h1')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Heading 1"><Heading1 size={16} /></button>
                <button onClick={() => insertFormat('h2')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Heading 2"><Heading2 size={16} /></button>
                <button onClick={() => insertFormat('quote')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Quote"><Quote size={16} /></button>
                <button onClick={() => insertFormat('list')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="List"><List size={16} /></button>
                <button onClick={() => insertFormat('hr')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Horizontal Rule"><Minus size={16} /></button>

                <div className="w-px h-4 bg-gray-200 mx-3"></div>

                <button 
                    onClick={handleAiContinue} 
                    disabled={isAiLoading}
                    className="flex items-center gap-1.5 px-3 py-1 text-[10px] font-bold uppercase tracking-wider text-black bg-gray-100 hover:bg-gray-200 transition-colors disabled:opacity-50 rounded"
                >
                    <PlayCircle size={12} />
                    {isAiLoading ? 'Thinking...' : 'Continue'}
                </button>
                <button 
                    onClick={handleAiImprove} 
                    disabled={isAiLoading}
                    className="flex items-center gap-1.5 px-3 py-1 text-[10px] font-bold uppercase tracking-wider text-black bg-gray-100 hover:bg-gray-200 transition-colors disabled:opacity-50 ml-1 rounded"
                    title="Select text to improve"
                >
                    <Wand2 size={12} />
                    Enhance
                </button>

                <div className="flex-1"></div>

                <button 
                    onClick={() => setIsZenMode(!isZenMode)}
                    className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" 
                    title="Zen Mode"
                >
                    {isZenMode ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
                </button>
            </div>
        )}

        {/* Editor Content Area */}
        <div className="flex-1 overflow-hidden bg-white relative flex">
            {/* Zen Mode Exit Button (Floating) */}
            {isZenMode && editorMode !== 'preview' && (
                <button 
                    onClick={() => setIsZenMode(false)}
                    className="absolute top-4 right-6 z-30 p-2 bg-gray-100 text-gray-500 hover:text-black hover:bg-gray-200 rounded-full opacity-50 hover:opacity-100 transition-opacity"
                    title="Exit Zen Mode"
                >
                    <Minimize2 size={16} />
                </button>
            )}

            {/* Editor Pane */}
            {(editorMode === 'edit' || editorMode === 'split') && (
                <div className={`flex-1 h-full flex flex-col overflow-auto transition-all duration-500 ${isZenMode ? 'py-16' : 'py-10'} ${editorMode === 'split' ? 'border-r border-gray-200' : ''}`}>
                    <div className="max-w-3xl mx-auto px-6 w-full h-full flex flex-col">
                        <input 
                            type="text" 
                            placeholder="ENTER_TITLE" 
                            className="text-4xl font-bold text-gray-900 placeholder-gray-200 border-none focus:ring-0 w-full bg-transparent p-0 mb-8 font-mono uppercase tracking-tight"
                            value={title}
                            onChange={(e) => setTitle(e.target.value)}
                        />
                        <textarea 
                            ref={contentRef}
                            placeholder="Start typing..." 
                            className="flex-1 resize-none w-full border-none focus:ring-0 text-lg leading-relaxed text-gray-800 placeholder-gray-200 bg-transparent p-0 font-mono outline-none"
                            value={content}
                            onChange={(e) => setContent(e.target.value)}
                            spellCheck={false}
                        />
                         {!isZenMode && (
                            <div className="mt-4 pt-4 border-t border-gray-100 text-[10px] text-gray-400 flex items-center justify-between font-mono uppercase tracking-widest">
                                <div className="flex items-center gap-4">
                                    <span>Markdown Enabled</span>
                                    {aiResponse && <span className="text-black font-bold animate-pulse">AI Suggestion Ready</span>}
                                </div>
                                <span className="flex items-center gap-1"><Clock size={12} /> {readTime} min read</span>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* Preview Pane */}
            {(editorMode === 'preview' || editorMode === 'split') && (
                <div className={`h-full overflow-auto bg-gray-50/50 ${editorMode === 'split' ? 'flex-1' : 'w-full'}`}>
                    <div className="max-w-3xl mx-auto px-8 py-16 prose prose-stone">
                        <h1 className="font-mono uppercase">{title || "Untitled Post"}</h1>
                        {coverImage && <img src={coverImage} alt="Cover" className="w-full grayscale border border-gray-200 mb-8 p-1" />}
                        <div dangerouslySetInnerHTML={{ __html: simpleMarkdown(content) }} />
                    </div>
                </div>
            )}
        </div>
      </div>

      {/* Settings/AI Sidebar */}
      <div className={`fixed right-0 top-0 bottom-0 w-80 bg-white border-l border-gray-200 shadow-2xl transform transition-transform duration-300 z-30 flex flex-col ${isSidebarOpen && !isZenMode ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="flex items-center justify-between p-5 border-b border-gray-200 bg-gray-50">
            <h3 className="font-bold text-xs text-gray-900 uppercase tracking-widest">Config</h3>
            <button onClick={() => setIsSidebarOpen(false)} className="text-gray-400 hover:text-black">
                <X size={18} />
            </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-8">
            {/* AI Assistant Section */}
            <div className="bg-gray-50 border border-gray-200 p-4">
                <div className="flex items-center gap-2 text-black font-bold text-[10px] uppercase tracking-widest mb-3">
                    <Sparkles size={12} />
                    <span>Gemini AI</span>
                </div>

                <div className="space-y-3">
                    <textarea 
                        className="w-full text-xs p-2 border border-gray-200 focus:border-black focus:ring-0 min-h-[80px] bg-white"
                        placeholder="Request generated content..."
                        value={aiPrompt}
                        onChange={(e) => setAiPrompt(e.target.value)}
                    />
                    <button 
                        onClick={handleAiGenerate}
                        disabled={isAiLoading || !aiPrompt}
                        className="w-full bg-white border border-gray-900 hover:bg-gray-900 hover:text-white text-black text-[10px] py-2 font-bold uppercase tracking-wider transition-colors disabled:opacity-50"
                    >
                        {isAiLoading ? 'Processing...' : 'Execute'}
                    </button>
                </div>

