                            className="flex-1 resize-none w-full border-none focus:ring-0 text-lg leading-relaxed text-gray-800 placeholder-gray-200 bg-transparent p-0 font-mono outline-none"
                            value={content}
                            onChange={(e) => setContent(e.target.value)}
