  Quote, List, Link as LinkIcon, Clock, Upload,
  Maximize2, Minimize2, Code, FileImage, Minus, Columns, Save, Film
} from 'lucide-react';

interface EditorProps {
  post?: Post;
  media: MediaItem[];
