import React, { useState } from 'react';
import { Post, PostStatus, SiteSettings, MediaItem } from '../types';
import { format } from 'date-fns';
import { ArrowLeft, Edit, LayoutDashboard, Twitter, Github } from 'lucide-react';

interface SitePreviewProps {
  posts: Post[];
  settings: SiteSettings;
  onBackToDashboard: () => void;
  onEditPost: (id: string) => void;
  media: MediaItem[];
}

// Content resolver: Handles asset:// links in HTML content
const resolveContent = (htmlContent: string, media: MediaItem[]) => {
    if (!htmlContent) return '';

    // Resolve asset:// references
    let html = htmlContent.replace(/asset:\/\/([a-zA-Z0-9-]+)/g, (match, id) => {
        const item = media.find(m => m.id === id);
        return item ? item.url : match;
    });

    // Ensure videos are responsive (only add class if missing)
    html = html.replace(/<video(?!.*?class)/g, '<video class="w-full my-6 border border-gray-200 block"');
    // Ensure images are responsive if they don't have classes
    html = html.replace(/<img(?!.*?class)/g, '<img class="max-w-full h-auto my-6 border border-gray-200 block"');

    // Remove contenteditable attributes from output
    html = html.replace(/contenteditable="[^"]*"/g, '');

    return html;
};

const SitePreview: React.FC<SitePreviewProps> = ({ posts, settings, onBackToDashboard, onEditPost, media }) => {
