  const publishedPosts = posts.filter(p => p.status === PostStatus.PUBLISHED);
  const activePost = viewingPostId ? posts.find(p => p.id === viewingPostId) : null;

  // Render Single Post
  if (activePost) {
    return (
      <div className="min-h-screen bg-white font-serif selection:bg-black selection:text-white">
        {/* Admin Bar Overlay */}
        <div className="fixed bottom-6 right-6 z-50 flex gap-2">
             <button 
                onClick={() => onEditPost(activePost.id)}
                className="bg-black text-white px-5 py-3 shadow-2xl hover:bg-gray-800 transition-transform hover:-translate-y-1 flex items-center gap-2 font-mono text-xs font-bold uppercase tracking-widest"
            >
                <Edit size={14} />
                Edit
