            </div>
        </header>

        {/* Toolbar - WYSIWYG */}
        {editorMode === 'edit' && (
            <div className={`px-6 py-2 border-b border-gray-100 bg-white flex items-center gap-1 sticky top-0 z-10 overflow-x-auto transition-all duration-300 ${isZenMode ? 'opacity-0 -translate-y-full absolute w-full' : ''}`}>
                <button onClick={() => execCmd('bold')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Bold"><Bold size={16} /></button>
                <button onClick={() => execCmd('italic')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Italic"><Italic size={16} /></button>
                <button onClick={insertLink} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Link"><LinkIcon size={16} /></button>

                <div className="w-px h-4 bg-gray-200 mx-3"></div>

                <button onClick={() => execCmd('formatBlock', 'H1')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Heading 1"><Heading1 size={16} /></button>
                <button onClick={() => execCmd('formatBlock', 'H2')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Heading 2"><Heading2 size={16} /></button>
                <button onClick={() => execCmd('formatBlock', 'BLOCKQUOTE')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Quote"><Quote size={16} /></button>
                <button onClick={() => execCmd('insertUnorderedList')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="List"><List size={16} /></button>
                <button onClick={() => execCmd('insertHorizontalRule')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Horizontal Rule"><Minus size={16} /></button>

                <div className="w-px h-4 bg-gray-200 mx-3"></div>

                <button onClick={() => openMediaPicker('content')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Insert Media"><ImageIcon size={16} /></button>
                <button onClick={insertVideoUrl} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Embed Video from URL"><Film size={16} /></button>

                <div className="flex-1"></div>

                <button 
                    onClick={() => setIsZenMode(!isZenMode)}
                    className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" 
                    title="Zen Mode"
                >
                    {isZenMode ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
                </button>
            </div>
        )}

        {/* Editor Content Area */}
        <div className="flex-1 overflow-hidden bg-white relative flex flex-col">
            {/* Zen Mode Exit Button (Floating) */}
            {isZenMode && editorMode === 'edit' && (
                <button 
                    onClick={() => setIsZenMode(false)}
                    className="absolute top-4 right-6 z-30 p-2 bg-gray-100 text-gray-500 hover:text-black hover:bg-gray-200 rounded-full opacity-50 hover:opacity-100 transition-opacity"
                    title="Exit Zen Mode"
                >
                    <Minimize2 size={16} />
                </button>
            )}

            <div className={`flex-1 h-full flex flex-col overflow-auto transition-all duration-500 ${isZenMode && editorMode === 'edit' ? 'py-16' : 'py-10'}`}>
                <div className="max-w-3xl mx-auto px-6 w-full h-full flex flex-col">
                    {editorMode === 'edit' ? (
                        <>
                            <input 
                                type="text" 
                                placeholder="Untitled Entry" 
                                className="text-5xl md:text-6xl font-bold text-gray-900 placeholder-gray-300 border-none focus:ring-0 w-full bg-transparent p-0 mb-8 tracking-tighter font-serif leading-[0.9]"
                                value={title}
                                onChange={(e) => setTitle(e.target.value)}
                            />

                            {/* ContentEditable WYSIWYG Area */}
                            <div
                                ref={editorRef}
                                contentEditable
                                className="flex-1 w-full outline-none prose prose-xl prose-stone max-w-none prose-headings:font-serif prose-p:text-gray-600 prose-p:font-serif prose-a:text-black hover:prose-a:decoration-black text-gray-800 leading-relaxed font-serif"
                                style={{ minHeight: '50vh' }}
                            />

                            {!isZenMode && (
                                <div className="mt-4 pt-4 border-t border-gray-100 text-[10px] text-gray-400 flex items-center justify-between font-mono uppercase tracking-widest">
                                    <div className="flex items-center gap-4">
                                        <span>WYSIWYG Enabled</span>
                                    </div>
                                    <span className="flex items-center gap-1"><Clock size={12} /> {readTime} min read</span>
                                </div>
                            )}
                        </>
                    ) : (
                         <div className="prose prose-xl prose-stone prose-headings:font-serif prose-p:text-gray-600 prose-p:font-serif prose-a:text-black hover:prose-a:decoration-black text-gray-800 leading-relaxed py-10">
                            <h1 className="text-5xl md:text-6xl font-bold text-gray-900 leading-[0.9] mb-8 tracking-tighter">{title || "Untitled Post"}</h1>
                            {coverImage && <img src={coverImage} alt="Cover" className="w-full grayscale border border-gray-200 mb-12 p-1" />}
                            <div dangerouslySetInnerHTML={{ __html: processPreviewContent(previewContent) }} />
                        </div>
                    )}
                </div>
            </div>
        </div>
      </div>

      {/* Settings Sidebar */}
      <div className={`fixed right-0 top-0 bottom-0 w-80 bg-white border-l border-gray-200 shadow-2xl transform transition-transform duration-300 z-30 flex flex-col ${isSidebarOpen && !isZenMode ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="flex items-center justify-between p-5 border-b border-gray-200 bg-gray-50">
            <h3 className="font-bold text-xs text-gray-900 uppercase tracking-widest">Config</h3>
            <button onClick={() => setIsSidebarOpen(false)} className="text-gray-400 hover:text-black">
                <X size={18} />
            </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-8">
            {/* General Settings */}
            <div>
                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Meta Description</label>
                <textarea 
                    className="w-full text-xs p-3 border border-gray-200 focus:border-black focus:ring-0 min-h-[100px] bg-gray-50"
                    placeholder="Brief summary..."
                    value={excerpt}
                    onChange={(e) => setExcerpt(e.target.value)}
                />
            </div>

            <div>
                 <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Cover Asset</label>
                 <div className="space-y-3">
                    <button 
                        onClick={() => openMediaPicker('cover')}
                        className="w-full py-6 border border-dashed border-gray-300 hover:border-black text-gray-400 hover:text-black transition-colors flex flex-col items-center justify-center gap-2 bg-gray-50"
                        title="Select Image"
                    >
                        <FileImage size={16} />
                        <span className="text-[10px] uppercase font-bold">Select from Library</span>
                    </button>

                    {coverImage && (
                        <div className="relative group">
                            <img src={coverImage} alt="Preview" className="w-full h-32 object-cover border border-gray-200 grayscale" />
                            <button onClick={() => setCoverImage('')} className="absolute top-2 right-2 bg-black text-white p-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                <X size={12} />
                            </button>
                        </div>
                    )}
                 </div>
            </div>

            <div>
                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Keywords / Tags</label>
                <div className="flex flex-wrap gap-2 mb-2">
                    {tags.map(tag => (
                        <span key={tag} className="bg-black text-white px-2 py-1 text-[10px] font-bold uppercase tracking-wider flex items-center gap-1">
                            {tag}
                            <button onClick={() => removeTag(tag)} className="hover:text-gray-300 ml-1"><X size={10} /></button>
                        </span>
                    ))}
                </div>
                <input 
                    type="text" 
                    placeholder="Type + Enter"
                    className="w-full text-xs p-2 border border-gray-200 focus:border-black focus:ring-0"
                    value={tagInput}
                    onChange={(e) => setTagInput(e.target.value)}
                    onKeyDown={handleAddTag}
                />
            </div>
        </div>
      </div>
    </div>
  );
};

export default Editor;

import React, { useState, useRef, useEffect } from 'react';
import { Post, PostStatus, MediaItem } from '../types';
import { 
  ArrowLeft, Eye, EyeOff, Image as ImageIcon, 
  MoreVertical, X, Bold, Italic, Heading1, Heading2, 
  Quote, List, Link as LinkIcon, Upload,
  Maximize2, Minimize2, Code, FileImage, Minus, Save, Film, Clock
} from 'lucide-react';

interface EditorProps {
  post?: Post;
  media: MediaItem[];
  onSave: (post: Post) => void;
  onCancel: () => void;
  onUploadMedia: (item: MediaItem) => void;
}

// Helper to convert legacy markdown to HTML for the initial load of the WYSIWYG editor
const legacyMarkdownToHtml = (text: string, media: MediaItem[]) => {
    let html = text
        .replace(/^# (.*$)/gim, '<h1>$1</h1>')
        .replace(/^## (.*$)/gim, '<h2>$1</h2>')
        .replace(/^### (.*$)/gim, '<h3>$1</h3>')
        .replace(/^\> (.*$)/gim, '<blockquote>$1</blockquote>')
        .replace(/\*\*(.*)\*\*/gim, '<b>$1</b>')
        .replace(/\*(.*)\*/gim, '<i>$1</i>')
        // Convert Markdown Video/Image syntax to HTML tags
        .replace(/!\[(.*?)\]\((.*?\.(mp4|webm|ogg|mov))\)/gim, "<video src='$2' controls contenteditable='false'></video>")
        .replace(/!\[(.*?)\]\((.*?)\)/gim, "<img alt='$1' src='$2' contenteditable='false' />")
        .replace(/\[(.*?)\]\((.*?)\)/gim, "<a href='$2'>$1</a>")
        .replace(/^\- (.*$)/gim, '<ul><li>$1</li></ul>')
        .replace(/\n/gim, '<br />');

    // Resolve asset:// references to real URLs for display
    html = html.replace(/asset:\/\/([a-zA-Z0-9-]+)/g, (match, id) => {
        const item = media.find(m => m.id === id);
        return item ? item.url : match;
    });

    return html;
};

// Helper to enhance preview content (e.g. converting raw video URLs to players)
const processPreviewContent = (html: string) => {
    let processed = html;

    // Fallback UI for broken videos
    // Escaped single quotes for embedding in the onerror attribute string
    const fallbackHtml = `<div class=\\'w-full my-6 p-8 bg-gray-50 border border-dashed border-gray-200 flex flex-col items-center justify-center text-gray-400 gap-2\\'><svg xmlns=\\'http://www.w3.org/2000/svg\\' width=\\'24\\' height=\\'24\\' viewBox=\\'0 0 24 24\\' fill=\\'none\\' stroke=\\'currentColor\\' stroke-width=\\'2\\' stroke-linecap=\\'round\\' stroke-linejoin=\\'round\\'><circle cx=\\'12\\' cy=\\'12\\' r=\\'10\\'/><line x1=\\'15\\' y=\\'9\\' x2=\\'9\\' y=\\'15\\'/><line x1=\\'9\\' y=\\'9\\' x2=\\'15\\' y=\\'15\\'/></svg><span class=\\'text-xs font-bold uppercase tracking-wider\\'>Video Unavailable</span></div>`;
    const onErrorAttr = `onerror="this.outerHTML='${fallbackHtml}'"`;

    // 1. Ensure existing video tags have controls, proper styling, and error handling
    processed = processed.replace(/<video(.*?)>/g, (match, attributes) => {
        let newAttrs = attributes;
        if (!newAttrs.includes('onerror=')) {
            newAttrs = `${onErrorAttr} ${newAttrs}`;
        }
        if (!newAttrs.includes('controls')) {
            newAttrs += ' controls';
        }
        return `<video ${newAttrs} class="w-full my-6 border border-gray-200 block">`;
    });

    // 2. Detect raw video URLs in text and convert to embeds
    // This regex looks for http/https URLs ending in video extensions that are NOT inside src="..." attributes
    const videoUrlRegex = /(?<!src=["'])(https?:\/\/[^\s<"]+\.(mp4|webm|ogg|mov))/g;
    processed = processed.replace(videoUrlRegex, `<video ${onErrorAttr} src="$1" controls class="w-full my-6 border border-gray-200 block"></video>`);

    return processed;
};

const Editor: React.FC<EditorProps> = ({ post, media, onSave, onCancel, onUploadMedia }) => {
  const [title, setTitle] = useState(post?.title || '');
  const [status, setStatus] = useState<PostStatus>(post?.status || PostStatus.DRAFT);
  const [tags, setTags] = useState<string[]>(post?.tags || []);
  const [coverImage, setCoverImage] = useState(post?.coverImage || '');

  // Editor State
  const [editorMode, setEditorMode] = useState<'edit' | 'preview'>('edit');
  const [previewContent, setPreviewContent] = useState('');

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isZenMode, setIsZenMode] = useState(false);

  // Media Picker State
  const [showMediaPicker, setShowMediaPicker] = useState(false);
  const [pickerTarget, setPickerTarget] = useState<'content' | 'cover'>('content');
  const [imageSize, setImageSize] = useState<'100%' | '50%' | '25%'>('100%');

  const [tagInput, setTagInput] = useState('');
  const [excerpt, setExcerpt] = useState(post?.excerpt || '');

  const editorRef = useRef<HTMLDivElement>(null);

  // Initialize content
  useEffect(() => {
    if (editorRef.current) {
        // If it looks like HTML, use it. If it looks like markdown (legacy), convert it.
        const initialContent = post?.content || '';
        const isHtml = initialContent.trim().startsWith('<');

        let contentToSet = initialContent;
        if (!isHtml) {
            contentToSet = legacyMarkdownToHtml(initialContent, media);
        } else {
             // Resolve assets for display if they are in HTML format
            contentToSet = contentToSet.replace(/asset:\/\/([a-zA-Z0-9-]+)/g, (match, id) => {
                const item = media.find(m => m.id === id);
                return item ? item.url : match;
            });
        }
        editorRef.current.innerHTML = contentToSet;
    }
  }, [post?.id]); 

  // Stats
  const getStats = () => {
     if (!editorRef.current) return { wordCount: 0, readTime: 0 };
     const text = editorRef.current.innerText || '';
     const wordCount = text.trim().split(/\s+/).filter(w => w.length > 0).length;
     const readTime = Math.ceil(wordCount / 200);
     return { wordCount, readTime };
  };
  const { wordCount, readTime } = getStats();

  const handleSave = (targetStatus: PostStatus) => {
    if (!editorRef.current) return;

    // Process content for save: Replace real Base64 URLs back to asset:// IDs to save space
    let htmlContent = editorRef.current.innerHTML;

    media.forEach(item => {
        if (item.url.length > 100) { 
             htmlContent = htmlContent.split(item.url).join(`asset://${item.id}`);
        }
    });

    const newPost: Post = {
      id: post?.id || crypto.randomUUID(),
      title,
      content: htmlContent, 
      excerpt,
      status: targetStatus,
      author: post?.author || 'Admin', 
      createdAt: post?.createdAt || Date.now(),
      updatedAt: Date.now(),
      tags,
      coverImage
    };
    onSave(newPost);
  };

  const handlePublish = () => handleSave(PostStatus.PUBLISHED);
  const handleSaveDraft = () => handleSave(PostStatus.DRAFT);

  const handleAddTag = (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' && tagInput.trim()) {
          e.preventDefault();
          if (!tags.includes(tagInput.trim())) {
              setTags([...tags, tagInput.trim()]);
          }
          setTagInput('');
      }
  };

  const removeTag = (tagToRemove: string) => {
      setTags(tags.filter(t => t !== tagToRemove));
  };

  const handleMediaUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        if (file.size > 5 * 1024 * 1024) {
            alert('File too large (Max 5MB)');
            return;
        }
        const reader = new FileReader();
        reader.onloadend = () => {
             const isVideo = file.type.startsWith('video/');
             const newItem: MediaItem = {
                id: crypto.randomUUID(),
                url: reader.result as string,
                name: file.name,
                type: file.type,
                mediaType: isVideo ? 'video' : 'image',
                createdAt: Date.now(),
                size: file.size
            };
            onUploadMedia(newItem);
        };
        reader.readAsDataURL(file);
    }
  };

  const openMediaPicker = (target: 'content' | 'cover') => {
      setPickerTarget(target);
      setShowMediaPicker(true);
  };

  const handleMediaSelect = (item: MediaItem) => {
      const isVideo = item.mediaType === 'video' || item.type.startsWith('video/');

      if (pickerTarget === 'cover') {
          if (isVideo) {
              alert('Cannot use video as cover image.');
              return;
          }
          setCoverImage(item.url);
      } else {
          // WYSIWYG: Insert the actual element directly into the DOM
          editorRef.current?.focus();

          if (isVideo) {
            const html = `<video src="${item.url}" controls width="${imageSize}" class="my-6 max-w-full border border-gray-200 block" contenteditable="false" preload="metadata"></video><p><br/></p>`;
            document.execCommand('insertHTML', false, html);
          } else {
            const html = `<img src="${item.url}" alt="${item.name}" width="${imageSize}" class="my-6 max-w-full border border-gray-200 block" contenteditable="false" /><p><br/></p>`;
            document.execCommand('insertHTML', false, html);
          }
      }
      setShowMediaPicker(false);
  };

  // WYSIWYG Commands
  const execCmd = (command: string, value: string | undefined = undefined) => {
      editorRef.current?.focus();
      document.execCommand(command, false, value);
  };

  const insertLink = () => {
      const url = prompt('Enter URL:');
      if (url) execCmd('createLink', url);
  };

  const insertVideoUrl = () => {
      const url = prompt('Enter Video URL (mp4, webm, ogg):');
      if (url) {
          const html = `<video src="${url}" controls class="w-full my-6 border border-gray-200" contenteditable="false"></video><p><br/></p>`;
          execCmd('insertHTML', html);
      }
  };

  const toggleMode = () => {
      if (editorMode === 'edit') {
          // Capture content before switching
          if (editorRef.current) {
              setPreviewContent(editorRef.current.innerHTML);
          }
          setEditorMode('preview');
      } else {
          setEditorMode('edit');
      }
  };

  return (
    <div className="flex h-full bg-white relative font-mono text-gray-900 overflow-hidden">
      {/* Media Picker Modal */}
      {showMediaPicker && (
          <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-8">
              <div className="bg-white w-full max-w-4xl h-[80vh] flex flex-col shadow-2xl animate-in fade-in zoom-in-95 duration-200">
                  <header className="p-6 border-b border-gray-100 flex items-center justify-between">
                      <div>
                          <h3 className="text-xl font-bold uppercase tracking-tight">Select Asset</h3>
                          <p className="text-xs text-gray-500 mt-1">
                              {pickerTarget === 'cover' ? 'Setting cover image' : 'Inserting into content'}
                          </p>
                      </div>
                      <div className="flex items-center gap-4">
                           {pickerTarget === 'content' && (
                                <div className="flex items-center gap-2 mr-4 bg-gray-50 p-1 border border-gray-200 rounded">
                                    <span className="text-[10px] font-bold uppercase px-2 text-gray-500">Width:</span>
                                    <button onClick={() => setImageSize('25%')} className={`text-[10px] px-2 py-1 font-bold ${imageSize === '25%' ? 'bg-black text-white' : 'text-gray-400'}`}>S</button>
                                    <button onClick={() => setImageSize('50%')} className={`text-[10px] px-2 py-1 font-bold ${imageSize === '50%' ? 'bg-black text-white' : 'text-gray-400'}`}>M</button>
                                    <button onClick={() => setImageSize('100%')} className={`text-[10px] px-2 py-1 font-bold ${imageSize === '100%' ? 'bg-black text-white' : 'text-gray-400'}`}>L</button>
                                </div>
                           )}

                          <div className="relative">
                                <input 
                                    type="file" 
                                    className="hidden" 
                                    id="modal-upload"
                                    accept="image/*,video/*"
                                    onChange={handleMediaUpload}
                                />
                                <label 
                                    htmlFor="modal-upload" 
                                    className="cursor-pointer bg-black text-white px-4 py-2 text-xs font-bold uppercase tracking-wider hover:bg-gray-800 flex items-center gap-2"
                                >
                                    <Upload size={14} /> Upload New
                                </label>
                          </div>
                          <button onClick={() => setShowMediaPicker(false)} className="p-2 hover:bg-gray-100"><X size={20} /></button>
                      </div>
                  </header>
                  <div className="flex-1 overflow-y-auto p-6 bg-gray-50">
                      <div className="grid grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                          {media.map(item => {
                              const isVideo = item.mediaType === 'video' || item.type.startsWith('video/');
                              return (
                                <button 
                                    key={item.id} 
                                    onClick={() => handleMediaSelect(item)}
                                    className="group relative aspect-square bg-white border border-gray-200 hover:border-black transition-colors focus:outline-none focus:ring-2 focus:ring-black focus:ring-offset-2 overflow-hidden"
                                    onMouseEnter={(e) => {
                                        if (isVideo) {
                                            const v = e.currentTarget.querySelector('video');
                                            if(v) v.play().catch(() => {});
                                        }
                                    }}
                                    onMouseLeave={(e) => {
                                        if (isVideo) {
                                            const v = e.currentTarget.querySelector('video');
                                            if(v) { v.pause(); v.currentTime = 0; }
                                        }
                                    }}
                                >
                                    {isVideo ? (
                                        <div className="w-full h-full relative flex items-center justify-center bg-gray-100">
                                            <video src={item.url} className="w-full h-full object-cover p-1 opacity-60" muted playsInline loop />
                                            <Film size={24} className="absolute text-black pointer-events-none" />
                                        </div>
                                    ) : (
                                        <img src={item.url} alt={item.name} className="w-full h-full object-cover p-1" />
                                    )}
                                    <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors" />
                                    <div className="absolute bottom-0 left-0 right-0 bg-white/90 p-1 text-[10px] truncate border-t border-gray-100">
                                        {item.name}
                                    </div>
                                </button>
                              );
                          })}
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Main Editor Area */}
      <div className={`flex-1 flex flex-col transition-all duration-300 ${isSidebarOpen && !isZenMode ? 'mr-80' : ''}`}>
        {/* Top Header */}
        <header className={`h-16 border-b border-gray-200 flex items-center justify-between px-6 bg-white z-20 transition-all duration-300 ${isZenMode ? '-mt-16 opacity-0 pointer-events-none' : ''}`}>
            <div className="flex items-center gap-4">
                <button onClick={onCancel} className="p-2 hover:bg-gray-100 text-gray-500 transition-colors">
                    <ArrowLeft size={16} />
                </button>
                <div className="flex flex-col">
                    <span className="text-sm font-bold text-gray-900 leading-none truncate max-w-[200px]">
                        {title || 'UNTITLED_ENTRY'}
