            </div>
            <div>
                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Tags</label>
                <div className="flex flex-wrap gap-2 mb-2">
                    {tags.map(tag => (
                        <span key={tag} className="bg-black text-white px-2 py-1 text-[10px] font-bold uppercase tracking-wider flex items-center gap-1">
                            {tag}<button onClick={() => removeTag(tag)} className="hover:text-gray-300 ml-1"><X size={10} /></button>
