const VIDEO_FALLBACK_HTML = `<div class="w-full my-6 p-8 bg-gray-50 border border-dashed border-gray-200 flex flex-col items-center justify-center text-gray-400 gap-2"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="15" y="9" x2="9" y="15"/><line x1="9" y="9" x2="15" y="15"/></svg><span class="text-xs font-bold uppercase tracking-wider">Video Unavailable</span></div>`;
// Using double quotes for attributes inside the JS string, so we can wrap the whole HTML in single quotes for the JS assignment.
const VIDEO_ERROR_ATTR = `onerror='this.outerHTML=\`${VIDEO_FALLBACK_HTML}\`'`;

const legacyMarkdownToHtml = (text: string, media: MediaItem[]) => {
    let html = text
        .replace(/^# (.*$)/gim, '<h1>$1</h1>')
        .replace(/^## (.*$)/gim, '<h2>$1</h2>')
        .replace(/^### (.*$)/gim, '<h3>$1</h3>')
        .replace(/^\> (.*$)/gim, '<blockquote>$1</blockquote>')
        .replace(/\*\*(.*)\*\*/gim, '<b>$1</b>')
        .replace(/\*(.*)\*/gim, '<i>$1</i>')
        .replace(/!\[(.*?)\]\((.*?\.(mp4|webm|ogg|mov))\)/gim, `<video src='$2' controls class='max-w-full h-auto my-6 border border-gray-200 block' contenteditable='false' ${VIDEO_ERROR_ATTR}></video>`)
        .replace(/!\[(.*?)\]\((.*?)\)/gim, "<img alt='$1' src='$2' contenteditable='false' />")
        .replace(/\[(.*?)\]\((.*?)\)/gim, "<a href='$2'>$1</a>")
        .replace(/^\- (.*$)/gim, '<ul><li>$1</li></ul>')
        .replace(/\n/gim, '<br />');

    html = html.replace(/asset:\/\/([a-zA-Z0-9-]+)/g, (match, id) => {
        const item = media.find(m => m.id === id);
        return item ? item.url : match;
    });

    return html;
};

const processPreviewContent = (html: string) => {
    let processed = html;

    // Enhance Videos
    processed = processed.replace(/<video(.*?)>/g, (match, attributes) => {
        let newAttrs = attributes;
        if (!newAttrs.includes('onerror=')) {
            newAttrs = `${VIDEO_ERROR_ATTR} ${newAttrs}`;
        }
        if (!newAttrs.includes('controls')) {
            newAttrs += ' controls';
        }
        const responsiveClasses = "max-w-full h-auto w-full my-6 border border-gray-200 block";
        if (!newAttrs.includes('class=')) {
            newAttrs += ` class="${responsiveClasses}"`;
        } else {
             newAttrs = newAttrs.replace(/class=(["'])(.*?)\1/, (m, q, c) => `class=${q}${c} ${responsiveClasses}${q}`);
        }
        return `<video${newAttrs}>`;
    });
    const videoUrlRegex = /(?<!src=["'])(?<!src=)(https?:\/\/[^\s<"]+\.(mp4|webm|ogg|mov))/g;
    processed = processed.replace(videoUrlRegex, `<video ${VIDEO_ERROR_ATTR} src="$1" controls class="w-full max-w-full h-auto my-6 border border-gray-200 block"></video>`);

    // Enhance Audio
    processed = processed.replace(/<audio(.*?)>/g, (match, attributes) => {
        let newAttrs = attributes;
        if (!newAttrs.includes('controls')) {
            newAttrs += ' controls';
        }
        const responsiveClasses = "w-full my-6 border border-gray-200 block";
        if (!newAttrs.includes('class=')) {
            newAttrs += ` class="${responsiveClasses}"`;
        } else {
             newAttrs = newAttrs.replace(/class=(["'])(.*?)\1/, (m, q, c) => `class=${q}${c} ${responsiveClasses}${q}`);
        }
        return `<audio${newAttrs}>`;
    });

    // Enhance Images for Lightbox
    processed = processed.replace(/<img([^>]*)>/g, (match, attrs) => {
        let newAttrs = attrs;
        const additionalClasses = `cursor-zoom-in transition-transform hover:scale-[1.01]`;

        if (newAttrs.includes('class=')) {
            newAttrs = newAttrs.replace(/class=(["'])(.*?)\1/, (m, q, c) => `class=${q}${c} ${additionalClasses}${q}`);
        } else {
            newAttrs += ` class="max-w-full h-auto my-6 border border-gray-200 block ${additionalClasses}"`;
        }
        return `<img${newAttrs}>`;
    });

    return processed;
};

const Editor: React.FC<EditorProps> = ({ post, media, onSave, onCancel, onUploadMedia }) => {
  const settings = StorageService.getSettings();
  const [title, setTitle] = useState(post?.title || '');
  const [status, setStatus] = useState<PostStatus>(post?.status || PostStatus.DRAFT);
  const [tags, setTags] = useState<string[]>(post?.tags || []);
  const [coverImage, setCoverImage] = useState(post?.coverImage || '');

  const [editorMode, setEditorMode] = useState<'edit' | 'preview'>('edit');
  const [previewContent, setPreviewContent] = useState('');

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isZenMode, setIsZenMode] = useState(false);

  const [showMediaPicker, setShowMediaPicker] = useState(false);
  const [pickerTarget, setPickerTarget] = useState<'content' | 'cover'>('content');
  const [linkMode, setLinkMode] = useState<'none' | 'file' | 'custom'>('none');
  const [customLinkUrl, setCustomLinkUrl] = useState('');
  const [savedRange, setSavedRange] = useState<Range | null>(null);

  const [tagInput, setTagInput] = useState('');
  const [excerpt, setExcerpt] = useState(post?.excerpt || '');

  // Image Selection & Resizing State
  const [selectedImg, setSelectedImg] = useState<HTMLImageElement | null>(null);
  const [refreshOverlay, setRefreshOverlay] = useState(0);

  // Modal State
  const [modalImage, setModalImage] = useState<string | null>(null);

  const editorRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (editorRef.current) {
        const initialContent = post?.content || '';
        const isHtml = initialContent.trim().startsWith('<');
        let contentToSet = initialContent;
        if (!isHtml) {
            contentToSet = legacyMarkdownToHtml(initialContent, media);
        } else {
            contentToSet = contentToSet.replace(/asset:\/\/([a-zA-Z0-9-]+)/g, (match, id) => {
                const item = media.find(m => m.id === id);
                return item ? item.url : match;
            });
        }
        editorRef.current.innerHTML = contentToSet;
    }
  }, [post?.id]); 

  // Modal Escape Listener
  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setModalImage(null);
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, []);

  // Image Selection Logic
  useEffect(() => {
    const editor = editorRef.current;
    if (!editor) return;

    const handleClick = (e: MouseEvent) => {
        const target = e.target as HTMLElement;
        if (target.tagName === 'IMG') {
             if (selectedImg !== target) {
                 setSelectedImg(target as HTMLImageElement);
                 setRefreshOverlay(prev => prev + 1);
             }
        } else {
             // If clicked outside image and not on a handle
             if (!target.closest('.resize-handle') && selectedImg) {
                 setSelectedImg(null);
             }
        }
    };

    const handleInput = () => {
        if (selectedImg) setSelectedImg(null);
    };

    editor.addEventListener('click', handleClick);
    editor.addEventListener('input', handleInput);

    return () => {
        editor.removeEventListener('click', handleClick);
        editor.removeEventListener('input', handleInput);
    };
  }, [selectedImg]);

  const getStats = () => {
     if (!editorRef.current) return { wordCount: 0, readTime: 0 };
     const text = editorRef.current.innerText || '';
     const wordCount = text.trim().split(/\s+/).filter(w => w.length > 0).length;
     const readTime = Math.ceil(wordCount / 200);
     return { wordCount, readTime };
  };
  const { wordCount, readTime } = getStats();

  const handleSave = (targetStatus: PostStatus) => {
    if (!editorRef.current) return;
    let htmlContent = editorRef.current.innerHTML;
    media.forEach(item => {
        if (item.url.length > 100) { 
             htmlContent = htmlContent.split(item.url).join(`asset://${item.id}`);
        }
    });
    const newPost: Post = {
      id: post?.id || crypto.randomUUID(),
      title,
      content: htmlContent, 
      excerpt,
      status: targetStatus,
      author: post?.author || 'Admin', 
      createdAt: post?.createdAt || Date.now(),
      updatedAt: Date.now(),
      tags,
      coverImage
    };
    onSave(newPost);
  };

  const handlePublish = () => handleSave(PostStatus.PUBLISHED);
  const handleSaveDraft = () => handleSave(PostStatus.DRAFT);

  const handleAddTag = (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' && tagInput.trim()) {
          e.preventDefault();
          if (!tags.includes(tagInput.trim())) {
              setTags([...tags, tagInput.trim()]);
          }
          setTagInput('');
      }
  };

  const removeTag = (tagToRemove: string) => {
      setTags(tags.filter(t => t !== tagToRemove));
  };

  const handleMediaUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        if (file.size > 5 * 1024 * 1024) {
            alert('File too large (Max 5MB)');
            return;
        }
        const reader = new FileReader();
        reader.onloadend = () => {
             const isVideo = file.type.startsWith('video/');
             const isAudio = file.type.startsWith('audio/');
             const newItem: MediaItem = {
                id: crypto.randomUUID(),
                url: reader.result as string,
                name: file.name,
                type: file.type,
                mediaType: isVideo ? 'video' : isAudio ? 'audio' : 'image',
                createdAt: Date.now(),
                size: file.size
            };
            onUploadMedia(newItem);
        };
        reader.readAsDataURL(file);
    }
  };

  const saveSelection = () => {
      const sel = window.getSelection();
      if (sel && sel.rangeCount > 0) {
          setSavedRange(sel.getRangeAt(0));
      }
  };

  const restoreSelection = () => {
      if (savedRange) {
          const sel = window.getSelection();
          if (sel) {
              sel.removeAllRanges();
              sel.addRange(savedRange);
          }
      }
  };

  const openMediaPicker = (target: 'content' | 'cover') => {
      if (target === 'content') {
          saveSelection();
      }
      setPickerTarget(target);
      setLinkMode('none');
      setCustomLinkUrl('');
      setShowMediaPicker(true);
  };

  const insertHtmlAtCursor = (html: string) => {
    editorRef.current?.focus();
    restoreSelection();
    document.execCommand('insertHTML', false, html);
    // After insertion, update saved range to end of insertion
    saveSelection();
  };

  const handleMediaSelect = (item: MediaItem) => {
      const isVideo = item.mediaType === 'video' || item.type.startsWith('video/');
      const isAudio = item.mediaType === 'audio' || item.type.startsWith('audio/');

      if (pickerTarget === 'cover') {
          if (isVideo || isAudio) {
              alert('Cannot use video/audio as cover image.');
              return;
          }
          setCoverImage(item.url);
      } else {
          let elementHtml = '';
          if (isVideo) {
            elementHtml = `<video src="${item.url}" controls style="width: 100%" class="my-6 max-w-full h-auto border border-gray-200 block" contenteditable="false" preload="metadata" ${VIDEO_ERROR_ATTR}></video>`;
          } else if (isAudio) {
             elementHtml = `<audio src="${item.url}" controls class="w-full my-6 border border-gray-200 block" contenteditable="false" preload="metadata"></audio>`;
          } else {
            // Default to 100% width on insertion, user can resize
            elementHtml = `<img src="${item.url}" alt="${item.name}" style="width: 100%" class="my-6 max-w-full border border-gray-200 block" contenteditable="false" />`;
          }
          if (linkMode !== 'none') {
             const href = linkMode === 'file' ? item.url : customLinkUrl;
             if (href) {
                 elementHtml = `<a href="${href}">${elementHtml}</a>`;
             }
          }
          insertHtmlAtCursor(elementHtml + '<p><br/></p>');
      }
      setShowMediaPicker(false);
  };

  const execCmd = (command: string, value: string | undefined = undefined) => {
      editorRef.current?.focus();
      document.execCommand(command, false, value);
  };

  const insertLink = () => {
      const url = prompt('Enter URL:');
      if (url) execCmd('createLink', url);
  };

  const insertVideoUrl = () => {
      saveSelection();
      const url = prompt('Enter Video URL (mp4, webm, ogg):');
      if (url) {
          const html = `<video src="${url}" controls class="w-full max-w-full h-auto my-6 border border-gray-200 block" contenteditable="false" ${VIDEO_ERROR_ATTR}></video><p><br/></p>`;
          insertHtmlAtCursor(html);
      }
  };

  const insertAudioUrl = () => {
      saveSelection();
      const url = prompt('Enter Audio URL (mp3, wav, ogg):');
      if (url) {
          const html = `<audio src="${url}" controls class="w-full my-6 border border-gray-200 block" contenteditable="false"></audio><p><br/></p>`;
          insertHtmlAtCursor(html);
      }
  };

  const insertYoutube = () => {
      saveSelection();
      const url = prompt('Enter YouTube URL:');
      if (url) {
          const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
          const match = url.match(regExp);
          if (match && match[2].length === 11) {
              const videoId = match[2];
              const html = `<div class="relative w-full aspect-video my-6 border border-gray-200 bg-gray-50" contenteditable="false"><iframe src="https://www.youtube.com/embed/${videoId}" class="absolute inset-0 w-full h-full" frameborder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" allowfullscreen></iframe></div><p><br/></p>`;
              insertHtmlAtCursor(html);
          } else {
              alert('Invalid YouTube URL');
          }
      }
  };

  const toggleMode = () => {
      if (editorMode === 'edit') {
          if (editorRef.current) {
              setPreviewContent(editorRef.current.innerHTML);
          }
          setEditorMode('preview');
          setSelectedImg(null); // Clear selection on mode switch
      } else {
          setEditorMode('edit');
      }
  };

  const focusEditor = (e: React.MouseEvent) => {
    // Check if the click was directly on the container, not on the input or toolbar
    if (e.target === e.currentTarget && editorRef.current) {
        editorRef.current.focus();
        // Move cursor to end of content
        const range = document.createRange();
        const sel = window.getSelection();
        range.selectNodeContents(editorRef.current);
        range.collapse(false);
        if (sel) {
            sel.removeAllRanges();
            sel.addRange(range);
        }
    }
  };

  // Preview Image Click Handler
  const handlePreviewImageClick = (e: React.MouseEvent) => {
      const target = e.target as HTMLElement;
      if (target.tagName === 'IMG') {
          setModalImage((target as HTMLImageElement).src);
      }
  };

  // Image Resizing Handler
  const handleResizeStart = (e: React.MouseEvent, direction: string) => {
    e.preventDefault();
    e.stopPropagation();

    if (!selectedImg || !editorRef.current) return;

    const startX = e.clientX;
    const startW = selectedImg.clientWidth;
    // Calculate aspect ratio
    const aspectRatio = selectedImg.naturalWidth / selectedImg.naturalHeight;

    const onMouseMove = (ev: MouseEvent) => {
        const deltaX = ev.clientX - startX;
        let newW = startW;

        // We only implement bottom-right corner for simplicity and consistency
        if (direction === 'se') {
            newW += deltaX;
        }

        // Limits
        if (newW < 50) newW = 50;
        const maxW = editorRef.current?.clientWidth || 800;
        if (newW > maxW) newW = maxW;

        selectedImg.style.width = `${newW}px`;
        selectedImg.style.height = 'auto'; // Maintain aspect ratio

        setRefreshOverlay(prev => prev + 1);
    };

    const onMouseUp = () => {
        window.removeEventListener('mousemove', onMouseMove);
        window.removeEventListener('mouseup', onMouseUp);
        editorRef.current?.focus(); // Return focus to editor
    };

    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onMouseUp);
  };

  // Render Resize Overlay
  const renderResizeOverlay = () => {
    if (!selectedImg || !editorRef.current) return null;

    // Use offsetTop/Left. Since editorRef is positioned relative (we will ensure this), these values are correct.
    const { offsetTop, offsetLeft, offsetWidth, offsetHeight } = selectedImg;

    return (
        <div 
            className="absolute border-2 border-black pointer-events-none z-10 transition-all duration-75"
            style={{
                top: offsetTop,
                left: offsetLeft,
                width: offsetWidth,
                height: offsetHeight
            }}
        >
            <div className="absolute top-2 right-2 bg-black text-white px-2 py-1 text-[10px] font-bold uppercase tracking-wider shadow-sm">
                {Math.round(offsetWidth)}px
            </div>
            {/* Bottom Right Handle */}
            <div 
               className="resize-handle absolute -right-1.5 -bottom-1.5 w-4 h-4 bg-white border-2 border-black cursor-se-resize pointer-events-auto hover:bg-black transition-colors"
               onMouseDown={(e) => handleResizeStart(e, 'se')}
            />
        </div>
    );
  };

  // Image Modal Component
  const ImageModal = () => (
    <div 
        className="fixed inset-0 z-[100] flex items-center justify-center bg-black/95 backdrop-blur-sm animate-in fade-in duration-200"
        onClick={() => setModalImage(null)}
    >
        <button 
            className="absolute top-8 right-8 text-white/50 hover:text-white transition-colors"
            onClick={() => setModalImage(null)}
        >
            <X size={32} />
        </button>
        <div className="max-w-[90vw] max-h-[90vh] relative p-4" onClick={(e) => e.stopPropagation()}>
            <img 
                src={modalImage || ''} 
                alt="Enlarged view" 
                className={`max-w-full max-h-[85vh] object-contain shadow-2xl rounded-sm border border-white/10`}
            />
            <div className="mt-4 flex items-center justify-between text-white/40 font-mono text-[10px] uppercase tracking-widest">
                <span>Preview Mode</span>
                <button 
                    onClick={() => window.open(modalImage || '', '_blank')}
                    className="hover:text-white flex items-center gap-2"
                >
                    <Maximize2 size={12} /> Full Resolution
                </button>
            </div>
        </div>
    </div>
  );

  // Inherited Styles
  const fontClass = settings.fontFamily === 'serif' ? 'font-serif' : settings.fontFamily === 'mono' ? 'font-mono' : 'font-sans';
  const widthClass = settings.contentWidth === 'compact' ? 'max-w-xl' : settings.contentWidth === 'relaxed' ? 'max-w-5xl' : 'max-w-3xl';

  return (
    <div className="flex h-full bg-white relative font-mono text-gray-900 overflow-hidden">
      {modalImage && <ImageModal />}

      {/* Media Picker Modal */}
      {showMediaPicker && (
          <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-8">
              <div className="bg-white w-full max-w-4xl h-[80vh] flex flex-col shadow-2xl animate-in fade-in zoom-in-95 duration-200">
                  <header className="p-6 border-b border-gray-100 flex items-center justify-between">
                      <div>
                          <h3 className="text-xl font-bold uppercase tracking-tight">Select Asset</h3>
                          <p className="text-xs text-gray-500 mt-1">
                              {pickerTarget === 'cover' ? 'Setting cover image' : 'Inserting into content'}
                          </p>
                      </div>
                      <div className="flex items-center gap-4">
                           {pickerTarget === 'content' && (
                                <div className="flex flex-col md:flex-row gap-2 md:gap-4 md:items-center mr-4">
                                    <div className="flex items-center gap-2 bg-gray-50 p-1 border border-gray-200 rounded">
                                        <span className="text-[10px] font-bold uppercase px-2 text-gray-500">Link:</span>
                                        <select 
                                            value={linkMode} 
                                            onChange={(e) => setLinkMode(e.target.value as any)}
                                            className="text-[10px] font-bold bg-transparent border-none focus:ring-0 cursor-pointer py-1"
                                        >
                                            <option value="none">None</option>
                                            <option value="file">Media File</option>
                                            <option value="custom">Custom URL</option>
                                        </select>
                                        {linkMode === 'custom' && (
                                            <input 
                                                type="text" 
                                                placeholder="https://" 
                                                className="text-[10px] border border-gray-300 rounded px-2 py-1 w-32 focus:border-black focus:outline-none"
                                                value={customLinkUrl}
                                                onChange={(e) => setCustomLinkUrl(e.target.value)}
                                            />
                                        )}
                                    </div>
                                </div>
                           )}
                          <div className="relative">
                                <input 
                                    type="file" 
                                    className="hidden" 
                                    id="modal-upload"
                                    accept="image/*,video/*,audio/*"
                                    onChange={handleMediaUpload}
                                />
                                <label 
                                    htmlFor="modal-upload" 
                                    className="cursor-pointer bg-black text-white px-4 py-2 text-xs font-bold uppercase tracking-wider hover:bg-gray-800 flex items-center gap-2"
                                >
                                    <Upload size={14} /> Upload New
                                </label>
                          </div>
                          <button onClick={() => setShowMediaPicker(false)} className="p-2 hover:bg-gray-100"><X size={20} /></button>
                      </div>
                  </header>
                  <div className="flex-1 overflow-y-auto p-6 bg-gray-50">
                      <div className="grid grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                          {media.map(item => {
                              const isVideo = item.mediaType === 'video' || item.type.startsWith('video/');
                              const isAudio = item.mediaType === 'audio' || item.type.startsWith('audio/');
                              return (
                                <button 
                                    key={item.id} 
                                    onClick={() => handleMediaSelect(item)}
                                    className="group relative aspect-square bg-white border border-gray-200 hover:border-black transition-colors focus:outline-none focus:ring-2 focus:ring-black focus:ring-offset-2 overflow-hidden"
                                    onMouseEnter={(e) => {
                                        if (isVideo) {
                                            const v = e.currentTarget.querySelector('video');
                                            if(v) v.play().catch(() => {});
                                        }
                                    }}
                                    onMouseLeave={(e) => {
                                        if (isVideo) {
                                            const v = e.currentTarget.querySelector('video');
                                            if(v) { v.pause(); v.currentTime = 0; }
                                        }
                                    }}
                                >
                                    {isVideo ? (
                                        <div className="w-full h-full relative flex items-center justify-center bg-gray-100">
                                            <video src={item.url} className="w-full h-full object-cover p-1 opacity-60" muted playsInline loop />
                                            <Film size={24} className="absolute text-black pointer-events-none" />
                                        </div>
                                    ) : isAudio ? (
                                        <div className="w-full h-full relative flex items-center justify-center bg-gray-100 text-gray-400">
                                            <Music size={24} />
                                            <div className="absolute bottom-2 right-2 text-[8px] font-bold text-gray-400 uppercase">AUDIO</div>
                                        </div>
                                    ) : (
                                        <img src={item.url} alt={item.name} className="w-full h-full object-cover p-1" />
                                    )}
                                    <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors" />
                                    <div className="absolute bottom-0 left-0 right-0 bg-white/90 p-1 text-[10px] truncate border-t border-gray-100">
                                        {item.name}
                                    </div>
                                </button>
                              );
                          })}
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Main Editor Area */}
      <div className={`flex-1 flex flex-col transition-all duration-300 ${isSidebarOpen && !isZenMode ? 'mr-80' : ''}`}>
        {/* Top Header */}
        <header className={`h-16 border-b border-gray-200 flex items-center justify-between px-6 bg-white z-20 transition-all duration-300 ${isZenMode ? '-mt-16 opacity-0 pointer-events-none' : ''}`}>
            <div className="flex items-center gap-4">
                <button onClick={onCancel} className="p-2 hover:bg-gray-100 text-gray-500 transition-colors">
                    <ArrowLeft size={16} />
                </button>
                <div className="flex flex-col">
                    <span className="text-sm font-bold text-gray-900 leading-none truncate max-w-[200px]">
                        {title || 'UNTITLED_ENTRY'}
                    </span>
                    <span className="text-[10px] text-gray-400 mt-1 uppercase tracking-widest font-bold">
                        {status === PostStatus.DRAFT ? 'Draft' : 'Live'} &bull; {wordCount} words
                    </span>
                </div>
            </div>

            <div className="flex items-center gap-3">
                 <button 
                    onClick={toggleMode} 
                    className="flex items-center gap-2 px-3 py-2 text-xs font-bold uppercase tracking-wider text-gray-500 border border-gray-200 hover:border-black hover:text-black transition-colors"
                >
                    {editorMode === 'edit' ? <Eye size={14} /> : <EyeOff size={14} />}
                    <span>{editorMode === 'edit' ? 'Preview' : 'Edit'}</span>
                </button>
                <div className="h-6 w-px bg-gray-200 mx-1"></div>
                <button 
                    onClick={handleSaveDraft} 
                    className="text-gray-500 hover:text-black px-4 py-2 text-xs font-bold uppercase tracking-wider hover:bg-gray-50"
                >
                    Save Draft
                </button>
                <button 
                    onClick={handlePublish} 
                    className="bg-black hover:bg-gray-800 text-white px-5 py-2 text-xs font-bold uppercase tracking-wider flex items-center gap-2 transition-transform active:scale-95"
                >
                    <Save size={14} />
                    {status === PostStatus.PUBLISHED ? 'Update' : 'Publish'}
                </button>
                <button 
                    onClick={() => setIsSidebarOpen(!isSidebarOpen)} 
                    className={`p-2 transition-colors border ${isSidebarOpen ? 'bg-gray-100 text-black border-gray-300' : 'text-gray-400 border-transparent hover:bg-gray-50 hover:text-black'}`}
                >
                    <MoreVertical size={18} />
                </button>
            </div>
        </header>

        {/* Toolbar - WYSIWYG */}
        {editorMode === 'edit' && (
            <div className={`px-6 py-2 border-b border-gray-100 bg-white flex items-center gap-1 sticky top-0 z-10 overflow-x-auto transition-all duration-300 ${isZenMode ? 'opacity-0 -translate-y-full absolute w-full' : ''}`}>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => execCmd('bold')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Bold"><Bold size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => execCmd('italic')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Italic"><Italic size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={insertLink} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Link"><LinkIcon size={16} /></button>
                <div className="w-px h-4 bg-gray-200 mx-3"></div>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => execCmd('formatBlock', 'H1')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Heading 1"><Heading1 size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => execCmd('formatBlock', 'H2')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Heading 2"><Heading2 size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => execCmd('formatBlock', 'BLOCKQUOTE')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Quote"><Quote size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => execCmd('insertUnorderedList')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="List"><List size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => execCmd('insertHorizontalRule')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Horizontal Rule"><Minus size={16} /></button>
                <div className="w-px h-4 bg-gray-200 mx-3"></div>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => openMediaPicker('content')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Insert Media"><ImageIcon size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={insertVideoUrl} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Embed Video from URL"><Film size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={insertAudioUrl} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Embed Audio from URL"><Music size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={insertYoutube} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Embed YouTube Video"><Youtube size={16} /></button>
                <div className="flex-1"></div>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => setIsZenMode(!isZenMode)} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Zen Mode">
                    {isZenMode ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
                </button>
            </div>
        )}

        {/* Editor Content Area */}
        <div className="flex-1 overflow-hidden bg-white relative flex flex-col">
            {isZenMode && editorMode === 'edit' && (
                <button 
                    onClick={() => setIsZenMode(false)}
                    className="absolute top-4 right-6 z-30 p-2 bg-gray-100 text-gray-500 hover:text-black hover:bg-gray-200 rounded-full opacity-50 hover:opacity-100 transition-opacity"
                    title="Exit Zen Mode"
                >
                    <Minimize2 size={16} />
                </button>
            )}
            <div className={`flex-1 h-full flex flex-col overflow-auto transition-all duration-500 ${isZenMode && editorMode === 'edit' ? 'py-16' : 'py-10'}`}>
                <div 
                    className={`${widthClass} mx-auto px-6 w-full min-h-full flex flex-col cursor-text pb-32 relative`}
                    onClick={editorMode === 'edit' ? focusEditor : undefined}
                >
                    {editorMode === 'edit' ? (
                        <>
                            <input 
                                type="text" 
                                placeholder="Untitled Entry" 
                                className="text-5xl md:text-6xl font-bold text-gray-900 placeholder-gray-300 border-none focus:ring-0 w-full bg-transparent p-0 mb-8 tracking-tighter font-serif leading-[0.9]"
                                value={title}
                                onChange={(e) => setTitle(e.target.value)}
                            />
                            {/* Resize Overlay */}
                            {renderResizeOverlay()}
                            <div
                                ref={editorRef}
                                contentEditable
                                onKeyUp={saveSelection}
                                onMouseUp={saveSelection}
                                className="flex-1 w-full outline-none prose prose-xl prose-stone max-w-none prose-headings:font-serif prose-p:text-gray-600 prose-p:font-serif prose-a:text-black hover:prose-a:decoration-black text-gray-800 leading-relaxed font-serif relative [&_img:hover]:ring-2 [&_img:hover]:ring-gray-300 [&_img:hover]:shadow-lg [&_img]:transition-all [&_img]:duration-200 [&_img]:cursor-pointer"
                                style={{ minHeight: '50vh' }}
                            />
                            {!isZenMode && (
                                <div className="mt-4 pt-4 border-t border-gray-100 text-[10px] text-gray-400 flex items-center justify-between font-mono uppercase tracking-widest">
                                    <div className="flex items-center gap-4"><span>WYSIWYG Mode</span></div>
                                    <span className="flex items-center gap-1"><Clock size={12} /> {readTime} min read</span>
                                </div>
                            )}
                        </>
                    ) : (
                         <div 
                            className={`prose prose-xl prose-stone max-w-none ${fontClass} text-gray-800 leading-relaxed py-10`}
                            onClick={handlePreviewImageClick}
                        >
                            <h1 className="text-5xl md:text-7xl font-bold text-gray-900 leading-[0.9] mb-8 tracking-tighter">{title || "Untitled Post"}</h1>
                            {coverImage && (
                                <img 
                                    src={coverImage} 
                                    alt="Cover" 
                                    className="w-full grayscale border border-gray-200 mb-12 p-1 cursor-zoom-in hover:scale-[1.01] transition-transform" 
                                    onClick={(e) => { e.stopPropagation(); setModalImage(coverImage); }}
                                />
                            )}
                            <div dangerouslySetInnerHTML={{ __html: processPreviewContent(previewContent) }} />
                        </div>
                    )}
                </div>
            </div>
        </div>
      </div>

      {/* Settings Sidebar */}
      <div className={`fixed right-0 top-0 bottom-0 w-80 bg-white border-l border-gray-200 shadow-2xl transform transition-transform duration-300 z-30 flex flex-col ${isSidebarOpen && !isZenMode ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="flex items-center justify-between p-5 border-b border-gray-200 bg-gray-50">
            <h3 className="font-bold text-xs text-gray-900 uppercase tracking-widest">Entry Meta</h3>
            <button onClick={() => setIsSidebarOpen(false)} className="text-gray-400 hover:text-black"><X size={18} /></button>
        </div>
        <div className="flex-1 overflow-y-auto p-6 space-y-8">
            <div>
                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Summary</label>
                <textarea 
                    className="w-full text-xs p-3 border border-gray-200 focus:border-black focus:ring-0 min-h-[100px] bg-gray-50"
                    placeholder="Brief summary for indexing..."
                    value={excerpt}
                    onChange={(e) => setExcerpt(e.target.value)}
                />
            </div>
            <div>
                 <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Featured Asset</label>
                 <div className="space-y-3">
                    <button onClick={() => openMediaPicker('cover')} className="w-full py-6 border border-dashed border-gray-300 hover:border-black text-gray-400 hover:text-black transition-colors flex flex-col items-center justify-center gap-2 bg-gray-50">
                        <FileImage size={16} /><span className="text-[10px] uppercase font-bold">Select from Library</span>
                    </button>
                    {coverImage && (
                        <div className="relative group">
                            <img src={coverImage} alt="Preview" className="w-full h-32 object-cover border border-gray-200 grayscale" />
                            <button onClick={() => setCoverImage('')} className="absolute top-2 right-2 bg-black text-white p-1 opacity-0 group-hover:opacity-100 transition-opacity"><X size={12} /></button>
                        </div>
                    )}
                 </div>
            </div>
            <div>
                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Tags</label>
                <div className="flex flex-wrap gap-2 mb-2">
                    {tags.map(tag => (
                        <span key={tag} className="bg-black text-white px-2 py-1 text-[10px] font-bold uppercase tracking-wider flex items-center gap-1">
                            {tag}<button onClick={() => removeTag(tag)} className="hover:text-gray-300 ml-1"><X size={10} /></button>
                        </span>
                    ))}
                </div>
                <input 
                    type="text" placeholder="Type + Enter"
                    className="w-full text-xs p-2 border border-gray-200 focus:border-black focus:ring-0"
                    value={tagInput}
                    onChange={(e) => setTagInput(e.target.value)}
                    onKeyDown={handleAddTag}
                />
            </div>
        </div>
      </div>
    </div>
  );
};

export default Editor;

import React, { useState, useEffect } from 'react';
import { Post, PostStatus, SiteSettings, MediaItem } from '../types';
import { format } from 'date-fns';
import { ArrowLeft, Edit, LayoutDashboard, Twitter, Github, X, Maximize2 } from 'lucide-react';

interface SitePreviewProps {
  posts: Post[];
  settings: SiteSettings;
  onBackToDashboard: () => void;
  onEditPost: (id: string) => void;
  media: MediaItem[];
}

const resolveContent = (htmlContent: string, media: MediaItem[], settings: SiteSettings) => {
    if (!htmlContent) return '';

    let html = htmlContent.replace(/asset:\/\/([a-zA-Z0-9-]+)/g, (match, id) => {
        const item = media.find(m => m.id === id);
        return item ? item.url : match;
    });

    const borderRadiusClass = settings.borderRadius === 'pill' ? 'rounded-2xl' : settings.borderRadius === 'subtle' ? 'rounded-md' : 'rounded-none';

    // Robust Image Class Injection
    html = html.replace(/<img([^>]*)>/g, (match, attrs) => {
        let newAttrs = attrs;
        const additionalClasses = `cursor-zoom-in transition-transform hover:scale-[1.01] ${borderRadiusClass}`;

        if (newAttrs.includes('class=')) {
            newAttrs = newAttrs.replace(/class=(["'])(.*?)\1/, (m, q, c) => `class=${q}${c} ${additionalClasses}${q}`);
        } else {
            newAttrs += ` class="max-w-full h-auto my-10 border border-gray-200 block ${additionalClasses}"`;
        }
        return `<img${newAttrs}>`;
    });

    // Robust Video Class Injection
    html = html.replace(/<video([^>]*)>/g, (match, attrs) => {
        let newAttrs = attrs;
        const additionalClasses = `w-full my-10 border border-gray-200 block ${borderRadiusClass}`;

        if (newAttrs.includes('class=')) {
             newAttrs = newAttrs.replace(/class=(["'])(.*?)\1/, (m, q, c) => `class=${q}${c} ${additionalClasses}${q}`);
        } else {
             newAttrs += ` class="${additionalClasses}"`;
        }
        return `<video${newAttrs}>`;
    });

    // Robust Audio Class Injection
    html = html.replace(/<audio([^>]*)>/g, (match, attrs) => {
        let newAttrs = attrs;
        const additionalClasses = `w-full my-10 border border-gray-200 block ${borderRadiusClass}`;

        if (newAttrs.includes('class=')) {
             newAttrs = newAttrs.replace(/class=(["'])(.*?)\1/, (m, q, c) => `class=${q}${c} ${additionalClasses}${q}`);
        } else {
             newAttrs += ` class="${additionalClasses}"`;
        }
        return `<audio${newAttrs}>`;
    });

    html = html.replace(/contenteditable="[^"]*"/g, '');

    return html;
};

