import React, { useRef, useState } from 'react';
import { MediaItem } from '../types';
import { Upload, Trash2, Copy, Image as ImageIcon, Film, Music } from 'lucide-react';
import { format } from 'date-fns';

interface MediaLibraryProps {
  media: MediaItem[];
  onUpload: (item: MediaItem) => void;
  onDelete: (id: string) => void;
}

const MediaLibrary: React.FC<MediaLibraryProps> = ({ media, onUpload, onDelete }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [copiedId, setCopiedId] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Increased limit to 5MB for small videos (LocalStorage constraint)
    if (file.size > 5 * 1024 * 1024) {
        alert("File too large. Max 5MB for local demo.");
        return;
    }

    setIsUploading(true);
    const reader = new FileReader();
    reader.onloadend = () => {
      const isVideo = file.type.startsWith('video/');
      const isAudio = file.type.startsWith('audio/');
      const newItem: MediaItem = {
        id: crypto.randomUUID(),
        url: reader.result as string,
        name: file.name,
        type: file.type,
        mediaType: isVideo ? 'video' : isAudio ? 'audio' : 'image',
        createdAt: Date.now(),
        size: file.size
      };
      onUpload(newItem);
      setIsUploading(false);
      // Reset input
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsDataURL(file);
  };

  const copyToClipboard = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const playVideo = (e: React.MouseEvent<HTMLDivElement>) => {
      const video = e.currentTarget.querySelector('video');
      if (video) {
          video.currentTime = 0;
          video.play().catch(() => {}); 
      }
  };

  const pauseVideo = (e: React.MouseEvent<HTMLDivElement>) => {
      const video = e.currentTarget.querySelector('video');
      if (video) {
          video.pause();
          video.currentTime = 0;
      }
  };

  return (
    <div className="p-8 max-w-7xl mx-auto h-full flex flex-col font-mono">
      <header className="mb-8 flex items-center justify-between">
        <div>
          <h2 className="text-xl font-bold text-black uppercase tracking-tight">Media Assets</h2>
          <p className="text-gray-500 mt-1 text-xs">Local storage asset management.</p>
        </div>
        <button 
          onClick={() => fileInputRef.current?.click()}
          disabled={isUploading}
          className="bg-black text-white px-4 py-2 flex items-center gap-2 text-xs font-bold uppercase tracking-wider hover:bg-gray-800 disabled:opacity-50"
        >
          <Upload size={14} />
          {isUploading ? 'Encoding...' : 'Upload Asset'}
        </button>
        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          accept="image/*,video/*,audio/*"
          onChange={handleFileChange} 
        />
      </header>

      {media.length === 0 ? (
        <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-gray-200 bg-gray-50 text-gray-400">
          <ImageIcon size={48} className="mb-4 opacity-20" />
          <p className="text-sm font-bold uppercase tracking-wide">No assets found</p>
          <p className="text-xs mt-2">Upload images, videos, or audio to use in your posts.</p>
        </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
          {media.map((item) => {
            const isVideo = item.mediaType === 'video' || item.type.startsWith('video/');
            const isAudio = item.mediaType === 'audio' || item.type.startsWith('audio/');

            return (
                <div key={item.id} className="group bg-white border border-gray-200 p-2 shadow-sm hover:shadow-md transition-shadow relative">
                <div 
                    className="aspect-square bg-gray-50 border border-gray-100 mb-3 overflow-hidden relative flex items-center justify-center cursor-pointer"
                    onMouseEnter={isVideo ? playVideo : undefined}
                    onMouseLeave={isVideo ? pauseVideo : undefined}
                >
                    {isVideo ? (
                        <div className="relative w-full h-full">
                                <video src={item.url} className="w-full h-full object-cover" muted playsInline loop />
                                <div className="absolute top-2 left-2 bg-black/70 text-white p-1 rounded-sm pointer-events-none transition-opacity duration-200 group-hover:opacity-0">
                                    <Film size={12} />
                                </div>
                        </div>
                    ) : isAudio ? (
                        <div className="relative w-full h-full flex items-center justify-center bg-gray-100 text-gray-400">
                            <Music size={32} />
                            <div className="absolute top-2 left-2 bg-black/70 text-white p-1 rounded-sm pointer-events-none">
                                <Music size={12} />
                            </div>
                             <audio src={item.url} className="absolute bottom-0 left-0 right-0 w-full h-8 opacity-0 group-hover:opacity-100 transition-opacity" controls />
                        </div>
                    ) : (
                        <img src={item.url} alt={item.name} className="w-full h-full object-cover" />
                    )}

                    <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2 z-10">
                        <button 
                            onClick={() => copyToClipboard(item.url, item.id)}
                            className="p-2 bg-white text-black hover:bg-gray-200"
                            title="Copy URL"
                        >
                            {copiedId === item.id ? <span className="text-[10px] font-bold">COPIED</span> : <Copy size={16} />}
                        </button>
                    </div>
                </div>
                <div className="flex items-start justify-between gap-2 px-1">
                    <div className="overflow-hidden">
                        <p className="text-xs font-bold text-gray-900 truncate" title={item.name}>{item.name}</p>
                        <p className="text-[10px] text-gray-400 mt-0.5 uppercase">{format(item.createdAt, 'MMM d')} &bull; {Math.round(item.size / 1024)}KB</p>
                    </div>
                    <button 
                        onClick={() => {
                            if(confirm('Delete asset?')) onDelete(item.id);
                        }}
                        className="text-gray-300 hover:text-red-600 transition-colors"
                    >
                        <Trash2 size={14} />
                    </button>
                </div>
                </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default MediaLibrary;

