import { Post, PostStatus, SiteSettings, MediaItem } from '../types';

const POSTS_KEY = 'zenpress_posts';
const SETTINGS_KEY = 'zenpress_settings';
const MEDIA_KEY = 'zenpress_media';

const DEFAULT_SETTINGS: SiteSettings = {
  title: 'ZenPress',
  description: 'A minimalist, monochrome CMS.',
  footerText: '© 2024 ZenPress Systems. All rights reserved.',
  language: 'en',
  postsPerPage: 10,
  homePageMode: 'list',
  showAuthor: true,
  showDate: true,
  fontFamily: 'serif',
  accentColor: 'black',
  borderRadius: 'none',
  contentWidth: 'standard',
  customCss: ''
};

const INITIAL_POSTS: Post[] = [
  {
    id: '1',
    title: 'System Architecture v1',
    excerpt: 'Initial thoughts on the minimalist design system.',
    content: `<h1>System Architecture</h1>
<p>We are prioritizing <b>function over form</b>. The interface is stripped back to the raw essentials.</p>
<h2>Core Directives</h2>
<ul>
<li>Monospace typography for high data density.</li>
<li>Grayscale palette to reduce cognitive load.</li>
<li>Instant content delivery.</li>
</ul>
<p>The system is operational.</p>`,
    status: PostStatus.PUBLISHED,
    author: 'Admin',
    createdAt: Date.now(),
    updatedAt: Date.now(),
    tags: ['system', 'design'],
    coverImage: 'https://picsum.photos/800/400?grayscale'
  }
];

export interface BackupData {
    posts: Post[];
    media: MediaItem[];
    settings: SiteSettings;
    timestamp: number;
    version: number;
}

export const StorageService = {
  getPosts: (): Post[] => {
    try {
      const stored = localStorage.getItem(POSTS_KEY);
      return stored ? JSON.parse(stored) : INITIAL_POSTS;
    } catch (e) {
      console.error("Failed to load posts", e);
      return [];
    }
  },

  savePost: (post: Post): void => {
    const posts = StorageService.getPosts();
    const existingIndex = posts.findIndex(p => p.id === post.id);

    if (existingIndex >= 0) {
      posts[existingIndex] = post;
    } else {
      posts.unshift(post);
    }

    localStorage.setItem(POSTS_KEY, JSON.stringify(posts));
  },

  deletePost: (id: string): void => {
    const posts = StorageService.getPosts().filter(p => p.id !== id);
    localStorage.setItem(POSTS_KEY, JSON.stringify(posts));
  },

  getPostById: (id: string): Post | undefined => {
    return StorageService.getPosts().find(p => p.id === id);
  },

  getSettings: (): SiteSettings => {
    try {
      const stored = localStorage.getItem(SETTINGS_KEY);
      if (!stored) return DEFAULT_SETTINGS;
      const parsed = JSON.parse(stored);
      // Merge with defaults to ensure new fields are populated
      return { ...DEFAULT_SETTINGS, ...parsed };
    } catch (e) {
      return DEFAULT_SETTINGS;
    }
  },

  saveSettings: (settings: SiteSettings): void => {
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  },

  getMedia: (): MediaItem[] => {
    try {
      const stored = localStorage.getItem(MEDIA_KEY);
      return stored ? JSON.parse(stored) : [];
    } catch (e) {
      return [];
    }
  },

  saveMedia: (mediaItem: MediaItem): void => {
    const media = StorageService.getMedia();
    media.unshift(mediaItem);
    if (media.length > 20) media.pop();
    try {
      localStorage.setItem(MEDIA_KEY, JSON.stringify(media));
    } catch (e) {
      alert("Storage quota exceeded. Delete some images.");
    }
  },

  deleteMedia: (id: string): void => {
    const media = StorageService.getMedia().filter(m => m.id !== id);
    localStorage.setItem(MEDIA_KEY, JSON.stringify(media));
  },

  getBackupData: (): BackupData => {
    return {
        posts: StorageService.getPosts(),
        media: StorageService.getMedia(),
        settings: StorageService.getSettings(),
        timestamp: Date.now(),
        version: 1
    };
  },

  restoreBackup: (data: BackupData): boolean => {
      try {
          if (!data || !Array.isArray(data.posts) || !data.settings) {
              return false;
          }
          localStorage.setItem(POSTS_KEY, JSON.stringify(data.posts));
          localStorage.setItem(MEDIA_KEY, JSON.stringify(data.media || []));
          localStorage.setItem(SETTINGS_KEY, JSON.stringify(data.settings));
          return true;
      } catch (e) {
          console.error("Restore failed", e);
          return false;
      }
  }
};

import React, { useState, useRef } from 'react';
import { SiteSettings } from '../types';
import { StorageService, BackupData } from '../services/storageService';
import { 
  Save, Upload, X, LayoutTemplate, User, Calendar, 
  Type, Palette, Maximize, Square, Circle, AlignLeft, Code,
  Download, Database, AlertTriangle
} from 'lucide-react';
import { format } from 'date-fns';

interface SettingsProps {
  settings: SiteSettings;
  onSave: (settings: SiteSettings) => void;
}

const Settings: React.FC<SettingsProps> = ({ settings, onSave }) => {
  const [formData, setFormData] = useState<SiteSettings>(settings);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);
  const [isDirty, setIsDirty] = useState(false);

  const handleChange = (field: keyof SiteSettings, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    setIsDirty(true);
  };

  const handleSave = () => {
    onSave(formData);
    setIsDirty(false);
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        handleChange('logoUrl', reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleExport = () => {
      const data = StorageService.getBackupData();
      const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `zenpress-backup-${format(Date.now(), 'yyyy-MM-dd-HHmm')}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      if (!window.confirm("WARNING: This will overwrite all current content, media, and settings. This action cannot be undone. Continue?")) {
          if (importInputRef.current) importInputRef.current.value = '';
          return;
      }

      const reader = new FileReader();
      reader.onload = (event) => {
          try {
              const json = JSON.parse(event.target?.result as string) as BackupData;
              const success = StorageService.restoreBackup(json);
              if (success) {
                  alert("System restored successfully. Reloading...");
                  window.location.reload();
              } else {
                  alert("Error: Invalid backup file format.");
              }
          } catch (err) {
              alert("Error parsing backup file.");
          }
      };
      reader.readAsText(file);
  };

  return (
    <div className="p-8 max-w-4xl mx-auto font-mono text-sm">
      <header className="mb-8 flex items-center justify-between">
        <div>
            <h2 className="text-xl font-bold text-black uppercase tracking-tight">System Configuration</h2>
            <p className="text-gray-500 mt-1 text-xs">Manage global parameters and visual DNA.</p>
        </div>
        {isDirty && (
            <button 
                onClick={handleSave}
                className="bg-black text-white px-4 py-2 flex items-center gap-2 text-xs font-bold uppercase tracking-wider hover:bg-gray-800 animate-in fade-in slide-in-from-right-2"
            >
                <Save size={14} /> Save Changes
            </button>
        )}
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="space-y-8">
            {/* General Identity */}
            <section className="bg-white border border-gray-200 p-6 shadow-sm">
                <h3 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-6 border-b border-gray-100 pb-2 flex items-center gap-2">
                    <Type size={12} /> Identity
                </h3>

                <div className="grid gap-6">
                    <div>
                        <label className="block text-[10px] font-bold text-gray-900 uppercase tracking-wider mb-2">Site Title</label>
                        <input 
                            type="text" 
                            value={formData.title} 
                            onChange={(e) => handleChange('title', e.target.value)}
                            className="w-full bg-gray-50 border border-gray-200 p-2.5 focus:border-black focus:outline-none transition-colors"
                        />
                    </div>

                    <div>
                        <label className="block text-[10px] font-bold text-gray-900 uppercase tracking-wider mb-2">Tagline</label>
                        <textarea 
                            value={formData.description} 
                            onChange={(e) => handleChange('description', e.target.value)}
                            className="w-full bg-gray-50 border border-gray-200 p-2.5 focus:border-black focus:outline-none transition-colors h-20 resize-none"
                        />
                    </div>
                </div>
            </section>

            {/* Design System: Typography & Color */}
            <section className="bg-white border border-gray-200 p-6 shadow-sm">
                 <h3 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-6 border-b border-gray-100 pb-2 flex items-center gap-2">
                    <Palette size={12} /> Visual Language
                </h3>

                <div className="space-y-6">
                    <div>
                        <label className="block text-[10px] font-bold text-gray-900 uppercase tracking-wider mb-3">Accent Theme</label>
                        <div className="flex gap-3">
                            {[
                                { id: 'black', class: 'bg-black' },
                                { id: 'zinc', class: 'bg-zinc-500' },
                                { id: 'blue', class: 'bg-blue-600' },
                                { id: 'red', class: 'bg-red-600' },
