            {/* Bottom Right Handle */}
            <div 
               className="resize-handle absolute -right-1.5 -bottom-1.5 w-4 h-4 bg-white border-2 border-black cursor-se-resize pointer-events-auto hover:bg-black transition-colors"
               onMouseDown={(e) => handleResizeStart(e, 'se')}
