                          </div>
                          <button onClick={() => setShowMediaPicker(false)} className="p-2 hover:bg-gray-100"><X size={20} /></button>
                      </div>
                  </header>
                  <div className="flex-1 overflow-y-auto p-6 bg-gray-50">
                      <div className="grid grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                          {media.map(item => {
                              const isVideo = item.mediaType === 'video' || item.type.startsWith('video/');
                              const isAudio = item.mediaType === 'audio' || item.type.startsWith('audio/');
                              return (
                                <button 
                                    key={item.id} 
                                    onClick={() => handleMediaSelect(item)}
                                    className="group relative aspect-square bg-white border border-gray-200 hover:border-black transition-colors focus:outline-none focus:ring-2 focus:ring-black focus:ring-offset-2 overflow-hidden"
                                    onMouseEnter={(e) => {
                                        if (isVideo) {
                                            const v = e.currentTarget.querySelector('video');
                                            if(v) v.play().catch(() => {});
                                        }
                                    }}
                                    onMouseLeave={(e) => {
                                        if (isVideo) {
                                            const v = e.currentTarget.querySelector('video');
                                            if(v) { v.pause(); v.currentTime = 0; }
                                        }
                                    }}
                                >
                                    {isVideo ? (
                                        <div className="w-full h-full relative flex items-center justify-center bg-gray-100">
                                            <video src={item.url} className="w-full h-full object-cover p-1 opacity-60" muted playsInline loop />
                                            <Film size={24} className="absolute text-black pointer-events-none" />
                                        </div>
                                    ) : isAudio ? (
                                        <div className="w-full h-full relative flex items-center justify-center bg-gray-100 text-gray-400">
                                            <Music size={24} />
                                            <div className="absolute bottom-2 right-2 text-[8px] font-bold text-gray-400 uppercase">AUDIO</div>
                                        </div>
                                    ) : (
                                        <img src={item.url} alt={item.name} className="w-full h-full object-cover p-1" />
                                    )}
                                    <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors" />
                                    <div className="absolute bottom-0 left-0 right-0 bg-white/90 p-1 text-[10px] truncate border-t border-gray-100">
                                        {item.name}
                                    </div>
                                </button>
                              );
                          })}
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Main Editor Area */}
      <div className={`flex-1 flex flex-col transition-all duration-300 ${isSidebarOpen && !isZenMode ? 'mr-80' : ''}`}>
        {/* Top Header */}
        <header className={`h-16 border-b border-gray-200 flex items-center justify-between px-6 bg-white z-20 transition-all duration-300 ${isZenMode ? '-mt-16 opacity-0 pointer-events-none' : ''}`}>
            <div className="flex items-center gap-4">
                <button onClick={onCancel} className="p-2 hover:bg-gray-100 text-gray-500 transition-colors">
                    <ArrowLeft size={16} />
                </button>
                <div className="flex flex-col">
                    <div className="flex items-center gap-2">
                        <span className="text-sm font-bold text-gray-900 leading-none truncate max-w-[200px]">
                            {title || 'UNTITLED_ENTRY'}
                        </span>
                        {/* Auto-Save Indicator */}
                        {isSaving ? (
                            <span className="text-[10px] text-gray-400 flex items-center gap-1">
                                <Loader2 size={10} className="animate-spin" /> Saving...
                            </span>
                        ) : lastAutoSave ? (
                            <span className="text-[10px] text-gray-400 flex items-center gap-1" title={format(lastAutoSave, 'HH:mm:ss')}>
                                <Check size={10} /> Saved
                            </span>
                        ) : null}
                    </div>
                    <span className="text-[10px] text-gray-400 mt-1 uppercase tracking-widest font-bold">
                        {status === PostStatus.DRAFT ? 'Draft' : 'Live'} &bull; {type} &bull; {wordCount} words
                    </span>
                </div>
            </div>

            <div className="flex items-center gap-3">
                 <button 
                    onClick={toggleMode} 
                    className="flex items-center gap-2 px-3 py-2 text-xs font-bold uppercase tracking-wider text-gray-500 border border-gray-200 hover:border-black hover:text-black transition-colors"
                >
                    {editorMode === 'edit' ? <Eye size={14} /> : <EyeOff size={14} />}
                    <span>{editorMode === 'edit' ? 'Preview' : 'Edit'}</span>
                </button>
                <div className="h-6 w-px bg-gray-200 mx-1"></div>
                <button 
                    onClick={handleSaveDraft} 
                    className="text-gray-500 hover:text-black px-4 py-2 text-xs font-bold uppercase tracking-wider hover:bg-gray-50"
                >
                    Save Draft
                </button>
                <button 
                    onClick={handlePublish} 
                    className="bg-black hover:bg-gray-800 text-white px-5 py-2 text-xs font-bold uppercase tracking-wider flex items-center gap-2 transition-transform active:scale-95"
                >
                    <Save size={14} />
                    {status === PostStatus.PUBLISHED ? 'Update' : 'Publish'}
                </button>
                <button 
                    onClick={() => setIsSidebarOpen(!isSidebarOpen)} 
                    className={`p-2 transition-colors border ${isSidebarOpen ? 'bg-gray-100 text-black border-gray-300' : 'text-gray-400 border-transparent hover:bg-gray-50 hover:text-black'}`}
                >
                    <MoreVertical size={18} />
                </button>
            </div>
        </header>

        {/* Toolbar - WYSIWYG */}
        {editorMode === 'edit' && (
            <div className={`px-6 py-2 border-b border-gray-100 bg-white flex items-center gap-1 sticky top-0 z-10 overflow-x-auto transition-all duration-300 ${isZenMode ? 'opacity-0 -translate-y-full absolute w-full' : ''}`}>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => execCmd('bold')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Bold"><Bold size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => execCmd('italic')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Italic"><Italic size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={insertLink} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Link"><LinkIcon size={16} /></button>
                <div className="w-px h-4 bg-gray-200 mx-3"></div>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => execCmd('formatBlock', 'H1')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Heading 1"><Heading1 size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => execCmd('formatBlock', 'H2')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Heading 2"><Heading2 size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => execCmd('formatBlock', 'BLOCKQUOTE')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Quote"><Quote size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => execCmd('insertUnorderedList')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="List"><List size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => execCmd('insertHorizontalRule')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Horizontal Rule"><Minus size={16} /></button>
                <div className="w-px h-4 bg-gray-200 mx-3"></div>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => openMediaPicker('content')} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Insert Media"><ImageIcon size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={insertVideoUrl} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Embed Video from URL"><Film size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={insertAudioUrl} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Embed Audio from URL"><Music size={16} /></button>
                <button onMouseDown={(e) => e.preventDefault()} onClick={insertVideoEmbed} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Embed Video (YouTube/Vimeo)"><Youtube size={16} /></button>
                <div className="flex-1"></div>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => setIsZenMode(!isZenMode)} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Zen Mode">
                    {isZenMode ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
                </button>
            </div>
        )}

        {/* Editor Content Area */}
        <div className="flex-1 overflow-hidden bg-white relative flex flex-col">
            {isZenMode && editorMode === 'edit' && (
                <button 
                    onClick={() => setIsZenMode(false)}
                    className="absolute top-4 right-6 z-30 p-2 bg-gray-100 text-gray-500 hover:text-black hover:bg-gray-200 rounded-full opacity-50 hover:opacity-100 transition-opacity"
                    title="Exit Zen Mode"
                >
                    <Minimize2 size={16} />
                </button>
            )}
            <div className={`flex-1 h-full flex flex-col overflow-auto transition-all duration-500 ${isZenMode && editorMode === 'edit' ? 'py-16' : 'py-10'}`}>
                <div 
                    className={`${widthClass} mx-auto px-6 w-full min-h-full flex flex-col cursor-text pb-32 relative`}
                    onClick={editorMode === 'edit' ? focusEditor : undefined}
                >
                    {editorMode === 'edit' ? (
                        <>
                            <input 
                                type="text" 
                                placeholder="Untitled Entry" 
                                className="text-5xl md:text-6xl font-bold text-gray-900 placeholder-gray-300 border-none focus:ring-0 w-full bg-transparent p-0 mb-8 tracking-tighter leading-[0.9]"
                                style={{ fontFamily: settings.fontFamily }}
                                value={title}
                                onChange={(e) => setTitle(e.target.value)}
                            />
                            {/* Resize Overlay */}
                            {renderResizeOverlay()}
                            <div
                                ref={editorRef}
                                contentEditable
                                onKeyUp={saveSelection}
                                onMouseUp={saveSelection}
                                onPaste={handlePaste}
                                onInput={triggerAutoSave}
                                className="flex-1 w-full outline-none prose prose-xl prose-stone max-w-none prose-headings:font-bold prose-p:text-gray-600 prose-a:text-black hover:prose-a:decoration-black text-gray-800 leading-relaxed relative [&_img:hover]:ring-2 [&_img:hover]:ring-gray-300 [&_img:hover]:shadow-lg [&_img]:transition-all [&_img]:duration-200 [&_img]:cursor-pointer"
                                style={{ minHeight: '50vh', fontFamily: settings.fontFamily }}
                            />
                            {!isZenMode && (
                                <div className="mt-4 pt-4 border-t border-gray-100 text-[10px] text-gray-400 flex items-center justify-between font-mono uppercase tracking-widest">
                                    <div className="flex items-center gap-4"><span>WYSIWYG Mode</span></div>
                                    <span className="flex items-center gap-1"><Clock size={12} /> {readTime} min read</span>
                                </div>
                            )}
                        </>
                    ) : (
                         <div 
                            className={`prose prose-xl prose-stone max-w-none text-gray-800 leading-relaxed py-10`}
                            style={{ fontFamily: settings.fontFamily }}
                            onClick={handlePreviewImageClick}
                        >
                            <h1 className="text-5xl md:text-7xl font-bold text-gray-900 leading-[0.9] mb-8 tracking-tighter">{title || "Untitled Post"}</h1>
                            {coverImage && (
                                <img 
                                    src={coverImage} 
                                    alt="Cover" 
                                    className="w-full grayscale border border-gray-200 mb-12 p-1 cursor-zoom-in hover:scale-[1.01] transition-transform" 
                                    onClick={(e) => { e.stopPropagation(); setModalImage(coverImage); }}
                                />
                            )}
                            <div dangerouslySetInnerHTML={{ __html: processPreviewContent(previewContent, settings.fontFamily) }} />
                        </div>
                    )}
                </div>
            </div>
        </div>
      </div>

      {/* Settings Sidebar */}
      <div className={`fixed right-0 top-0 bottom-0 w-80 bg-white border-l border-gray-200 shadow-2xl transform transition-transform duration-300 z-30 flex flex-col ${isSidebarOpen && !isZenMode ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="flex items-center justify-between p-5 border-b border-gray-200 bg-gray-50">
            <h3 className="font-bold text-xs text-gray-900 uppercase tracking-widest">Entry Meta</h3>
            <button onClick={() => setIsSidebarOpen(false)} className="text-gray-400 hover:text-black"><X size={18} /></button>
        </div>
        <div className="flex-1 overflow-y-auto p-6 space-y-8">
            <div>
                 <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Entry Type</label>
                 <div className="flex bg-gray-100 p-1 rounded">
                     <button 
                        onClick={() => setType('post')}
                        className={`flex-1 flex items-center justify-center gap-2 py-2 text-[10px] font-bold uppercase tracking-wider rounded transition-colors ${type === 'post' ? 'bg-white shadow text-black' : 'text-gray-400 hover:text-gray-600'}`}
                     >
                         <FileText size={12} /> Post
                     </button>
                     <button 
                        onClick={() => setType('page')}
                        className={`flex-1 flex items-center justify-center gap-2 py-2 text-[10px] font-bold uppercase tracking-wider rounded transition-colors ${type === 'page' ? 'bg-white shadow text-black' : 'text-gray-400 hover:text-gray-600'}`}
                     >
                         <Layout size={12} /> Page
                     </button>
                 </div>
            </div>

            <div>
                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Summary</label>
                <textarea 
                    className="w-full text-xs p-3 border border-gray-200 focus:border-black focus:ring-0 min-h-[100px] bg-gray-50"
                    placeholder="Brief summary for indexing..."
                    value={excerpt}
                    onChange={(e) => setExcerpt(e.target.value)}
                />
            </div>
            <div>
                 <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Featured Asset</label>
                 <div className="space-y-3">
                    <button onClick={() => openMediaPicker('cover')} className="w-full py-6 border border-dashed border-gray-300 hover:border-black text-gray-400 hover:text-black transition-colors flex flex-col items-center justify-center gap-2 bg-gray-50">
                        <FileImage size={16} /><span className="text-[10px] uppercase font-bold">Select from Library</span>
                    </button>
                    {coverImage && (
                        <div className="relative group">
                            <img src={coverImage} alt="Preview" className="w-full h-32 object-cover border border-gray-200 grayscale" />
                            <button onClick={() => setCoverImage('')} className="absolute top-2 right-2 bg-black text-white p-1 opacity-0 group-hover:opacity-100 transition-opacity"><X size={12} /></button>
                        </div>
                    )}
                 </div>
            </div>
            <div>
                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Tags</label>
                <div className="flex flex-wrap gap-2 mb-2">
                    {tags.map(tag => (
                        <span key={tag} className="bg-black text-white px-2 py-1 text-[10px] font-bold uppercase tracking-wider flex items-center gap-1">
                            {tag}<button onClick={() => removeTag(tag)} className="hover:text-gray-300 ml-1"><X size={10} /></button>
                        </span>
                    ))}
                </div>
                <input 
                    type="text" placeholder="Type + Enter"
                    className="w-full text-xs p-2 border border-gray-200 focus:border-black focus:ring-0"
                    value={tagInput}
                    onChange={(e) => setTagInput(e.target.value)}
                    onKeyDown={handleAddTag}
                />
            </div>
        </div>
      </div>
    </div>
  );
};

export default Editor;

import React, { useState, useRef } from 'react';
import { SiteSettings, MenuItem } from '../types';
import { StorageService, BackupData } from '../services/storageService';
import { 
  Save, Upload, X, LayoutTemplate, User, Calendar, 
  Type, Palette, Maximize, Square, Circle, AlignLeft, Code,
  Download, Database, AlertTriangle, Menu, Plus, Trash2, Link as LinkIcon
} from 'lucide-react';
import { format } from 'date-fns';

interface SettingsProps {
  settings: SiteSettings;
  onSave: (settings: SiteSettings) => void;
}

const FONTS = [
    { name: 'Merriweather', type: 'Serif' },
    { name: 'Playfair Display', type: 'Serif' },
    { name: 'Lora', type: 'Serif' },
    { name: 'Inter', type: 'Sans' },
    { name: 'Roboto', type: 'Sans' },
    { name: 'JetBrains Mono', type: 'Mono' },
    { name: 'IBM Plex Mono', type: 'Mono' },
    { name: 'Space Mono', type: 'Mono' },
];

const Settings: React.FC<SettingsProps> = ({ settings, onSave }) => {
  const [formData, setFormData] = useState<SiteSettings>(settings);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);
  const [isDirty, setIsDirty] = useState(false);

  // Menu State
  const [newMenuLabel, setNewMenuLabel] = useState('');
  const [newMenuUrl, setNewMenuUrl] = useState('');

  const handleChange = (field: keyof SiteSettings, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    setIsDirty(true);
  };

  const handleSave = () => {
    onSave(formData);
    setIsDirty(false);
  };

  const handleExport = () => {
      const data = StorageService.getBackupData();
      const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `zenpress-backup-${format(Date.now(), 'yyyy-MM-dd-HHmm')}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      if (!window.confirm("WARNING: This will overwrite all current content, media, and settings. This action cannot be undone. Continue?")) {
          if (importInputRef.current) importInputRef.current.value = '';
          return;
      }

      const reader = new FileReader();
      reader.onload = (event) => {
          try {
              const json = JSON.parse(event.target?.result as string) as BackupData;
              const success = StorageService.restoreBackup(json);
              if (success) {
                  alert("System restored successfully. Reloading...");
                  window.location.reload();
              } else {
                  alert("Error: Invalid backup file format.");
              }
          } catch (err) {
              alert("Error parsing backup file.");
          }
      };
      reader.readAsText(file);
  };

  const addMenuItem = () => {
      if (!newMenuLabel || !newMenuUrl) return;
      const newItem: MenuItem = {
          id: crypto.randomUUID(),
          label: newMenuLabel,
          url: newMenuUrl
      };
      handleChange('navigation', [...(formData.navigation || []), newItem]);
      setNewMenuLabel('');
      setNewMenuUrl('');
  };

  const removeMenuItem = (id: string) => {
      handleChange('navigation', (formData.navigation || []).filter(item => item.id !== id));
  };

  return (
    <div className="p-8 max-w-4xl mx-auto font-mono text-sm">
      <header className="mb-8 flex items-center justify-between">
        <div>
            <h2 className="text-xl font-bold text-black uppercase tracking-tight">System Configuration</h2>
            <p className="text-gray-500 mt-1 text-xs">Manage global parameters and visual DNA.</p>
        </div>
        {isDirty && (
            <button 
                onClick={handleSave}
                className="bg-black text-white px-4 py-2 flex items-center gap-2 text-xs font-bold uppercase tracking-wider hover:bg-gray-800 animate-in fade-in slide-in-from-right-2"
            >
                <Save size={14} /> Save Changes
            </button>
        )}
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="space-y-8">
            {/* General Identity */}
            <section className="bg-white border border-gray-200 p-6 shadow-sm">
                <h3 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-6 border-b border-gray-100 pb-2 flex items-center gap-2">
                    <Type size={12} /> Identity
                </h3>

                <div className="grid gap-6">
                    <div>
                        <label className="block text-[10px] font-bold text-gray-900 uppercase tracking-wider mb-2">Site Title</label>
                        <input 
                            type="text" 
                            value={formData.title} 
                            onChange={(e) => handleChange('title', e.target.value)}
                            className="w-full bg-gray-50 border border-gray-200 p-2.5 focus:border-black focus:outline-none transition-colors"
                        />
                    </div>

                    <div>
                        <label className="block text-[10px] font-bold text-gray-900 uppercase tracking-wider mb-2">Tagline</label>
                        <textarea 
                            value={formData.description} 
                            onChange={(e) => handleChange('description', e.target.value)}
                            className="w-full bg-gray-50 border border-gray-200 p-2.5 focus:border-black focus:outline-none transition-colors h-20 resize-none"
                        />
                    </div>
                </div>
            </section>

             {/* Navigation Builder */}
             <section className="bg-white border border-gray-200 p-6 shadow-sm">
                <h3 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-6 border-b border-gray-100 pb-2 flex items-center gap-2">
                    <Menu size={12} /> Navigation
                </h3>

                <div className="space-y-4">
                    <ul className="space-y-2">
                        {(formData.navigation || []).map((item) => (
                            <li key={item.id} className="flex items-center gap-2 bg-gray-50 p-2 border border-gray-200">
                                <span className="font-bold text-xs flex-1">{item.label}</span>
                                <span className="text-[10px] text-gray-500 font-mono truncate max-w-[120px]">{item.url}</span>
                                <button onClick={() => removeMenuItem(item.id)} className="text-gray-400 hover:text-red-500">
                                    <Trash2 size={14} />
                                </button>
                            </li>
                        ))}
                    </ul>

                    <div className="flex gap-2 items-end pt-2 border-t border-gray-100">
                        <div className="flex-1">
                             <input 
                                type="text" 
                                placeholder="Label (e.g. About)" 
                                className="w-full text-xs p-2 border border-gray-200 mb-1"
                                value={newMenuLabel}
                                onChange={(e) => setNewMenuLabel(e.target.value)}
                             />
                             <input 
                                type="text" 
                                placeholder="URL (e.g. /about)" 
                                className="w-full text-xs p-2 border border-gray-200"
                                value={newMenuUrl}
                                onChange={(e) => setNewMenuUrl(e.target.value)}
                             />
                        </div>
                        <button 
                            onClick={addMenuItem}
                            disabled={!newMenuLabel || !newMenuUrl}
                            className="bg-black text-white p-2 h-full flex items-center justify-center disabled:opacity-50"
                        >
                            <Plus size={16} />
                        </button>
                    </div>
                </div>
            </section>

            {/* Design System: Typography & Color */}
            <section className="bg-white border border-gray-200 p-6 shadow-sm">
                 <h3 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-6 border-b border-gray-100 pb-2 flex items-center gap-2">
                    <Palette size={12} /> Visual Language
                </h3>

                <div className="space-y-6">
                    <div>
                        <label className="block text-[10px] font-bold text-gray-900 uppercase tracking-wider mb-3">Accent Theme</label>
                        <div className="flex gap-3">
                            {[
                                { id: 'black', class: 'bg-black' },
                                { id: 'zinc', class: 'bg-zinc-500' },
                                { id: 'blue', class: 'bg-blue-600' },
                                { id: 'red', class: 'bg-red-600' },
                                { id: 'green', class: 'bg-emerald-700' }
                            ].map(color => (
                                <button
                                    key={color.id}
                                    onClick={() => handleChange('accentColor', color.id)}
                                    className={`w-10 h-10 border-2 transition-all ${color.class} ${formData.accentColor === color.id ? 'border-gray-900 ring-2 ring-gray-200 scale-110 ring-offset-2' : 'border-transparent hover:scale-105'}`}
                                    title={color.id}
                                />
                            ))}
                        </div>
                    </div>

                    <div>
                        <label className="block text-[10px] font-bold text-gray-900 uppercase tracking-wider mb-3">Primary Typeface</label>
                        <select 
