                             {post.coverImage && (
                                <div className="mb-12 cursor-zoom-in" onClick={() => setModalImage(post.coverImage || null)}>
                                    <img src={post.coverImage} alt={post.title} className={`w-full h-auto grayscale ${borderRadiusClass}`} />
