import { Post, PostStatus, SiteSettings, MediaItem } from '../types';

const POSTS_KEY = 'zenpress_posts';
const SETTINGS_KEY = 'zenpress_settings';
const MEDIA_KEY = 'zenpress_media';

const DEFAULT_SETTINGS: SiteSettings = {
  title: 'ZenPress',
