    { id: 'black', class: 'bg-black' },
    { id: 'zinc', class: 'bg-zinc-500' },
    { id: 'blue', class: 'bg-blue-600' },
    { id: 'red', class: 'bg-red-600' },
    { id: 'green', class: 'bg-emerald-700' },
    { id: 'orange', class: 'bg-orange-600' },
    { id: 'purple', class: 'bg-purple-600' },
