    { id: 'yellow', class: 'bg-yellow-500' },
    { id: 'teal', class: 'bg-teal-600' },
];

const Settings: React.FC<SettingsProps> = ({ settings, onSave }) => {
  const [formData, setFormData] = useState<SiteSettings>(settings);
  const importInputRef = useRef<HTMLInputElement>(null);
  const [isDirty, setIsDirty] = useState(false);

  // Media Picker State
  const [showMediaPicker, setShowMediaPicker] = useState(false);
  const [mediaItems, setMediaItems] = useState<MediaItem[]>(StorageService.getMedia());

  // Menu State
  const [newMenuLabel, setNewMenuLabel] = useState('');
  const [newMenuUrl, setNewMenuUrl] = useState('');

  const handleChange = (field: keyof SiteSettings, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    setIsDirty(true);
  };

  const handleSave = () => {
    onSave(formData);
    setIsDirty(false);
  };

  const handleExport = () => {
      const data = StorageService.getBackupData();
      const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `zenpress-backup-${format(Date.now(), 'yyyy-MM-dd-HHmm')}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      if (!window.confirm("WARNING: This will overwrite all current content, media, and settings. This action cannot be undone. Continue?")) {
          if (importInputRef.current) importInputRef.current.value = '';
          return;
      }

      const reader = new FileReader();
      reader.onload = (event) => {
          try {
              const json = JSON.parse(event.target?.result as string) as BackupData;
              const success = StorageService.restoreBackup(json);
              if (success) {
                  alert("System restored successfully. Reloading...");
                  window.location.reload();
              } else {
                  alert("Error: Invalid backup file format. Missing required data fields.");
              }
          } catch (err) {
              console.error(err);
              alert("Error parsing backup file. Please ensure it is a valid JSON file.");
          } finally {
              if (importInputRef.current) importInputRef.current.value = '';
          }
      };
      reader.readAsText(file);
  };

  const addMenuItem = () => {
      if (!newMenuLabel || !newMenuUrl) return;
      const newItem: MenuItem = {
          id: crypto.randomUUID(),
          label: newMenuLabel,
          url: newMenuUrl
      };
      handleChange('navigation', [...(formData.navigation || []), newItem]);
      setNewMenuLabel('');
      setNewMenuUrl('');
  };

  const removeMenuItem = (id: string) => {
      handleChange('navigation', (formData.navigation || []).filter(item => item.id !== id));
  };

  const handleSelectLogo = (url: string) => {
      handleChange('logoUrl', url);
      setShowMediaPicker(false);
  };

  return (
    <div className="p-8 max-w-4xl mx-auto font-mono text-sm relative">
       {/* Media Picker Modal for Logo */}
