import React, { useRef, useState, useEffect } from 'react';
import { Save, X, RotateCw, Crop, Sliders, Check, Undo } from 'lucide-react';

interface ImageEditorProps {
  file: File;
  onSave: (processedFile: File) => void;
  onCancel: () => void;
}

const ImageEditor: React.FC<ImageEditorProps> = ({ file, onSave, onCancel }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [imageSrc, setImageSrc] = useState<string | null>(null);
  const [rotation, setRotation] = useState(0); // 0, 90, 180, 270
  const [brightness, setBrightness] = useState(100);
  const [contrast, setContrast] = useState(100);
  const [isSquare, setIsSquare] = useState(false);
  const [originalImage, setOriginalImage] = useState<HTMLImageElement | null>(null);

  useEffect(() => {
    const reader = new FileReader();
    reader.onload = (e) => {
      if (e.target?.result) {
        const img = new Image();
        img.onload = () => {
          setOriginalImage(img);
          setImageSrc(img.src);
        };
        img.src = e.target.result as string;
      }
    };
    reader.readAsDataURL(file);
  }, [file]);

  useEffect(() => {
    if (!originalImage || !canvasRef.current) return;
    drawCanvas();
  }, [originalImage, rotation, brightness, contrast, isSquare]);

  const drawCanvas = () => {
    if (!originalImage || !canvasRef.current) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Determine output dimensions
    let w = originalImage.naturalWidth;
    let h = originalImage.naturalHeight;

    // If rotating 90 or 270, swap dims
    if (rotation % 180 !== 0) {
      [w, h] = [h, w];
    }

    // Apply Crop
    let sx = 0, sy = 0, sw = originalImage.naturalWidth, sh = originalImage.naturalHeight;

    if (isSquare) {
      const minDim = Math.min(w, h);
      // We need to calculate the crop on the *rotated* result conceptually, 
      // but simpler to calculate crop on source relative to orientation
      // For simplicity in this lightweight editor, we center crop the source based on the shortest side
      const shortestOriginal = Math.min(originalImage.naturalWidth, originalImage.naturalHeight);
      sx = (originalImage.naturalWidth - shortestOriginal) / 2;
      sy = (originalImage.naturalHeight - shortestOriginal) / 2;
      sw = shortestOriginal;
      sh = shortestOriginal;
      w = shortestOriginal;
      h = shortestOriginal;
    }

    canvas.width = w;
    canvas.height = h;

    // Filters
    ctx.filter = `brightness(${brightness}%) contrast(${contrast}%)`;

    // Transforms
    ctx.translate(w / 2, h / 2);
    ctx.rotate((rotation * Math.PI) / 180);

    // Draw
    // If not square, we draw normal centered
    // If square, we draw the cropped region centered
    if (isSquare) {
         // Rotate logic complicates source cropping coordinates.
         // Strategy: Rotate context, then draw image centered.
         // If square, we effectively just change the canvas bounds and draw center of image.
         // But we need to handle the crop rect relative to source image rotation.

         // Simplified Square Crop: Just center the image in the square canvas
         // Note: True source-cropping with rotation is complex. 
         // We will perform rotation first, then draw.

         // Reset transform for a moment to clear logic? No.
         // With square crop, we set canvas to Square.
         // We draw image centered.
         if (rotation % 180 !== 0) {
             ctx.drawImage(originalImage, -originalImage.naturalHeight / 2, -originalImage.naturalWidth / 2);
         } else {
             ctx.drawImage(originalImage, -originalImage.naturalWidth / 2, -originalImage.naturalHeight / 2);
         }
    } else {
        // Standard draw logic for full image
        if (rotation % 180 !== 0) {
             ctx.drawImage(originalImage, -originalImage.naturalHeight / 2, -originalImage.naturalWidth / 2);
        } else {
             ctx.drawImage(originalImage, -originalImage.naturalWidth / 2, -originalImage.naturalHeight / 2);
        }
    }
  };

  const handleSave = () => {
    if (!canvasRef.current) return;
    canvasRef.current.toBlob((blob) => {
        if (blob) {
            const newFile = new File([blob], file.name, { type: 'image/jpeg' });
            onSave(newFile);
        }
    }, 'image/jpeg', 0.95);
  };

  return (
    <div className="fixed inset-0 z-[60] bg-black/95 flex flex-col animate-in fade-in duration-200">
        {/* Header */}
        <div className="h-16 border-b border-white/10 flex items-center justify-between px-6 bg-gray-900">
             <h3 className="text-white font-bold uppercase tracking-widest text-sm flex items-center gap-2">
                 <Sliders size={16} /> Image Editor
             </h3>
             <div className="flex items-center gap-4">
                 <button onClick={onCancel} className="text-gray-400 hover:text-white px-3 py-1 uppercase text-xs font-bold tracking-wider">Cancel</button>
                 <button 
                    onClick={handleSave} 
                    className="bg-white text-black px-4 py-2 text-xs font-bold uppercase tracking-wider hover:bg-gray-200 flex items-center gap-2"
                >
                     <Save size={14} /> Save Asset
                 </button>
             </div>
        </div>

        {/* Workspace */}
        <div className="flex-1 flex overflow-hidden">
            {/* Canvas Area */}
            <div className="flex-1 bg-black flex items-center justify-center p-8 overflow-auto relative">
                 <canvas 
                    ref={canvasRef} 
                    className="max-w-full max-h-full shadow-2xl border border-white/20"
                    style={{ backgroundImage: 'radial-gradient(#333 1px, transparent 1px)', backgroundSize: '20px 20px' }} 
                 />
            </div>

            {/* Sidebar Controls */}
            <div className="w-80 bg-gray-900 border-l border-white/10 p-6 flex flex-col gap-8 overflow-y-auto">

                 {/* Transformations */}
                 <div>
                     <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-4 block">Geometry</label>
                     <div className="grid grid-cols-2 gap-2">
                         <button 
                            onClick={() => setRotation(r => (r + 90) % 360)}
                            className="bg-gray-800 text-white p-3 flex flex-col items-center gap-2 hover:bg-gray-700 transition-colors border border-transparent hover:border-gray-600"
                        >
                             <RotateCw size={18} />
                             <span className="text-[10px] font-bold uppercase">Rotate</span>
                         </button>
                         <button 
                            onClick={() => setIsSquare(!isSquare)}
                            className={`p-3 flex flex-col items-center gap-2 transition-all border ${isSquare ? 'bg-white text-black border-white' : 'bg-gray-800 text-white border-transparent hover:bg-gray-700'}`}
                        >
                             <Crop size={18} />
                             <span className="text-[10px] font-bold uppercase">Square Crop</span>
                         </button>
                     </div>
                 </div>

                 {/* Adjustments */}
                 <div>
                     <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-4 block">Adjustments</label>

                     <div className="space-y-6">
                         <div>
                             <div className="flex justify-between mb-2">
                                <span className="text-xs text-gray-300">Brightness</span>
                                <span className="text-xs font-mono text-gray-500">{brightness}%</span>
                             </div>
                             <input 
                                type="range" min="50" max="150" value={brightness} 
                                onChange={(e) => setBrightness(Number(e.target.value))}
                                className="w-full accent-white h-1 bg-gray-700 rounded-lg appearance-none cursor-pointer"
                             />
                         </div>

                         <div>
                             <div className="flex justify-between mb-2">
                                <span className="text-xs text-gray-300">Contrast</span>
                                <span className="text-xs font-mono text-gray-500">{contrast}%</span>
                             </div>
                             <input 
                                type="range" min="50" max="150" value={contrast} 
                                onChange={(e) => setContrast(Number(e.target.value))}
                                className="w-full accent-white h-1 bg-gray-700 rounded-lg appearance-none cursor-pointer"
                             />
                         </div>
                     </div>
                 </div>

                 <div className="mt-auto pt-6 border-t border-white/10">
                     <button 
                        onClick={() => { setRotation(0); setBrightness(100); setContrast(100); setIsSquare(false); }}
                        className="w-full py-3 flex items-center justify-center gap-2 text-gray-400 hover:text-white uppercase text-xs font-bold tracking-widest"
                     >
                         <Undo size={14} /> Reset All
                     </button>
                 </div>
            </div>
        </div>
    </div>
  );
};

