import React, { useRef, useState, useEffect } from 'react';
import { Save, X, RotateCw, Crop, Sliders, Check, Undo, Image as ImageIcon, BoxSelect } from 'lucide-react';

interface ImageEditorProps {
  file: File;
  onSave: (processedFile: File) => void;
  onCancel: () => void;
}

type AspectRatio = 'free' | 1 | 1.7777 | 1.3333 | 1.5 | 0.8; // Free, 1:1, 16:9, 4:3, 3:2, 4:5

const ASPECT_RATIOS: { label: string; value: AspectRatio }[] = [
    { label: 'Original', value: 'free' },
    { label: 'Square (1:1)', value: 1 },
    { label: 'Wide (16:9)', value: 1.7777 },
    { label: 'Standard (4:3)', value: 1.3333 },
    { label: 'Classic (3:2)', value: 1.5 },
    { label: 'Portrait (4:5)', value: 0.8 },
];

const ImageEditor: React.FC<ImageEditorProps> = ({ file, onSave, onCancel }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [rotation, setRotation] = useState(0); // 0, 90, 180, 270
  const [brightness, setBrightness] = useState(100);
  const [contrast, setContrast] = useState(100);
  const [saturation, setSaturation] = useState(100);
  const [grayscale, setGrayscale] = useState(false);
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('free');
  const [originalImage, setOriginalImage] = useState<HTMLImageElement | null>(null);

  useEffect(() => {
    const reader = new FileReader();
    reader.onload = (e) => {
      if (e.target?.result) {
        const img = new Image();
        img.onload = () => {
          setOriginalImage(img);
        };
        img.src = e.target.result as string;
      }
    };
    reader.readAsDataURL(file);
  }, [file]);

  useEffect(() => {
    if (!originalImage || !canvasRef.current) return;
    drawCanvas();
  }, [originalImage, rotation, brightness, contrast, saturation, grayscale, aspectRatio]);

  const drawCanvas = () => {
    if (!originalImage || !canvasRef.current) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // 1. Determine dimensions of the rotated image
    let rotatedW = originalImage.naturalWidth;
    let rotatedH = originalImage.naturalHeight;

    // If rotating 90 or 270, dimensions swap relative to the screen
    if (rotation % 180 !== 0) {
      [rotatedW, rotatedH] = [rotatedH, rotatedW];
    }

    // 2. Determine Crop Dimensions based on Aspect Ratio
    let cropW = rotatedW;
    let cropH = rotatedH;

    if (aspectRatio !== 'free') {
        const targetRatio = aspectRatio as number;
        const currentRatio = rotatedW / rotatedH;

        if (currentRatio > targetRatio) {
            // Image is wider than target -> Crop Width
            cropH = rotatedH;
            cropW = rotatedH * targetRatio;
        } else {
            // Image is taller than target -> Crop Height
            cropW = rotatedW;
            cropH = rotatedW / targetRatio;
        }
    }

    // 3. Set Canvas Size to Crop Size
    canvas.width = cropW;
    canvas.height = cropH;

    // 4. Apply Filters
    const filterString = [
        `brightness(${brightness}%)`,
        `contrast(${contrast}%)`,
        `saturate(${saturation}%)`,
        grayscale ? 'grayscale(100%)' : ''
    ].filter(Boolean).join(' ');

    ctx.filter = filterString;

    // 5. Draw
    // Move origin to center of canvas (which is center of crop)
    ctx.translate(cropW / 2, cropH / 2);

    // Apply Rotation
    ctx.rotate((rotation * Math.PI) / 180);

    // Draw Image centered
    // Note: drawImage uses the *original* unrotated image.
    // We simply draw it centered at the current origin.
    // Since we are center cropping, the center of the crop is the center of the image.
    ctx.drawImage(
        originalImage, 
        -originalImage.naturalWidth / 2, 
        -originalImage.naturalHeight / 2
    );
  };

  const handleSave = () => {
    if (!canvasRef.current) return;
    canvasRef.current.toBlob((blob) => {
        if (blob) {
            const newFile = new File([blob], file.name, { type: 'image/jpeg' });
            onSave(newFile);
        }
    }, 'image/jpeg', 0.95);
  };

  const resetAll = () => {
      setRotation(0);
      setBrightness(100);
      setContrast(100);
      setSaturation(100);
      setGrayscale(false);
      setAspectRatio('free');
  };

  return (
    <div className="fixed inset-0 z-[60] bg-black/95 flex flex-col animate-in fade-in duration-200">
        {/* Header */}
        <div className="h-16 border-b border-white/10 flex items-center justify-between px-6 bg-gray-900">
             <h3 className="text-white font-bold uppercase tracking-widest text-sm flex items-center gap-2">
                 <Sliders size={16} /> Image Editor
             </h3>
             <div className="flex items-center gap-4">
                 <button onClick={onCancel} className="text-gray-400 hover:text-white px-3 py-1 uppercase text-xs font-bold tracking-wider">Cancel</button>
                 <button 
                    onClick={handleSave} 
                    className="bg-white text-black px-4 py-2 text-xs font-bold uppercase tracking-wider hover:bg-gray-200 flex items-center gap-2"
                >
                     <Save size={14} /> Save Asset
                 </button>
             </div>
        </div>

        {/* Workspace */}
        <div className="flex-1 flex overflow-hidden">
            {/* Canvas Area */}
            <div className="flex-1 bg-black flex items-center justify-center p-8 overflow-auto relative">
                 <canvas 
                    ref={canvasRef} 
                    className="max-w-full max-h-full shadow-2xl border border-white/20"
                    style={{ backgroundImage: 'radial-gradient(#333 1px, transparent 1px)', backgroundSize: '20px 20px' }} 
                 />
            </div>

            {/* Sidebar Controls */}
            <div className="w-80 bg-gray-900 border-l border-white/10 p-6 flex flex-col gap-8 overflow-y-auto">

                 {/* Transformations */}
                 <div>
                     <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-4 block flex items-center gap-2">
                        <Crop size={12} /> Geometry
                     </label>
                     <div className="space-y-4">
                         <button 
                            onClick={() => setRotation(r => (r + 90) % 360)}
                            className="w-full bg-gray-800 text-white p-3 flex items-center justify-center gap-2 hover:bg-gray-700 transition-colors border border-transparent hover:border-gray-600"
                        >
                             <RotateCw size={16} />
                             <span className="text-[10px] font-bold uppercase">Rotate 90°</span>
                         </button>

                         <div className="grid grid-cols-2 gap-2">
                             {ASPECT_RATIOS.map(ratio => (
                                 <button
                                    key={String(ratio.value)}
                                    onClick={() => setAspectRatio(ratio.value)}
                                    className={`p-2 text-[10px] font-bold uppercase border transition-colors ${aspectRatio === ratio.value ? 'bg-white text-black border-white' : 'bg-transparent text-gray-400 border-gray-700 hover:border-gray-500'}`}
                                 >
                                     {ratio.label}
                                 </button>
                             ))}
                         </div>
                     </div>
                 </div>

                 {/* Adjustments */}
                 <div>
                     <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-4 block flex items-center gap-2">
                        <Sliders size={12} /> Adjustments
                     </label>

                     <div className="space-y-6">
                         <div>
                             <div className="flex justify-between mb-2">
                                <span className="text-xs text-gray-300">Brightness</span>
                                <span className="text-xs font-mono text-gray-500">{brightness}%</span>
                             </div>
                             <input 
                                type="range" min="0" max="200" value={brightness} 
                                onChange={(e) => setBrightness(Number(e.target.value))}
                                className="w-full accent-white h-1 bg-gray-700 rounded-lg appearance-none cursor-pointer"
                             />
                         </div>

                         <div>
                             <div className="flex justify-between mb-2">
                                <span className="text-xs text-gray-300">Contrast</span>
                                <span className="text-xs font-mono text-gray-500">{contrast}%</span>
