const VIDEO_FALLBACK_HTML = `<div class="w-full my-8 aspect-video bg-gray-50 border border-gray-200 flex flex-col items-center justify-center text-gray-500 font-mono relative overflow-hidden group"><div class="absolute inset-0 bg-[linear-gradient(45deg,transparent_25%,rgba(0,0,0,0.02)_50%,transparent_75%,transparent_100%)] bg-[length:20px_20px]"></div><svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" class="mb-3 text-gray-400"><rect width="18" height="18" x="3" y="3" rx="2" ry="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/><line x1="3" x2="21" y1="3" y2="21" /></svg><p class="text-xs font-bold uppercase tracking-widest text-gray-600 z-10">Video Signal Lost</p><p class="text-[10px] text-gray-400 mt-1 z-10">Unable to load media source</p></div>`;

const VIDEO_ERROR_ATTR = `onerror='this.outerHTML=\`${VIDEO_FALLBACK_HTML}\`'`;

const legacyMarkdownToHtml = (text: string, media: MediaItem[]) => {
    let html = text
        .replace(/^# (.*$)/gim, '<h1>$1</h1>')
        .replace(/^## (.*$)/gim, '<h2>$1</h2>')
        .replace(/^### (.*$)/gim, '<h3>$1</h3>')
        .replace(/^\> (.*$)/gim, '<blockquote>$1</blockquote>')
        .replace(/\*\*(.*)\*\*/gim, '<b>$1</b>')
        .replace(/\*(.*)\*/gim, '<i>$1</i>')
        .replace(/!\[(.*?)\]\((.*?\.(mp4|webm|ogg|mov))\)/gim, `<video src='$2' controls class='max-w-full h-auto my-6 border border-gray-200 block' contenteditable='false' ${VIDEO_ERROR_ATTR}></video>`)
        .replace(/!\[(.*?)\]\((.*?)\)/gim, "<img alt='$1' src='$2' contenteditable='false' />")
        .replace(/\[(.*?)\]\((.*?)\)/gim, "<a href='$2'>$1</a>")
        .replace(/^\- (.*$)/gim, '<ul><li>$1</li></ul>')
        .replace(/\n/gim, '<br />');

    html = html.replace(/asset:\/\/([a-zA-Z0-9-]+)/g, (match, id) => {
        const item = media.find(m => m.id === id);
        return item ? item.url : match;
    });

    return html;
};

const processPreviewContent = (html: string, fontFamily: string) => {
    let processed = html;

    // Enhance Videos
    processed = processed.replace(/<video(.*?)>/g, (match, attributes) => {
        let newAttrs = attributes;
        if (!newAttrs.includes('onerror=')) {
            newAttrs = `${VIDEO_ERROR_ATTR} ${newAttrs}`;
        }
        if (!newAttrs.includes('controls')) {
            newAttrs += ' controls';
        }
        const responsiveClasses = "max-w-full h-auto w-full my-6 border border-gray-200 block";
        if (!newAttrs.includes('class=')) {
            newAttrs += ` class="${responsiveClasses}"`;
        } else {
             newAttrs = newAttrs.replace(/class=(["'])(.*?)\1/, (m, q, c) => `class=${q}${c} ${responsiveClasses}${q}`);
        }
        return `<video${newAttrs}>`;
    });
    const videoUrlRegex = /(?<!src=["'])(?<!src=)(https?:\/\/[^\s<"]+\.(mp4|webm|ogg|mov))/g;
    processed = processed.replace(videoUrlRegex, `<video ${VIDEO_ERROR_ATTR} src="$1" controls class="w-full max-w-full h-auto my-6 border border-gray-200 block"></video>`);

    // Enhance Audio
    processed = processed.replace(/<audio(.*?)>/g, (match, attributes) => {
        let newAttrs = attributes;
        if (!newAttrs.includes('controls')) {
            newAttrs += ' controls';
        }
        const responsiveClasses = "w-full my-6 border border-gray-200 block";
        if (!newAttrs.includes('class=')) {
            newAttrs += ` class="${responsiveClasses}"`;
        } else {
             newAttrs = newAttrs.replace(/class=(["'])(.*?)\1/, (m, q, c) => `class=${q}${c} ${responsiveClasses}${q}`);
        }
        return `<audio${newAttrs}>`;
    });

    // Enhance Images
    processed = processed.replace(/<img([^>]*)>/g, (match, attrs) => {
        if (attrs.includes('data-gallery="true"')) {
            return `<img${attrs}>`;
        }
        let newAttrs = attrs;
        const additionalClasses = `cursor-zoom-in transition-transform hover:scale-[1.01]`;
        if (newAttrs.includes('class=')) {
            newAttrs = newAttrs.replace(/class=(["'])(.*?)\1/, (m, q, c) => `class=${q}${c} ${additionalClasses}${q}`);
        } else {
            newAttrs += ` class="max-w-full h-auto my-6 border border-gray-200 block ${additionalClasses}"`;
        }
        return `<img${newAttrs}>`;
    });

    return processed;
};

const Editor: React.FC<EditorProps> = ({ post, media, onSave, onCancel, onUploadMedia }) => {
  const settings = StorageService.getSettings();
  const [postId] = useState(post?.id || crypto.randomUUID());

  const [title, setTitle] = useState(post?.title || '');
  const [status, setStatus] = useState<PostStatus>(post?.status || PostStatus.DRAFT);
  const [type, setType] = useState<PostType>(post?.type || 'post');
  const [tags, setTags] = useState<string[]>(post?.tags || []);
  const [coverImage, setCoverImage] = useState(post?.coverImage || '');
  const [excerpt, setExcerpt] = useState(post?.excerpt || '');

  const [editorMode, setEditorMode] = useState<'edit' | 'preview'>('edit');
  const [previewContent, setPreviewContent] = useState('');

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isZenMode, setIsZenMode] = useState(false);

  const [showMediaPicker, setShowMediaPicker] = useState(false);
  const [pickerTarget, setPickerTarget] = useState<'content' | 'cover'>('content');
  const [linkMode, setLinkMode] = useState<'none' | 'file' | 'custom'>('none');
  const [customLinkUrl, setCustomLinkUrl] = useState('');
  const [savedRange, setSavedRange] = useState<Range | null>(null);

  const [selectedMediaIds, setSelectedMediaIds] = useState<Set<string>>(new Set());
  const [tagInput, setTagInput] = useState('');

  const [isSaving, setIsSaving] = useState(false);
  const [lastAutoSave, setLastAutoSave] = useState<number | null>(null);
  const autoSaveTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Selection State
  const [selectedElement, setSelectedElement] = useState<HTMLElement | null>(null);
  const [refreshOverlay, setRefreshOverlay] = useState(0);

  const [modalImage, setModalImage] = useState<string | null>(null);
  const [fileToEdit, setFileToEdit] = useState<File | null>(null);
  const editorUploadInputRef = useRef<HTMLInputElement>(null);

  // Toolbar State
  const [showColorPicker, setShowColorPicker] = useState(false);
  const [showSizePicker, setShowSizePicker] = useState(false);
  const [isDraggingMedia, setIsDraggingMedia] = useState(false);

  const editorRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (editorRef.current) {
        const initialContent = post?.content || '';
        const isHtml = initialContent.trim().startsWith('<');
        let contentToSet = initialContent;
        if (!isHtml) {
            contentToSet = legacyMarkdownToHtml(initialContent, media);
        } else {
            contentToSet = contentToSet.replace(/asset:\/\/([a-zA-Z0-9-]+)/g, (match, id) => {
                const item = media.find(m => m.id === id);
                return item ? item.url : match;
            });
        }
        editorRef.current.innerHTML = contentToSet;
    }
  }, [post?.id]); 

  // Modal Escape Listener
  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setModalImage(null);
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, []);

  // Selection Logic for IMG and VIDEO
  useEffect(() => {
    const editor = editorRef.current;
    if (!editor) return;

    const handleClick = (e: MouseEvent) => {
        const target = e.target as HTMLElement;
        const isImage = target.tagName === 'IMG';
        const isVideo = target.tagName === 'VIDEO';

        // Don't deselect if clicking inside the media toolbar or on handles
        if (target.closest('.media-toolbar') || target.closest('.resize-handle')) return;

        if (isImage || isVideo) {
             if (selectedElement !== target) {
                 setSelectedElement(target);
                 setRefreshOverlay(prev => prev + 1);
             }
        } else {
             if (selectedElement) {
                 setSelectedElement(null);
             }
        }
    };

    const handleInput = () => {
        // Deselect on typing
        if (selectedElement) setSelectedElement(null);
    };

    editor.addEventListener('click', handleClick);
    editor.addEventListener('input', handleInput);

    return () => {
        editor.removeEventListener('click', handleClick);
        editor.removeEventListener('input', handleInput);
    };
  }, [selectedElement]);

  const getStats = () => {
     if (!editorRef.current) return { wordCount: 0, readTime: 0 };
     const text = editorRef.current.innerText || '';
     const wordCount = text.trim().split(/\s+/).filter(w => w.length > 0).length;
     const readTime = Math.ceil(wordCount / 200);
     return { wordCount, readTime };
  };
  const { wordCount, readTime } = getStats();

  const getPostData = useCallback((targetStatus: PostStatus): Post | null => {
      if (!editorRef.current) return null;
      let htmlContent = editorRef.current.innerHTML;
      media.forEach(item => {
          if (item.url.length > 100) { 
               htmlContent = htmlContent.split(item.url).join(`asset://${item.id}`);
          }
      });
      return {
        id: postId,
        title,
        content: htmlContent, 
        excerpt,
        status: targetStatus,
        type,
        author: post?.author || 'Admin', 
        createdAt: post?.createdAt || Date.now(),
        updatedAt: Date.now(),
        tags,
        coverImage
      };
  }, [postId, title, excerpt, status, type, tags, coverImage, post?.author, post?.createdAt, media]);

  const handleSave = (targetStatus: PostStatus) => {
    const newPost = getPostData(targetStatus);
    if (newPost) onSave(newPost, true);
  };

  const triggerAutoSave = useCallback(() => {
      if (status !== PostStatus.DRAFT) return;

      if (autoSaveTimeoutRef.current) clearTimeout(autoSaveTimeoutRef.current);
      setIsSaving(true);

      autoSaveTimeoutRef.current = setTimeout(() => {
          const newPost = getPostData(PostStatus.DRAFT);
          if (newPost) {
              onSave(newPost, false);
              setLastAutoSave(Date.now());
              setIsSaving(false);
          }
      }, 2000);
  }, [status, getPostData, onSave]);

  const handlePublish = () => handleSave(PostStatus.PUBLISHED);
  const handleSaveDraft = () => handleSave(PostStatus.DRAFT);

  const handleAddTag = (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' && tagInput.trim()) {
          e.preventDefault();
          if (!tags.includes(tagInput.trim())) {
              const newTags = [...tags, tagInput.trim()];
              setTags(newTags);
          }
          setTagInput('');
      }
  };

  const removeTag = (tagToRemove: string) => {
      setTags(tags.filter(t => t !== tagToRemove));
  };

  useEffect(() => {
      if (Date.now() - (post?.updatedAt || 0) < 1000 && !title) return;
      triggerAutoSave();
  }, [title, excerpt, tags, coverImage, type, triggerAutoSave]);

  const handleMediaUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        if (file.size > 5 * 1024 * 1024) {
            alert('File too large (Max 5MB)');
            return;
        }
        if (file.type.startsWith('image/')) {
            setFileToEdit(file);
            if (editorUploadInputRef.current) editorUploadInputRef.current.value = '';
        } else {
            processMediaUpload(file);
        }
    }
  };

  const processMediaUpload = (file: File) => {
      const reader = new FileReader();
      reader.onloadend = () => {
           const isVideo = file.type.startsWith('video/');
           const isAudio = file.type.startsWith('audio/');
           const newItem: MediaItem = {
              id: crypto.randomUUID(),
              url: reader.result as string,
              name: file.name,
              type: file.type,
              mediaType: isVideo ? 'video' : isAudio ? 'audio' : 'image',
              createdAt: Date.now(),
              size: file.size
          };
          onUploadMedia(newItem);
          if (editorUploadInputRef.current) editorUploadInputRef.current.value = '';
      };
      reader.readAsDataURL(file);
  };

  const handleEditorSave = (editedFile: File) => {
      setFileToEdit(null);
      processMediaUpload(editedFile);
  };

  const saveSelection = () => {
      const sel = window.getSelection();
      if (sel && sel.rangeCount > 0) {
          setSavedRange(sel.getRangeAt(0));
      }
  };

  const restoreSelection = () => {
      if (savedRange) {
          const sel = window.getSelection();
          if (sel) {
              sel.removeAllRanges();
              sel.addRange(savedRange);
          }
      }
  };

  const openMediaPicker = (target: 'content' | 'cover') => {
      if (target === 'content') {
          saveSelection();
      }
      setPickerTarget(target);
      setLinkMode('none');
      setCustomLinkUrl('');
      setSelectedMediaIds(new Set());
      setShowMediaPicker(true);
  };

  const insertHtmlAtCursor = (html: string) => {
    editorRef.current?.focus();
    restoreSelection();
    document.execCommand('insertHTML', false, html);
    saveSelection();
    triggerAutoSave();
  };

  const handleMediaItemClick = (item: MediaItem) => {
      if (pickerTarget === 'cover') {
          handleMediaSelect(item);
          return;
      }
      const newSet = new Set(selectedMediaIds);
      if (newSet.has(item.id)) {
          newSet.delete(item.id);
      } else {
          newSet.add(item.id);
      }
      setSelectedMediaIds(newSet);
  };

  const insertSelectedMedia = () => {
      if (selectedMediaIds.size === 0) return;
      if (selectedMediaIds.size === 1) {
          const itemId = Array.from(selectedMediaIds)[0];
          const item = media.find(m => m.id === itemId);
          if (item) handleMediaSelect(item);
      } else {
          const items = media.filter(m => selectedMediaIds.has(m.id));
          handleGalleryInsert(items);
      }
      setShowMediaPicker(false);
  };

  const handleGalleryInsert = (items: MediaItem[]) => {
      const images = items.filter(i => i.mediaType === 'image' || i.type.startsWith('image/'));
      if (images.length === 0) return;
      const gridClass = images.length === 2 ? 'grid-cols-2' : 'grid-cols-2 md:grid-cols-3';
      const galleryHtml = `
        <div class="gallery-container grid ${gridClass} gap-4 my-8" contenteditable="false">
            ${images.map(img => `
                <div class="aspect-square bg-gray-50 overflow-hidden relative border border-gray-100">
                    <img src="${img.url}" alt="${img.name}" class="w-full h-full object-cover" data-gallery="true" />
                </div>
            `).join('')}
        </div><p><br/></p>
      `;
      insertHtmlAtCursor(galleryHtml);
  };

  const handleMediaSelect = (item: MediaItem) => {
      const isVideo = item.mediaType === 'video' || item.type.startsWith('video/');
      const isAudio = item.mediaType === 'audio' || item.type.startsWith('audio/');

      if (pickerTarget === 'cover') {
          if (isVideo || isAudio) {
              alert('Cannot use video/audio as cover image.');
              return;
          }
          setCoverImage(item.url);
      } else {
          let elementHtml = '';
          if (isVideo) {
            elementHtml = `<video src="${item.url}" controls class="my-6 max-w-full h-auto border border-gray-200 block" contenteditable="false" preload="metadata" ${VIDEO_ERROR_ATTR}></video>`;
          } else if (isAudio) {
             elementHtml = `<audio src="${item.url}" controls class="w-full my-6 border border-gray-200 block" contenteditable="false" preload="metadata"></audio>`;
          } else {
            elementHtml = `<img src="${item.url}" alt="${item.name}" class="my-6 max-w-full border border-gray-200 block" contenteditable="false" />`;
          }
          if (linkMode !== 'none') {
             const href = linkMode === 'file' ? item.url : customLinkUrl;
             if (href) {
                 elementHtml = `<a href="${href}">${elementHtml}</a>`;
             }
          }
          insertHtmlAtCursor(elementHtml + '<p><br/></p>');
      }
      setShowMediaPicker(false);
  };

  const getVideoEmbedHtml = (url: string) => {
      let embedUrl = '';
      const ytMatch = url.match(/^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/);
      if (ytMatch && ytMatch[2].length === 11) {
          embedUrl = `https://www.youtube.com/embed/${ytMatch[2]}`;
      }
      if (!embedUrl) {
          const vimeoMatch = url.match(/vimeo\.com\/(?:channels\/(?:\w+\/)?|groups\/(?:[^\/]*)\/videos\/|album\/(?:\d+)\/video\/|video\/|)(\d+)(?:$|\/|\?)/);
          if (vimeoMatch && vimeoMatch[1]) {
              embedUrl = `https://player.vimeo.com/video/${vimeoMatch[1]}`;
          }
      }
      if (embedUrl) {
           return `<div class="relative w-full aspect-video my-6 border border-gray-200 bg-gray-50" contenteditable="false"><iframe src="${embedUrl}" class="absolute inset-0 w-full h-full" frameborder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" allowfullscreen></iframe></div><p><br/></p>`;
      }
      return null;
  };

  const insertFormat = (command: string, value: string | undefined = undefined) => {
      editorRef.current?.focus();
      if (command === 'youtube') {
          saveSelection();
          const url = prompt('Enter YouTube Video URL:');
          if (url) {
              const html = getVideoEmbedHtml(url);
              if (html) {
                  insertHtmlAtCursor(html);
              } else {
                  alert('Invalid Video URL');
              }
          }
          return;
      }
      document.execCommand(command, false, value);
      triggerAutoSave();
  };

  const insertLink = () => {
      const url = prompt('Enter URL:');
      if (url) insertFormat('createLink', url);
  };

  const handlePaste = (e: React.ClipboardEvent) => {
      const text = e.clipboardData.getData('text/plain');
      if (text) {
          const html = getVideoEmbedHtml(text.trim());
          if (html) {
              e.preventDefault();
              if (!savedRange) {
                   document.execCommand('insertHTML', false, html);
              } else {
                   insertHtmlAtCursor(html);
              }
          }
      }
      triggerAutoSave();
  };

  const toggleMode = () => {
      if (editorMode === 'edit') {
          if (editorRef.current) {
              setPreviewContent(editorRef.current.innerHTML);
          }
          setEditorMode('preview');
          setSelectedElement(null);
      } else {
          setEditorMode('edit');
      }
  };

  const focusEditor = (e: React.MouseEvent) => {
    if (e.target === e.currentTarget && editorRef.current) {
        editorRef.current.focus();
        const range = document.createRange();
        const sel = window.getSelection();
        range.selectNodeContents(editorRef.current);
        range.collapse(false);
        if (sel) {
            sel.removeAllRanges();
            sel.addRange(range);
        }
    }
  };

  const handlePreviewImageClick = (e: React.MouseEvent) => {
      const target = e.target as HTMLElement;
      if (target.tagName === 'IMG') {
          setModalImage((target as HTMLImageElement).src);
      }
  };

  // Resize Logic for General Elements
  const handleResizeStart = (e: React.MouseEvent, direction: string) => {
    e.preventDefault();
    e.stopPropagation();

    if (!selectedElement || !editorRef.current) return;

    const startX = e.clientX;
    const startW = selectedElement.clientWidth;

    const onMouseMove = (ev: MouseEvent) => {
        const deltaX = ev.clientX - startX;
        let newW = startW;

        if (direction.includes('w')) {
             newW = startW - deltaX;
        } else {
             newW = startW + deltaX;
        }

        if (newW < 50) newW = 50;
        const maxW = editorRef.current?.clientWidth || 800;
        if (newW > maxW) newW = maxW;

        selectedElement.style.width = `${newW}px`;
        selectedElement.style.height = 'auto'; // Maintain aspect ratio

        setRefreshOverlay(prev => prev + 1);
    };

    const onMouseUp = () => {
        window.removeEventListener('mousemove', onMouseMove);
        window.removeEventListener('mouseup', onMouseUp);
        editorRef.current?.focus();
        triggerAutoSave();
    };

    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onMouseUp);
  };

  // Media Property Handlers
  const updateMediaStyle = (style: Partial<CSSStyleDeclaration>) => {
      if (!selectedElement) return;
      Object.assign(selectedElement.style, style);
      setRefreshOverlay(prev => prev + 1);
      triggerAutoSave();
  };

  const toggleAttribute = (attr: string) => {
      if (!selectedElement) return;
      if (selectedElement.hasAttribute(attr)) {
          selectedElement.removeAttribute(attr);
      } else {
          selectedElement.setAttribute(attr, '');
      }
      setRefreshOverlay(prev => prev + 1);
      triggerAutoSave();
  };

  const updateAttribute = (attr: string, value: string) => {
      if (!selectedElement) return;
      selectedElement.setAttribute(attr, value);
      triggerAutoSave();
  };

  // Modal Drag & Drop
  const onModalDragOver = useCallback((e: React.DragEvent) => {
      e.preventDefault();
      setIsDraggingMedia(true);
  }, []);

  const onModalDragLeave = useCallback((e: React.DragEvent) => {
      e.preventDefault();
      setIsDraggingMedia(false);
  }, []);

  const onModalDrop = useCallback((e: React.DragEvent) => {
      e.preventDefault();
      setIsDraggingMedia(false);
      const file = e.dataTransfer.files?.[0];
      if (file) {
        if (file.type.startsWith('image/')) {
            setFileToEdit(file);
            if (editorUploadInputRef.current) editorUploadInputRef.current.value = '';
        } else {
            processMediaUpload(file);
        }
      }
  }, []);

  // Render Resize Overlay & Media Toolbar
  const renderResizeOverlay = () => {
    if (!selectedElement || !editorRef.current) return null;

    const { offsetTop, offsetLeft, offsetWidth, offsetHeight } = selectedElement;
    const tagName = selectedElement.tagName;

    return (
        <>
            {/* Selection Border */}
            <div 
                className="absolute border-2 border-blue-600 pointer-events-none z-10 transition-all duration-75"
                style={{ top: offsetTop, left: offsetLeft, width: offsetWidth, height: offsetHeight }}
            >
                <div className="absolute -top-8 left-1/2 -translate-x-1/2 bg-black text-white px-2 py-1 text-[10px] font-bold uppercase tracking-wider shadow-sm flex gap-2 rounded z-20 whitespace-nowrap">
                    <span>{tagName} &bull; {Math.round(offsetWidth)}px</span>
                </div>
                {/* Corner Handles */}
                <div className="resize-handle absolute -top-1.5 -left-1.5 w-3 h-3 bg-white border border-blue-600 cursor-nw-resize pointer-events-auto hover:bg-blue-600 transition-colors shadow-sm" onMouseDown={(e) => handleResizeStart(e, 'nw')} />
                <div className="resize-handle absolute -top-1.5 -right-1.5 w-3 h-3 bg-white border border-blue-600 cursor-ne-resize pointer-events-auto hover:bg-blue-600 transition-colors shadow-sm" onMouseDown={(e) => handleResizeStart(e, 'ne')} />
                <div className="resize-handle absolute -bottom-1.5 -left-1.5 w-3 h-3 bg-white border border-blue-600 cursor-sw-resize pointer-events-auto hover:bg-blue-600 transition-colors shadow-sm" onMouseDown={(e) => handleResizeStart(e, 'sw')} />
                <div className="resize-handle absolute -bottom-1.5 -right-1.5 w-3 h-3 bg-white border border-blue-600 cursor-se-resize pointer-events-auto hover:bg-blue-600 transition-colors shadow-sm" onMouseDown={(e) => handleResizeStart(e, 'se')} />
            </div>

            {/* Floating Toolbar */}
            <div 
                className="media-toolbar absolute z-20 flex flex-col gap-1 bg-white border border-gray-200 shadow-xl rounded-md p-1 animate-in fade-in zoom-in-95 duration-150"
                style={{ top: offsetTop - 50, left: Math.max(0, offsetLeft), transform: 'translateY(-100%)' }}
            >
                <div className="flex items-center gap-1">
                     <button onClick={() => updateMediaStyle({ float: 'left', margin: '0 1em 1em 0' })} className="p-1.5 hover:bg-gray-100 rounded text-gray-600" title="Float Left"><AlignLeft size={14} /></button>
                     <button onClick={() => updateMediaStyle({ float: 'none', margin: '1em auto', display: 'block' })} className="p-1.5 hover:bg-gray-100 rounded text-gray-600" title="Center"><AlignCenter size={14} /></button>
                     <button onClick={() => updateMediaStyle({ float: 'right', margin: '0 0 1em 1em' })} className="p-1.5 hover:bg-gray-100 rounded text-gray-600" title="Float Right"><AlignRight size={14} /></button>
                     <div className="w-px h-4 bg-gray-200 mx-1"></div>
                     <button onClick={() => updateMediaStyle({ width: '100%', height: 'auto' })} className="p-1.5 hover:bg-gray-100 rounded text-gray-600" title="Full Width"><AlignJustify size={14} /></button>
                </div>

                {/* Specific Tools */}
                <div className="flex items-center gap-1 border-t border-gray-100 pt-1">
                    {tagName === 'IMG' && (
                        <>
                             <button onClick={() => { const alt = prompt("Alt Text:", selectedElement.getAttribute('alt') || ''); if(alt !== null) updateAttribute('alt', alt); }} className="p-1.5 hover:bg-gray-100 rounded text-gray-600" title="Alt Text"><Type size={14} /></button>
                             <button onClick={() => updateMediaStyle({ borderRadius: selectedElement.style.borderRadius === '8px' ? '0' : '8px' })} className="p-1.5 hover:bg-gray-100 rounded text-gray-600" title="Rounded Corners"><BoxSelect size={14} /></button>
                             <button onClick={() => updateMediaStyle({ filter: selectedElement.style.filter === 'grayscale(100%)' ? 'none' : 'grayscale(100%)' })} className="p-1.5 hover:bg-gray-100 rounded text-gray-600" title="Grayscale"><Layers size={14} /></button>
                        </>
                    )}
                    {tagName === 'VIDEO' && (
                        <>
                            <button onClick={() => toggleAttribute('autoplay')} className={`p-1.5 hover:bg-gray-100 rounded ${selectedElement.hasAttribute('autoplay') ? 'text-blue-600 bg-blue-50' : 'text-gray-600'}`} title="Autoplay"><PlayCircle size={14} /></button>
                            <button onClick={() => toggleAttribute('loop')} className={`p-1.5 hover:bg-gray-100 rounded ${selectedElement.hasAttribute('loop') ? 'text-blue-600 bg-blue-50' : 'text-gray-600'}`} title="Loop"><Repeat size={14} /></button>
                            <button onClick={() => toggleAttribute('muted')} className={`p-1.5 hover:bg-gray-100 rounded ${selectedElement.hasAttribute('muted') ? 'text-blue-600 bg-blue-50' : 'text-gray-600'}`} title="Muted"><VolumeX size={14} /></button>
                        </>
                    )}
                    <div className="flex-1"></div>
                    <button 
                        onClick={() => { selectedElement.remove(); setSelectedElement(null); triggerAutoSave(); }} 
                        className="p-1.5 hover:bg-red-50 text-red-500 rounded" 
                        title="Remove"
                    >
                        <Trash2 size={14} />
                    </button>
                </div>
            </div>
        </>
    );
  };

  const ImageModal = () => (
    <div 
        className="fixed inset-0 z-[100] flex items-center justify-center bg-black/95 backdrop-blur-sm animate-in fade-in duration-200"
        onClick={() => setModalImage(null)}
    >
        <button 
            className="absolute top-8 right-8 text-white/50 hover:text-white transition-colors"
            onClick={() => setModalImage(null)}
        >
            <X size={32} />
        </button>
        <div className="max-w-[90vw] max-h-[90vh] relative p-4" onClick={(e) => e.stopPropagation()}>
            <img 
                src={modalImage || ''} 
                alt="Enlarged view" 
                className={`max-w-full max-h-[85vh] object-contain shadow-2xl rounded-sm border border-white/10`}
            />
            <div className="mt-4 flex items-center justify-between text-white/40 font-mono text-[10px] uppercase tracking-widest">
                <span>Preview Mode</span>
                <button 
                    onClick={() => window.open(modalImage || '', '_blank')}
                    className="hover:text-white flex items-center gap-2"
                >
                    <Maximize2 size={12} /> Full Resolution
                </button>
            </div>
        </div>
    </div>
  );

  const widthClass = settings.contentWidth === 'compact' ? 'max-w-xl' : settings.contentWidth === 'relaxed' ? 'max-w-5xl' : 'max-w-3xl';

  return (
    <div className="flex h-full bg-white relative font-mono text-gray-900 overflow-hidden">
      {modalImage && <ImageModal />}

      {fileToEdit && (
          <ImageEditor 
            file={fileToEdit} 
            onSave={handleEditorSave} 
            onCancel={() => setFileToEdit(null)} 
          />
      )}

      {showMediaPicker && (
          <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-8">
              <div className="bg-white w-full max-w-4xl h-[80vh] flex flex-col shadow-2xl animate-in fade-in zoom-in-95 duration-200">
                  <header className="p-6 border-b border-gray-100 flex items-center justify-between">
                      <div>
                          <h3 className="text-xl font-bold uppercase tracking-tight">Select Asset</h3>
                          <p className="text-xs text-gray-500 mt-1">
                              {pickerTarget === 'cover' ? 'Setting cover image' : 'Select items to insert (Drag & Drop supported)'}
                          </p>
                      </div>
                      <div className="flex items-center gap-4">
                           {pickerTarget === 'content' && (
                                <div className="flex flex-col md:flex-row gap-2 md:gap-4 md:items-center mr-4">
                                     {selectedMediaIds.size > 0 ? (
                                        <button 
                                            onClick={insertSelectedMedia}
                                            className="bg-black text-white px-4 py-2 text-xs font-bold uppercase tracking-wider hover:bg-gray-800 flex items-center gap-2"
                                        >
                                            <Check size={14} /> Insert {selectedMediaIds.size} {selectedMediaIds.size === 1 ? 'Item' : 'Items'}
                                        </button>
                                     ) : (
                                        <div className="flex items-center gap-2 bg-gray-50 p-1 border border-gray-200 rounded">
                                            <span className="text-[10px] font-bold uppercase px-2 text-gray-500">Link:</span>
                                            <select 
                                                value={linkMode} 
                                                onChange={(e) => setLinkMode(e.target.value as any)}
                                                className="text-[10px] font-bold bg-transparent border-none focus:ring-0 cursor-pointer py-1"
                                            >
                                                <option value="none">None</option>
                                                <option value="file">Media File</option>
                                                <option value="custom">Custom URL</option>
                                            </select>
                                            {linkMode === 'custom' && (
                                                <input 
                                                    type="text" 
                                                    placeholder="https://" 
                                                    className="text-[10px] border border-gray-300 rounded px-2 py-1 w-32 focus:border-black focus:outline-none"
                                                    value={customLinkUrl}
                                                    onChange={(e) => setCustomLinkUrl(e.target.value)}
                                                />
                                            )}
                                        </div>
                                     )}
                                </div>
                           )}
                          <div className="relative">
                                <input 
                                    type="file" 
                                    className="hidden" 
                                    id="modal-upload"
                                    accept="image/*,video/*,audio/*"
                                    onChange={handleMediaUpload}
                                    ref={editorUploadInputRef}
                                />
                                <label 
                                    htmlFor="modal-upload" 
                                    className="cursor-pointer bg-white border border-gray-200 text-black px-4 py-2 text-xs font-bold uppercase tracking-wider hover:bg-gray-50 flex items-center gap-2"
                                >
                                    <Upload size={14} /> Upload New
                                </label>
                          </div>
                          <button onClick={() => setShowMediaPicker(false)} className="p-2 hover:bg-gray-100"><X size={20} /></button>
                      </div>
                  </header>
                  <div 
                      className="flex-1 overflow-y-auto p-6 bg-gray-50 relative"
                      onDragOver={onModalDragOver}
                      onDragLeave={onModalDragLeave}
                      onDrop={onModalDrop}
                  >
                      {isDraggingMedia && (
                          <div className="absolute inset-0 bg-black/5 z-50 border-4 border-black border-dashed m-4 flex flex-col items-center justify-center pointer-events-none backdrop-blur-sm animate-in fade-in rounded-lg">
                              <MoveDown size={48} className="mb-4 animate-bounce" />
                              <h3 className="text-xl font-bold uppercase tracking-widest">Drop to Upload</h3>
                          </div>
                      )}
                      <div className="grid grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                          {media.map(item => {
                              const isVideo = item.mediaType === 'video' || item.type.startsWith('video/');
                              const isAudio = item.mediaType === 'audio' || item.type.startsWith('audio/');
                              const isSelected = selectedMediaIds.has(item.id);

                              return (
                                <button 
                                    key={item.id} 
                                    onClick={() => handleMediaItemClick(item)}
                                    className={`group relative aspect-square bg-white border transition-all focus:outline-none overflow-hidden ${isSelected ? 'border-black ring-2 ring-black ring-offset-2' : 'border-gray-200 hover:border-black'}`}
                                >
                                    {isVideo ? (
                                        <div className="w-full h-full relative flex items-center justify-center bg-gray-100">
                                            <video src={item.url} className="w-full h-full object-cover p-1 opacity-60" muted playsInline loop />
                                            <Film size={24} className="absolute text-black pointer-events-none" />
                                        </div>
                                    ) : isAudio ? (
                                        <div className="w-full h-full relative flex items-center justify-center bg-gray-100 text-gray-400">
                                            <Music size={24} />
                                            <div className="absolute bottom-2 right-2 text-[8px] font-bold text-gray-400 uppercase">AUDIO</div>
                                        </div>
                                    ) : (
                                        <img src={item.url} alt={item.name} className="w-full h-full object-cover p-1" />
                                    )}

                                    {isSelected && (
                                        <div className="absolute inset-0 bg-black/10 flex items-center justify-center">
                                            <div className="bg-black text-white rounded-full p-1">
                                                <Check size={16} strokeWidth={3} />
                                            </div>
                                        </div>
                                    )}

                                    <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors" />
                                    <div className="absolute bottom-0 left-0 right-0 bg-white/90 p-1 text-[10px] truncate border-t border-gray-100">
                                        {item.name}
                                    </div>
                                </button>
                              );
                          })}
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Main Editor Area */}
