                              const isVideo = item.mediaType === 'video' || item.type.startsWith('video/');
                              const isAudio = item.mediaType === 'audio' || item.type.startsWith('audio/');
                              const isSelected = selectedMediaIds.has(item.id);

                              return (
                                <button 
                                    key={item.id} 
                                    onClick={() => handleMediaItemClick(item)}
                                    className={`group relative aspect-square bg-white border transition-all focus:outline-none overflow-hidden ${isSelected ? 'border-black ring-2 ring-black ring-offset-2' : 'border-gray-200 hover:border-black'}`}
