                <div className="w-px h-4 bg-gray-200 mx-3"></div>

                <div className="relative">
                    <button onMouseDown={(e) => e.preventDefault()} onClick={() => { setShowSizePicker(!showSizePicker); setShowColorPicker(false); }} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Font Size"><Type size={16} /></button>
                    {showSizePicker && (
                        <div className="absolute top-full left-0 mt-1 bg-white border border-gray-200 shadow-xl rounded p-1 z-50 flex flex-col gap-1 min-w-[120px] animate-in fade-in zoom-in-95 duration-150">
