                            <button onMouseDown={(e) => e.preventDefault()} onClick={() => { insertFormat('fontSize', '7'); setShowSizePicker(false); }} className="text-left px-3 py-2 hover:bg-gray-50 text-2xl font-bold">Huge</button>
                        </div>
                    )}
                </div>

                <div className="relative">
                    <button onMouseDown={(e) => e.preventDefault()} onClick={() => { setShowColorPicker(!showColorPicker); setShowSizePicker(false); }} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Text Color"><Palette size={16} /></button>
                    {showColorPicker && (
                        <div className="absolute top-full left-0 mt-1 bg-white border border-gray-200 shadow-xl rounded p-3 z-50 grid grid-cols-4 gap-2 w-48 animate-in fade-in zoom-in-95 duration-150">
                            {[
                                { c: '#000000', label: 'Black' },
                                { c: '#52525b', label: 'Gray' },
                                { c: '#dc2626', label: 'Red' },
                                { c: '#2563eb', label: 'Blue' },
                                { c: '#16a34a', label: 'Green' },
                                { c: '#d97706', label: 'Orange' },
                                { c: '#9333ea', label: 'Purple' },
                                { c: '#db2777', label: 'Pink' }
                            ].map(({c, label}) => (
                                <button key={c} onMouseDown={(e) => e.preventDefault()} onClick={() => { insertFormat('foreColor', c); setShowColorPicker(false); }} className="w-8 h-8 rounded-full border border-gray-200 hover:scale-110 transition-transform focus:outline-none focus:ring-2 focus:ring-offset-1 focus:ring-black" style={{backgroundColor: c}} title={label} />
                            ))}
                        </div>
