                <div className="flex-1"></div>
                <button onMouseDown={(e) => e.preventDefault()} onClick={() => setIsZenMode(!isZenMode)} className="p-1.5 text-gray-400 hover:text-black hover:bg-gray-50 rounded" title="Zen Mode">
