                                onChange={(e) => setTitle(e.target.value)}
                            />
                            {/* Resize Overlay */}
                            {renderResizeOverlay()}
                            <div
                                ref={editorRef}
                                contentEditable
                                onKeyUp={saveSelection}
                                onMouseUp={saveSelection}
                                onPaste={handlePaste}
                                onInput={triggerAutoSave}
