<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${settings.title}</title>
    <meta name="description" content="${settings.description}">
    <script src="https://cdn.tailwindcss.com"></script>
    <link href="https://fonts.googleapis.com/css2?family=IBM+Plex+Mono:wght@300;400;500;600&family=Inter:wght@300;400;500;600;700&family=JetBrains+Mono:wght@300;400;500;600;700&family=Lora:ital,wght@0,400;0,500;0,600;1,400&family=Merriweather:ital,wght@0,300;0,400;0,700;1,400&family=Playfair+Display:ital,wght@0,400;0,600;0,700;1,400&family=Roboto:wght@300;400;500;700&family=Space+Mono:ital,wght@0,400;0,700;1,400&display=swap" rel="stylesheet">
    <style>
        body { font-family: '${settings.fontFamily}', sans-serif; }
        ::-webkit-scrollbar { width: 4px; height: 4px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: #d4d4d8; }
        ${settings.customCss || ''}
    </style>
</head>
<body class="bg-white text-gray-900 antialiased selection:bg-black selection:text-white">
    <!-- Header -->
    <header class="border-b-4 ${accentBorderClass} bg-white ${settings.stickyHeader ? 'sticky top-0' : ''} z-40">
        <div class="max-w-6xl mx-auto px-6 py-8 flex ${settings.headerStyle === 'center' ? 'flex-col items-center gap-8' : settings.headerStyle === 'right' ? 'flex-row-reverse justify-between items-center' : 'justify-between items-center'}">
            <div class="flex items-center gap-4">
                ${settings.logoUrl ? `<img src="${settings.logoUrl}" alt="Logo" class="h-12 w-12 object-contain ${borderRadiusClass}">` : ''}
                <div class="${settings.headerStyle === 'center' ? 'text-center' : ''}">
                    <h1 class="text-3xl font-bold text-black tracking-tighter leading-none uppercase">${settings.title}</h1>
                    ${settings.headerStyle === 'center' ? `<p class="text-xs text-gray-400 mt-2 font-mono uppercase tracking-widest">${settings.description}</p>` : ''}
                </div>
            </div>
            <nav class="flex gap-6 items-center">
                ${settings.headerStyle === 'left' ? `<div class="hidden sm:flex items-center gap-6 mr-8"><span class="text-xs text-gray-400 font-mono uppercase tracking-widest border-l border-gray-200 pl-6 h-8 flex items-center">${settings.description}</span></div>` : ''}
                ${(settings.navigation || []).map(item => `<a href="${item.url}" class="text-xs font-bold uppercase tracking-widest text-gray-500 hover:text-black transition-colors">${item.label}</a>`).join('')}
            </nav>
        </div>
    </header>

    <!-- Main Content -->
    <main class="max-w-6xl mx-auto px-6 py-24">
        ${(settings.headerStyle === 'left' || settings.headerStyle === 'split') ? `
            <div class="mb-24 max-w-4xl">
                <h2 class="text-5xl md:text-7xl font-bold text-gray-900 mb-8 leading-[0.9] tracking-tighter">${settings.description}</h2>
                <div class="h-2 w-32 ${accentBgClass} ${borderRadiusClass}"></div>
            </div>
        ` : ''}

        <div class="flex flex-col gap-40">
            ${feedPosts.length === 0 ? `<div class="text-center py-24 bg-gray-50 border border-dashed border-gray-200 ${borderRadiusClass}"><p class="text-xl text-gray-400 italic">No posts published.</p></div>` : 
            feedPosts.map(post => `
                <article class="${widthClass} mx-auto border-b-2 border-gray-100 pb-24 last:border-0">
                    <header class="mb-12 text-center">
                        <div class="flex items-center justify-center gap-3 text-[10px] font-mono text-gray-400 mb-6 font-bold uppercase tracking-widest">
                            ${settings.showDate ? `<span>${format(post.createdAt, 'MMMM d, yyyy')}</span><span>/</span>` : ''}
                            <span class="${accentTextClass}">${post.tags[0] || 'Uncategorized'}</span>
                        </div>
                        <h2 class="text-5xl md:text-6xl font-bold text-gray-900 leading-[0.9] mb-8 tracking-tighter">${post.title}</h2>
                        ${settings.showAuthor ? `<div class="text-[10px] font-mono font-bold uppercase tracking-widest text-gray-500">Writer: ${post.author}</div>` : ''}
                    </header>
                    ${post.coverImage ? `<div class="mb-12"><img src="${post.coverImage}" alt="${post.title}" class="w-full h-auto grayscale ${borderRadiusClass}"></div>` : ''}
                    <div class="prose prose-xl prose-stone max-w-none prose-p:text-gray-700 prose-headings:text-black prose-a:text-black" style="font-family: inherit">
                        ${resolveContent(post.content, media, settings)}
                    </div>
                </article>
            `).join('')}
        </div>
    </main>

    <!-- Footer -->
    <footer class="border-t-4 ${accentBorderClass} mt-32 bg-gray-50">
        <div class="max-w-6xl mx-auto px-6 py-20 flex flex-col md:flex-row justify-between items-start md:items-center gap-8">
            <div>
                <h4 class="font-bold font-mono text-xs uppercase tracking-widest mb-2">${settings.title}</h4>
                <p class="text-gray-500 font-mono text-[10px] max-w-xs leading-relaxed">${settings.footerText}</p>
            </div>
            <div class="flex items-center gap-4 text-[10px] font-mono text-gray-300 uppercase tracking-widest">
                <span>Published with ZenPress</span>
            </div>
        </div>
    </footer>
</body>
</html>`;

    // 4. Trigger Download
    const blob = new Blob([html], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = 'index.html';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
    setIsGenerating(false);
  };

  const triggerWebhook = async () => {
    if (!settings.webhookUrl) return;
    setIsTriggering(true);
    setTriggerStatus('idle');
    try {
        const response = await fetch(settings.webhookUrl, {
            method: 'POST',
            body: JSON.stringify({
                timestamp: Date.now(),
                site: settings.title,
                event: 'manual_trigger'
            })
        });
        if (response.ok) {
            setTriggerStatus('success');
        } else {
            setTriggerStatus('error');
        }
    } catch (e) {
        setTriggerStatus('error');
    } finally {
        setIsTriggering(false);
        setTimeout(() => setTriggerStatus('idle'), 3000);
    }
  };

  return (
    <div className="p-8 max-w-5xl mx-auto font-mono text-sm">
        <header className="mb-12 border-b border-gray-200 pb-8">
            <h2 className="text-xl font-bold text-black uppercase tracking-tight">Site Publishing</h2>
            <p className="text-gray-500 mt-1 text-xs">Generate a standalone version of your system.</p>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="bg-white border border-gray-200 p-8 shadow-sm relative overflow-hidden group">
                 <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                     <Rocket size={100} />
                 </div>
                 <h3 className="text-sm font-bold text-gray-900 uppercase tracking-widest mb-4 flex items-center gap-2">
                     <Rocket size={16} /> Static Build
                 </h3>
                 <p className="text-gray-500 mb-8 leading-relaxed">
                     Compile your entire site into a single, high-performance HTML file. 
                     Includes all styles, fonts, and content. Perfect for hosting on GitHub Pages, Netlify, or sharing via email.
                 </p>

                 <div className="space-y-2 mb-8 text-[10px] text-gray-400 font-mono">
                     <div className="flex items-center gap-2"><Check size={12} className="text-green-500" /> Tailwind CSS Embedded</div>
                     <div className="flex items-center gap-2"><Check size={12} className="text-green-500" /> Google Fonts Linked</div>
                     <div className="flex items-center gap-2"><Check size={12} className="text-green-500" /> Images Referenced via URL</div>
                     <div className="flex items-center gap-2"><Check size={12} className="text-green-500" /> Mobile Responsive</div>
                 </div>

                 <button 
                    onClick={generateStaticHtml}
                    disabled={isGenerating}
                    className="w-full bg-black text-white py-4 px-6 text-xs font-bold uppercase tracking-wider hover:bg-gray-800 transition-colors flex items-center justify-center gap-3"
                 >
                     {isGenerating ? (
                         <>Processing...</>
                     ) : (
                         <>
                            <Download size={16} /> Download 'index.html'
                         </>
                     )}
                 </button>
            </div>

            <div className="space-y-8">
                 <div className="bg-gray-50 border border-gray-200 p-6">
                     <h3 className="text-xs font-bold text-gray-900 uppercase tracking-widest mb-2 flex items-center gap-2">
                         <Info size={14} /> Deployment Guide
                     </h3>
                     <p className="text-gray-500 mb-4 text-[11px] leading-relaxed">
                         To deploy your site, simply upload the downloaded <code className="bg-gray-200 px-1 py-0.5 rounded text-black">index.html</code> file to any static hosting provider.
                     </p>
                     <ul className="list-disc list-inside text-[11px] text-gray-500 space-y-1 ml-1">
                         <li><strong>Netlify:</strong> Drag and drop the file into the "Deploys" tab.</li>
                         <li><strong>Vercel:</strong> Install Vercel CLI and run <code className="bg-gray-200 px-1">vercel deploy</code>.</li>
                         <li><strong>GitHub Pages:</strong> Push to a repository as <code className="bg-gray-200 px-1">index.html</code>.</li>
                     </ul>
                 </div>

                 <div className={`bg-white border p-6 transition-all ${settings.webhookUrl ? 'border-gray-200' : 'border-gray-200 opacity-60'}`}>
                     <div className="flex justify-between items-start mb-2">
                        <h3 className="text-xs font-bold text-gray-900 uppercase tracking-widest flex items-center gap-2">
                            <Webhook size={14} /> API Integration
                        </h3>
                        {!settings.webhookUrl && <span className="text-[9px] bg-gray-100 px-2 py-0.5 font-bold uppercase">Setup Required</span>}
                        {settings.webhookUrl && <span className="text-[9px] bg-green-100 text-green-700 px-2 py-0.5 font-bold uppercase">Active</span>}
                     </div>
                     <p className="text-gray-400 text-[11px] leading-relaxed mb-4">
                         {settings.webhookUrl 
                            ? 'Webhook configured. Click below to trigger a build on your connected CI/CD provider.' 
                            : 'Connect to a headless CMS endpoint or trigger webhooks on publish. Configure the URL in Settings > Integrations.'}
                     </p>

                     {settings.webhookUrl && (
                        <button 
                            onClick={triggerWebhook}
                            disabled={isTriggering}
                            className={`w-full py-2 px-4 text-xs font-bold uppercase tracking-wider flex items-center justify-center gap-2 transition-colors ${
                                triggerStatus === 'success' ? 'bg-green-600 text-white' : 
                                triggerStatus === 'error' ? 'bg-red-600 text-white' : 
                                'bg-gray-900 text-white hover:bg-gray-800'
                            }`}
                        >
                            {isTriggering ? <Loader2 size={14} className="animate-spin" /> : <Webhook size={14} />}
                            {triggerStatus === 'success' ? 'Triggered!' : 
                             triggerStatus === 'error' ? 'Failed' : 
                             'Trigger Build Hook'}
                        </button>
                     )}
                 </div>
            </div>
        </div>
    </div>
  );
};

export default Publish;

import React, { useState } from 'react';
import { Post, SiteSettings, MediaItem, PostStatus } from '../types';
import { Download, Rocket, Check, Code, Info, Webhook, Loader2, Package } from 'lucide-react';
import { format } from 'date-fns';
import JSZip from 'jszip';

interface PublishProps {
  posts: Post[];
  settings: SiteSettings;
  media: MediaItem[];
}

const resolveContent = (htmlContent: string, media: MediaItem[], settings: SiteSettings) => {
    if (!htmlContent) return '';

    let html = htmlContent.replace(/asset:\/\/([a-zA-Z0-9-]+)/g, (match, id) => {
        const item = media.find(m => m.id === id);
        return item ? item.url : match;
    });

    const borderRadiusClass = settings.borderRadius === 'pill' ? 'rounded-2xl' : settings.borderRadius === 'subtle' ? 'rounded-md' : 'rounded-none';

    html = html.replace(/<img([^>]*)>/g, (match, attrs) => {
        if (attrs.includes('data-gallery="true"')) {
             let newAttrs = attrs;
             if (newAttrs.includes('class=')) {
                  newAttrs = newAttrs.replace(/class=(["'])(.*?)\1/, (m, q, c) => `class=${q}${c} cursor-zoom-in hover:opacity-90 transition-opacity${q}`);
             }
             return `<img${newAttrs}>`;
        }
        let newAttrs = attrs;
        const additionalClasses = `cursor-zoom-in transition-transform hover:scale-[1.01] ${borderRadiusClass}`;
        if (newAttrs.includes('class=')) {
            newAttrs = newAttrs.replace(/class=(["'])(.*?)\1/, (m, q, c) => `class=${q}${c} ${additionalClasses}${q}`);
        } else {
            newAttrs += ` class="max-w-full h-auto my-10 border border-gray-200 block ${additionalClasses}"`;
        }
        return `<img${newAttrs}>`;
    });

    html = html.replace(/<video([^>]*)>/g, (match, attrs) => {
        let newAttrs = attrs;
        const additionalClasses = `w-full my-10 border border-gray-200 block ${borderRadiusClass}`;
        if (newAttrs.includes('class=')) {
             newAttrs = newAttrs.replace(/class=(["'])(.*?)\1/, (m, q, c) => `class=${q}${c} ${additionalClasses}${q}`);
        } else {
             newAttrs += ` class="${additionalClasses}"`;
        }
        return `<video${newAttrs}>`;
    });

    html = html.replace(/<audio([^>]*)>/g, (match, attrs) => {
        let newAttrs = attrs;
        const additionalClasses = `w-full my-10 border border-gray-200 block ${borderRadiusClass}`;
        if (newAttrs.includes('class=')) {
             newAttrs = newAttrs.replace(/class=(["'])(.*?)\1/, (m, q, c) => `class=${q}${c} ${additionalClasses}${q}`);
        } else {
             newAttrs += ` class="${additionalClasses}"`;
        }
        return `<audio${newAttrs}>`;
    });

    html = html.replace(/contenteditable="[^"]*"/g, '');
    return html;
};

const getPageTemplate = (
    title: string, 
    content: string, 
    settings: SiteSettings, 
    rootPath: string = '.'
) => {
    const accentBorderClass = {
        black: 'border-black', zinc: 'border-zinc-500', blue: 'border-blue-600', red: 'border-red-600', green: 'border-emerald-700',
        orange: 'border-orange-600', purple: 'border-purple-600', pink: 'border-pink-600', yellow: 'border-yellow-500', teal: 'border-teal-600'
    }[settings.accentColor];

    const borderRadiusClass = settings.borderRadius === 'pill' ? 'rounded-2xl' : settings.borderRadius === 'subtle' ? 'rounded-md' : 'rounded-none';

    // Navigation Resolver
    const resolveLink = (url: string) => {
        if (url === '/') return `${rootPath}/index.html`;
        if (url.startsWith('http')) return url;
        if (url.startsWith('/')) {
            // Try to map relative links if they match page IDs or fallback
            return `${rootPath}${url}.html`; 
        }
        return url;
    };

    return `<!DOCTYPE html>
<html lang="${settings.language}">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${title} | ${settings.title}</title>
    <meta name="description" content="${settings.description}">
    <script src="https://cdn.tailwindcss.com"></script>
    <link href="https://fonts.googleapis.com/css2?family=IBM+Plex+Mono:wght@300;400;500;600&family=Inter:wght@300;400;500;600;700&family=JetBrains+Mono:wght@300;400;500;600;700&family=Lora:ital,wght@0,400;0,500;0,600;1,400&family=Merriweather:ital,wght@0,300;0,400;0,700;1,400&family=Playfair+Display:ital,wght@0,400;0,600;0,700;1,400&family=Roboto:wght@300;400;500;700&family=Space+Mono:ital,wght@0,400;0,700;1,400&display=swap" rel="stylesheet">
    <style>
        body { font-family: '${settings.fontFamily}', sans-serif; }
        ::-webkit-scrollbar { width: 4px; height: 4px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: #d4d4d8; }
        ${settings.customCss || ''}
    </style>
</head>
<body class="bg-white text-gray-900 antialiased selection:bg-black selection:text-white">
    <!-- Header -->
    <header class="border-b-4 ${accentBorderClass} bg-white ${settings.stickyHeader ? 'sticky top-0' : ''} z-40">
        <div class="max-w-6xl mx-auto px-6 py-8 flex ${settings.headerStyle === 'center' ? 'flex-col items-center gap-8' : settings.headerStyle === 'right' ? 'flex-row-reverse justify-between items-center' : 'justify-between items-center'}">
            <div class="flex items-center gap-4">
                ${settings.logoUrl ? `<a href="${rootPath}/index.html"><img src="${settings.logoUrl}" alt="Logo" class="h-12 w-12 object-contain ${borderRadiusClass}"></a>` : ''}
                <div class="${settings.headerStyle === 'center' ? 'text-center' : ''}">
                    <a href="${rootPath}/index.html" class="text-3xl font-bold text-black tracking-tighter leading-none uppercase hover:opacity-70 transition-opacity block">${settings.title}</a>
                    ${settings.headerStyle === 'center' ? `<p class="text-xs text-gray-400 mt-2 font-mono uppercase tracking-widest">${settings.description}</p>` : ''}
                </div>
            </div>
            <nav class="flex gap-6 items-center">
                ${settings.headerStyle === 'left' ? `<div class="hidden sm:flex items-center gap-6 mr-8"><span class="text-xs text-gray-400 font-mono uppercase tracking-widest border-l border-gray-200 pl-6 h-8 flex items-center">${settings.description}</span></div>` : ''}
                ${(settings.navigation || []).map(item => `<a href="${resolveLink(item.url)}" class="text-xs font-bold uppercase tracking-widest text-gray-500 hover:text-black transition-colors">${item.label}</a>`).join('')}
            </nav>
        </div>
    </header>

    <!-- Main Content -->
    <main class="max-w-6xl mx-auto px-6 py-24 min-h-[60vh]">
        ${content}
    </main>

    <!-- Footer -->
    <footer class="border-t-4 ${accentBorderClass} mt-32 bg-gray-50">
        <div class="max-w-6xl mx-auto px-6 py-20 flex flex-col md:flex-row justify-between items-start md:items-center gap-8">
            <div>
                <h4 class="font-bold font-mono text-xs uppercase tracking-widest mb-2">${settings.title}</h4>
                <p class="text-gray-500 font-mono text-[10px] max-w-xs leading-relaxed">${settings.footerText}</p>
            </div>
            <div class="flex items-center gap-4 text-[10px] font-mono text-gray-300 uppercase tracking-widest">
                <span>Published with ZenPress</span>
            </div>
        </div>
    </footer>
</body>
</html>`;
};

const Publish: React.FC<PublishProps> = ({ posts, settings, media }) => {
  const [isGenerating, setIsGenerating] = useState(false);
  const [isTriggering, setIsTriggering] = useState(false);
  const [triggerStatus, setTriggerStatus] = useState<'idle' | 'success' | 'error'>('idle');

  const generateStaticSite = async () => {
    setIsGenerating(true);

    try {
        const zip = new JSZip();

        // Styles Resolution
        const borderRadiusClass = settings.borderRadius === 'pill' ? 'rounded-2xl' : settings.borderRadius === 'subtle' ? 'rounded-md' : 'rounded-none';
        const widthClass = settings.contentWidth === 'compact' ? 'max-w-xl' : settings.contentWidth === 'relaxed' ? 'max-w-5xl' : 'max-w-3xl';

        const accentTextClass = {
            black: 'text-black', zinc: 'text-zinc-500', blue: 'text-blue-600', red: 'text-red-600', green: 'text-emerald-700',
            orange: 'text-orange-600', purple: 'text-purple-600', pink: 'text-pink-600', yellow: 'text-yellow-500', teal: 'text-teal-600'
        }[settings.accentColor];

        const accentBgClass = {
            black: 'bg-black', zinc: 'bg-zinc-500', blue: 'bg-blue-600', red: 'bg-red-600', green: 'bg-emerald-700',
            orange: 'bg-orange-600', purple: 'bg-purple-600', pink: 'bg-pink-600', yellow: 'bg-yellow-500', teal: 'bg-teal-600'
        }[settings.accentColor];

        // 1. Generate Homepage (Index)
        const feedPosts = posts.filter(p => p.status === PostStatus.PUBLISHED && p.type === 'post').sort((a, b) => b.createdAt - a.createdAt);

        let homeBody = '';
        if (settings.headerStyle === 'left' || settings.headerStyle === 'split') {
            homeBody += `
            <div class="mb-24 max-w-4xl">
                <h2 class="text-5xl md:text-7xl font-bold text-gray-900 mb-8 leading-[0.9] tracking-tighter">${settings.description}</h2>
                <div class="h-2 w-32 ${accentBgClass} ${borderRadiusClass}"></div>
            </div>`;
        }

        homeBody += `<div class="flex flex-col gap-24">`;
        if (feedPosts.length === 0) {
            homeBody += `<div class="text-center py-24 bg-gray-50 border border-dashed border-gray-200 ${borderRadiusClass}"><p class="text-xl text-gray-400 italic">No posts published.</p></div>`;
        } else {
            feedPosts.forEach(post => {
                 homeBody += `
                    <article class="${widthClass} mx-auto border-b-2 border-gray-100 pb-12 last:border-0">
                        <header class="mb-6">
                            <div class="flex items-center gap-3 text-[10px] font-mono text-gray-400 mb-4 font-bold uppercase tracking-widest">
                                ${settings.showDate ? `<span>${format(post.createdAt, 'MMMM d, yyyy')}</span><span>/</span>` : ''}
                                <span class="${accentTextClass}">${post.tags[0] || 'Uncategorized'}</span>
                            </div>
                            <a href="./posts/${post.id}.html" class="group block">
                                <h2 class="text-4xl md:text-5xl font-bold text-gray-900 leading-[0.95] mb-4 tracking-tighter group-hover:underline decoration-4 underline-offset-4 decoration-gray-300">${post.title}</h2>
                            </a>
                        </header>
                         <p class="text-gray-500 leading-relaxed mb-6 font-serif text-lg">${post.excerpt || ''}</p>
                         <a href="./posts/${post.id}.html" class="inline-block text-[10px] font-bold uppercase tracking-widest border-b border-gray-900 pb-0.5 hover:text-gray-600 transition-colors">Read Entry &rarr;</a>
                    </article>
                 `;
            });
        }
        homeBody += `</div>`;

        zip.file("index.html", getPageTemplate("Home", homeBody, settings, "."));

        // 2. Generate Posts
        const postsFolder = zip.folder("posts");
        feedPosts.forEach(post => {
             const contentHtml = resolveContent(post.content, media, settings);
             const postBody = `
                <article class="${widthClass} mx-auto">
                    <header class="mb-12 text-center">
                        <div class="flex items-center justify-center gap-3 text-[10px] font-mono text-gray-400 mb-6 font-bold uppercase tracking-widest">
                            ${settings.showDate ? `<span>${format(post.createdAt, 'MMMM d, yyyy')}</span><span>/</span>` : ''}
                            <span class="${accentTextClass}">${post.tags[0] || 'Uncategorized'}</span>
                        </div>
                        <h1 class="text-5xl md:text-6xl font-bold text-gray-900 leading-[0.9] mb-8 tracking-tighter">${post.title}</h1>
                        ${settings.showAuthor ? `<div class="text-[10px] font-mono font-bold uppercase tracking-widest text-gray-500">Writer: ${post.author}</div>` : ''}
                    </header>
                    ${post.coverImage ? `<div class="mb-12"><img src="${post.coverImage}" alt="${post.title}" class="w-full h-auto grayscale ${borderRadiusClass}"></div>` : ''}
                    <div class="prose prose-xl prose-stone max-w-none prose-p:text-gray-700 prose-headings:text-black prose-a:text-black" style="font-family: inherit">
                        ${contentHtml}
                    </div>
                </article>
             `;
             postsFolder?.file(`${post.id}.html`, getPageTemplate(post.title, postBody, settings, ".."));
        });

        // 3. Generate Pages
        const pagesFolder = zip.folder("pages");
        const pages = posts.filter(p => p.status === PostStatus.PUBLISHED && p.type === 'page');
        pages.forEach(page => {
             const contentHtml = resolveContent(page.content, media, settings);
             const pageBody = `
                <article class="${widthClass} mx-auto">
                    <header class="mb-12 text-center">
                        <h1 class="text-5xl md:text-6xl font-bold text-gray-900 leading-[0.9] mb-8 tracking-tighter">${page.title}</h1>
                    </header>
                    ${page.coverImage ? `<div class="mb-12"><img src="${page.coverImage}" alt="${page.title}" class="w-full h-auto grayscale ${borderRadiusClass}"></div>` : ''}
                    <div class="prose prose-xl prose-stone max-w-none prose-p:text-gray-700 prose-headings:text-black prose-a:text-black" style="font-family: inherit">
                        ${contentHtml}
                    </div>
                </article>
             `;
             // For pages, we try to map navigation URLs to filenames if possible, otherwise use ID
             // Current logic maps ID. 
             // If a user navigates to /about, we need to ensure the file is pages/about.html OR handle it via a redirect rule (not possible in static html easily).
             // We will export as ID.html, but users linking via the menu should ideally check the ID.
             // Simplification: We export as ID.html.
             pagesFolder?.file(`${page.id}.html`, getPageTemplate(page.title, pageBody, settings, ".."));
        });

        // 4. Generate & Download
        const blob = await zip.generateAsync({type:"blob"});
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `${settings.title.toLowerCase().replace(/\s+/g, '-')}-export.zip`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);

    } catch (e) {
        console.error("Export failed", e);
        alert("Failed to generate static site archive.");
    } finally {
        setIsGenerating(false);
    }
  };

  const triggerWebhook = async () => {
    if (!settings.webhookUrl) return;
    setIsTriggering(true);
    setTriggerStatus('idle');
    try {
        const response = await fetch(settings.webhookUrl, {
            method: 'POST',
            body: JSON.stringify({
                timestamp: Date.now(),
                site: settings.title,
                event: 'manual_trigger'
            })
        });
        if (response.ok) {
            setTriggerStatus('success');
        } else {
            setTriggerStatus('error');
        }
    } catch (e) {
        setTriggerStatus('error');
    } finally {
        setIsTriggering(false);
        setTimeout(() => setTriggerStatus('idle'), 3000);
    }
  };

  return (
    <div className="p-8 max-w-5xl mx-auto font-mono text-sm">
        <header className="mb-12 border-b border-gray-200 pb-8">
            <h2 className="text-xl font-bold text-black uppercase tracking-tight">Site Publishing</h2>
            <p className="text-gray-500 mt-1 text-xs">Generate a standalone version of your system.</p>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="bg-white border border-gray-200 p-8 shadow-sm relative overflow-hidden group">
                 <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                     <Package size={100} />
                 </div>
                 <h3 className="text-sm font-bold text-gray-900 uppercase tracking-widest mb-4 flex items-center gap-2">
                     <Package size={16} /> Static Build
                 </h3>
                 <p className="text-gray-500 mb-8 leading-relaxed">
                     Compile your entire site into a multi-page ZIP archive. 
                     Includes homepage, all posts, pages, and assets referenced via URL.
                     Ready for upload to any web server.
                 </p>

                 <div className="space-y-2 mb-8 text-[10px] text-gray-400 font-mono">
                     <div className="flex items-center gap-2"><Check size={12} className="text-green-500" /> Full Site Structure</div>
                     <div className="flex items-center gap-2"><Check size={12} className="text-green-500" /> Relative Linking</div>
                     <div className="flex items-center gap-2"><Check size={12} className="text-green-500" /> Zero Dependencies</div>
                     <div className="flex items-center gap-2"><Check size={12} className="text-green-500" /> SEO Optimized</div>
                 </div>

                 <button 
                    onClick={generateStaticSite}
                    disabled={isGenerating}
                    className="w-full bg-black text-white py-4 px-6 text-xs font-bold uppercase tracking-wider hover:bg-gray-800 transition-colors flex items-center justify-center gap-3"
                 >
                     {isGenerating ? (
                         <>
                             <Loader2 size={16} className="animate-spin" /> Bundling Assets...
                         </>
                     ) : (
                         <>
                            <Download size={16} /> Download Site Archive (.zip)
                         </>
                     )}
                 </button>
            </div>

            <div className="space-y-8">
                 <div className="bg-gray-50 border border-gray-200 p-6">
                     <h3 className="text-xs font-bold text-gray-900 uppercase tracking-widest mb-2 flex items-center gap-2">
                         <Info size={14} /> Deployment Guide
                     </h3>
                     <p className="text-gray-500 mb-4 text-[11px] leading-relaxed">
                         To deploy your site, extract the downloaded ZIP file and upload the contents to your hosting provider's public folder.
                     </p>
                     <ul className="list-disc list-inside text-[11px] text-gray-500 space-y-1 ml-1">
                         <li><strong>Netlify:</strong> Drag the folder into the "Deploys" tab.</li>
                         <li><strong>Vercel:</strong> Run <code className="bg-gray-200 px-1">vercel deploy</code> inside the folder.</li>
                         <li><strong>GitHub Pages:</strong> Push contents to <code className="bg-gray-200 px-1">gh-pages</code> branch.</li>
                     </ul>
                 </div>

                 <div className={`bg-white border p-6 transition-all ${settings.webhookUrl ? 'border-gray-200' : 'border-gray-200 opacity-60'}`}>
                     <div className="flex justify-between items-start mb-2">
                        <h3 className="text-xs font-bold text-gray-900 uppercase tracking-widest flex items-center gap-2">
                            <Webhook size={14} /> API Integration
                        </h3>
                        {!settings.webhookUrl && <span className="text-[9px] bg-gray-100 px-2 py-0.5 font-bold uppercase">Setup Required</span>}
                        {settings.webhookUrl && <span className="text-[9px] bg-green-100 text-green-700 px-2 py-0.5 font-bold uppercase">Active</span>}
                     </div>
                     <p className="text-gray-400 text-[11px] leading-relaxed mb-4">
                         {settings.webhookUrl 
                            ? 'Webhook configured. Click below to trigger a build on your connected CI/CD provider.' 
                            : 'Connect to a headless CMS endpoint or trigger webhooks on publish. Configure the URL in Settings > Integrations.'}
                     </p>

                     {settings.webhookUrl && (
                        <button 
                            onClick={triggerWebhook}
                            disabled={isTriggering}
                            className={`w-full py-2 px-4 text-xs font-bold uppercase tracking-wider flex items-center justify-center gap-2 transition-colors ${
                                triggerStatus === 'success' ? 'bg-green-600 text-white' : 
                                triggerStatus === 'error' ? 'bg-red-600 text-white' : 
                                'bg-gray-900 text-white hover:bg-gray-800'
                            }`}
                        >
                            {isTriggering ? <Loader2 size={14} className="animate-spin" /> : <Webhook size={14} />}
                            {triggerStatus === 'success' ? 'Triggered!' : 
                             triggerStatus === 'error' ? 'Failed' : 
                             'Trigger Build Hook'}
                        </button>
                     )}
                 </div>
            </div>
        </div>
    </div>
  );
};

