import React, { useRef, useState, useCallback, useMemo } from 'react';
import { MediaItem } from '../types';
import { 
  Upload, Trash2, Copy, Image as ImageIcon, Film, Music, 
  MoveDown, Search, X, Maximize2, Play, Info, Download, 
  Clock, HardDrive, FileText
} from 'lucide-react';
import { format } from 'date-fns';
import ImageEditor from './ImageEditor';

interface MediaLibraryProps {
  media: MediaItem[];
  onUpload: (item: MediaItem) => void;
  onDelete: (id: string) => void;
}

const MediaLibrary: React.FC<MediaLibraryProps> = ({ media, onUpload, onDelete }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  // Editor & Preview State
  const [fileToEdit, setFileToEdit] = useState<File | null>(null);
  const [previewItem, setPreviewItem] = useState<MediaItem | null>(null);

  const filteredMedia = useMemo(() => {
    return media.filter(item => 
      item.name.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [media, searchQuery]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) handleFile(file);
  };

  const handleFile = (file: File) => {
    if (file.size > 5 * 1024 * 1024) {
        alert("File too large. Max 5MB for local demo.");
        return;
    }

    if (file.type.startsWith('image/')) {
        setFileToEdit(file);
        if (fileInputRef.current) fileInputRef.current.value = '';
    } else {
        processUpload(file);
    }
  };

  const processUpload = (file: File) => {
    setIsUploading(true);
    const reader = new FileReader();
    reader.onloadend = () => {
      const isVideo = file.type.startsWith('video/');
      const isAudio = file.type.startsWith('audio/');
      const newItem: MediaItem = {
        id: crypto.randomUUID(),
        url: reader.result as string,
        name: file.name,
        type: file.type,
        mediaType: isVideo ? 'video' : isAudio ? 'audio' : 'image',
        createdAt: Date.now(),
        size: file.size
      };
      onUpload(newItem);
      setIsUploading(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsDataURL(file);
  };

  const handleEditorSave = (editedFile: File) => {
      setFileToEdit(null);
      processUpload(editedFile);
  };

  const onDragOver = useCallback((e: React.DragEvent) => {
      e.preventDefault();
      setIsDragging(true);
  }, []);

  const onDragLeave = useCallback((e: React.DragEvent) => {
      e.preventDefault();
      setIsDragging(false);
  }, []);

  const onDrop = useCallback((e: React.DragEvent) => {
      e.preventDefault();
      setIsDragging(false);
      const file = e.dataTransfer.files?.[0];
      if (file) handleFile(file);
  }, []);

  const copyToClipboard = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const formatBytes = (bytes: number) => {
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1048576) return (bytes / 1024).toFixed(1) + ' KB';
    return (bytes / 1048576).toFixed(1) + ' MB';
  };

  const PreviewModal = () => {
    if (!previewItem) return null;
    const isVideo = previewItem.mediaType === 'video';
    const isAudio = previewItem.mediaType === 'audio';

    return (
      <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-md flex items-center justify-center p-4 md:p-12 animate-in fade-in duration-300" onClick={() => setPreviewItem(null)}>
        <button className="absolute top-6 right-6 text-white/50 hover:text-white transition-colors" onClick={() => setPreviewItem(null)}>
            <X size={32} />
        </button>

        <div className="w-full max-w-6xl h-full flex flex-col md:flex-row bg-gray-900 border border-white/10 shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
            <div className="flex-1 bg-black flex items-center justify-center p-4 relative group">
                {isVideo ? (
                    <video src={previewItem.url} controls className="max-w-full max-h-full" />
                ) : isAudio ? (
                    <div className="flex flex-col items-center gap-8 w-full px-12">
                        <div className="w-32 h-32 bg-gray-800 rounded-full flex items-center justify-center text-gray-400">
                            <Music size={64} />
                        </div>
                        <audio src={previewItem.url} controls className="w-full" />
                    </div>
                ) : (
                    <img src={previewItem.url} alt={previewItem.name} className="max-w-full max-h-full object-contain" />
                )}
            </div>

            <div className="w-full md:w-80 bg-gray-900 border-t md:border-t-0 md:border-l border-white/10 p-6 flex flex-col text-sm">
                <div className="mb-8">
                    <h3 className="text-white font-bold text-lg leading-tight break-words mb-2">{previewItem.name}</h3>
                    <span className="text-[10px] font-bold uppercase tracking-widest text-gray-500 bg-gray-800 px-2 py-0.5 rounded">
                        {previewItem.type}
                    </span>
                </div>

                <div className="space-y-4 mb-auto">
                    <div className="flex items-center gap-3 text-gray-400">
                        <Clock size={16} />
                        <div>
                            <p className="text-[10px] uppercase font-bold text-gray-600">Created</p>
                            <p className="text-xs text-gray-300">{format(previewItem.createdAt, 'MMMM d, yyyy HH:mm')}</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-3 text-gray-400">
                        <HardDrive size={16} />
                        <div>
                            <p className="text-[10px] uppercase font-bold text-gray-600">Size</p>
                            <p className="text-xs text-gray-300">{formatBytes(previewItem.size)}</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-3 text-gray-400">
                        <Info size={16} />
                        <div>
                            <p className="text-[10px] uppercase font-bold text-gray-600">ID</p>
                            <p className="text-[10px] font-mono text-gray-500">{previewItem.id}</p>
                        </div>
                    </div>
                </div>

                <div className="space-y-3 pt-8 border-t border-white/10">
                    <button 
                        onClick={() => copyToClipboard(previewItem.url, previewItem.id)}
                        className="w-full bg-white text-black py-3 text-xs font-bold uppercase tracking-widest hover:bg-gray-200 transition-colors flex items-center justify-center gap-2"
                    >
                        <Copy size={14} /> {copiedId === previewItem.id ? 'Copied URL' : 'Copy Resource Link'}
                    </button>
                    <a 
                        href={previewItem.url} 
                        download={previewItem.name}
                        className="w-full bg-gray-800 text-white py-3 text-xs font-bold uppercase tracking-widest hover:bg-gray-700 transition-colors flex items-center justify-center gap-2"
                    >
                        <Download size={14} /> Download File
                    </a>
                    <button 
                        onClick={() => { if(confirm('Delete permanently?')) { onDelete(previewItem.id); setPreviewItem(null); } }}
                        className="w-full py-3 text-xs font-bold uppercase tracking-widest text-red-500 hover:text-red-400 transition-colors"
                    >
                        Delete Asset
                    </button>
                </div>
            </div>
        </div>
      </div>
    );
  };

  return (
    <div 
        className="p-8 max-w-7xl mx-auto h-full flex flex-col font-mono relative"
        onDragOver={onDragOver}
        onDragLeave={onDragLeave}
        onDrop={onDrop}
    >
      {previewItem && <PreviewModal />}

      {isDragging && (
          <div className="absolute inset-0 bg-black/5 z-50 border-4 border-black border-dashed m-4 flex flex-col items-center justify-center pointer-events-none backdrop-blur-sm animate-in fade-in rounded-xl">
              <MoveDown size={48} className="mb-4 animate-bounce" />
              <h3 className="text-xl font-bold uppercase tracking-widest">Drop to Import</h3>
          </div>
      )}

      {fileToEdit && (
          <ImageEditor 
            file={fileToEdit} 
            onSave={handleEditorSave} 
            onCancel={() => setFileToEdit(null)} 
          />
      )}

      <header className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-xl font-bold text-black uppercase tracking-tight">Media Assets</h2>
          <p className="text-gray-500 mt-1 text-xs">Library management and resource indexing.</p>
        </div>

        <div className="flex items-center gap-4">
          <div className="relative group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-black transition-colors" size={14} />
            <input 
                type="text" 
                placeholder="Search assets..." 
                className="pl-9 pr-3 py-2 border border-gray-200 bg-white focus:outline-none focus:border-black text-xs w-64 transition-colors placeholder-gray-400"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>
          <button 
            onClick={() => fileInputRef.current?.click()}
            disabled={isUploading}
            className="bg-black text-white px-5 py-2 flex items-center gap-2 text-xs font-bold uppercase tracking-wider hover:bg-gray-800 disabled:opacity-50 transition-transform active:scale-95 shadow-lg"
          >
            <Upload size={14} />
            {isUploading ? 'Encoding...' : 'Upload Asset'}
          </button>
        </div>

        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          accept="image/*,video/*,audio/*"
          onChange={handleFileChange} 
        />
      </header>

      {media.length === 0 ? (
        <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-gray-200 bg-gray-50 text-gray-400 group hover:border-black hover:text-black transition-all cursor-pointer rounded-xl" onClick={() => fileInputRef.current?.click()}>
          <div className="w-16 h-16 bg-white border border-gray-200 rounded-full flex items-center justify-center mb-6 shadow-sm group-hover:scale-110 transition-transform">
             <ImageIcon size={24} className="opacity-20 group-hover:opacity-100 transition-opacity" />
